function sgdiApiRoot(){
  const injected=window.__SGDI_API_ROOT__;
  if(injected)return String(injected).replace(/\/+$/,"");
  if(window.__SGDI_API_BASE__){
    const b=String(window.__SGDI_API_BASE__).replace(/\/legacy\/?$/,"");
    if(b)return b.replace(/\/+$/,"");
  }
  if(location.protocol==="file:")return "http://localhost:8000/api";
  return location.origin.replace(/\/+$/,"")+"/api";
}
function sgdiApiBase(){return (window.__SGDI_API_BASE__?String(window.__SGDI_API_BASE__).replace(/\/+$/,""):sgdiApiRoot()+"/legacy")}
function sgdiBackendExplicitlyConfigured(){
  return window.__SGDI_BACKEND_ENABLED__===true
    || !!window.__SGDI_API_ROOT__
    || !!window.__SGDI_API_BASE__;
}
function sgdiBackendShouldUse(){return true}
function sgdiApiUrl(path,legacy){
  if(/^https?:\/\//i.test(path))return path;
  if(path.startsWith("/api/"))return location.protocol==="file:"?sgdiApiRoot().replace(/\/api$/,"")+path:path;
  return (legacy?sgdiApiBase():sgdiApiRoot())+(path.startsWith("/")?path:"/"+path);
}
function sgdiAuthHeaders(headers){
  const h={"content-type":"application/json",...(headers||{})};
  const token=sessionStorage.getItem(SGDI_API_TOKEN_KEY);
  if(token)h.authorization="Bearer "+token;
  return h;
}
function sgdiAuthToken(){return sessionStorage.getItem(SGDI_API_TOKEN_KEY)||""}
async function sgdiApi(path,options){
  const opts=options||{};
  const legacy=opts.legacy!==false;
  const isForm=typeof FormData!=="undefined"&&opts.body instanceof FormData;
  const body=isForm?opts.body:(opts.body&&typeof opts.body!=="string"?JSON.stringify(opts.body):opts.body);
  const url=sgdiApiUrl(path,legacy);
  const headers=sgdiAuthHeaders(opts.headers);
  if(isForm)delete headers["content-type"];
  const res=await fetch(url,{cache:"no-store",...opts,body,headers});
  const out=await res.json().catch(()=>({ok:false,error:"Réponse API invalide"}));
  if(!res.ok||out.ok===false){
    const detail=Array.isArray(out.detail)?out.detail.map(d=>d.msg||JSON.stringify(d)).join(", "):out.detail;
    const message=out.error||detail||out.message||("Erreur API "+res.status);
    console.error("Erreur API",res.status,url,out);
    throw new Error(message);
  }
  return out.data===undefined?out:out.data;
}
async function sgdiActionApi(path,options){
  const opts=options||{};
  const legacy=opts.legacy!==false;
  const isForm=typeof FormData!=="undefined"&&opts.body instanceof FormData;
  const body=isForm?opts.body:(opts.body&&typeof opts.body!=="string"?JSON.stringify(opts.body):opts.body);
  const url=sgdiApiUrl(path,legacy);
  const headers=sgdiAuthHeaders(opts.headers);
  if(isForm)delete headers["content-type"];
  const res=await fetch(url,{cache:"no-store",...opts,body,headers});
  const out=await res.json().catch(()=>({status:"error",error:"Réponse API invalide"}));
  if(!res.ok||out.status!=="success"){
    const detail=Array.isArray(out.detail)?out.detail.map(d=>d.msg||JSON.stringify(d)).join(", "):out.detail;
    const message=out.error||detail||out.message||("Action refusée par le backend "+res.status);
    console.error("Action API refusée",res.status,url,out);
    throw new Error(message);
  }
  return out;
}
async function sgdiDownload(path,filename){
  const url=sgdiApiUrl(path,false);
  const res=await fetch(url,{cache:"no-store",headers:sgdiAuthHeaders({})});
  if(!res.ok){
    const out=await res.json().catch(()=>({detail:"Téléchargement impossible"}));
    throw new Error(out.detail||out.error||"Téléchargement impossible");
  }
  const blob=await res.blob();
  const a=document.createElement("a");
  const objectUrl=URL.createObjectURL(blob);
  a.href=objectUrl;
  a.download=filename||"document";
  document.body.appendChild(a);a.click();a.remove();
  setTimeout(()=>URL.revokeObjectURL(objectUrl),1000);
}
function sgdiSetApiRoot(url){window.__SGDI_API_ROOT__=String(url||"").replace(/\/+$/,"");window.__SGDI_BACKEND_ENABLED__=true}
function sgdiServerOnlyFailure(message){
  sgdiPostgresReady=false;
  sgdiDirty=true;
  const msg=message||"Sauvegarde PostgreSQL obligatoire échouée. L'application est bloquée pour empêcher une sauvegarde locale.";
  console.error(msg);
  if(typeof toast==="function")toast(msg,"error");
  if(session&&typeof renderPostgresRequired==="function")setTimeout(()=>renderPostgresRequired(msg),50);
}
function sgdiRequireServerWrite(){
  if(!session)throw new Error("Session SGDI absente");
  if(!sgdiAuthToken())throw new Error("Session PostgreSQL expirée : reconnectez-vous");
  if(!sgdiPostgresReady)throw new Error("PostgreSQL non chargé : sauvegarde refusée");
  return true;
}
let sgdiSaveQueue=Promise.resolve();
const SQL_OWNED_COLLECTIONS=new Set(["candidats","sites","clients","stockArticles","stockMouvements","magasins","fournisseurs"]);
function sgdiLegacySnapshot(){
  const source=db&&typeof db==="object"?db:{};
  const snap={...source};
  SQL_OWNED_COLLECTIONS.forEach(k=>{if(Array.isArray(snap[k]))snap[k]=[]});
  return snap;
}
function sgdiBackendSave(){
  if(!sgdiBackendShouldUse()||!db)return false;
  sanitizeCandidatesInDB();
  const token=sgdiAuthToken();
  if(!token){
    sgdiServerOnlyFailure("Session PostgreSQL expirée : reconnectez-vous");
    uiSaveState("Sauvegarde refusée","error");
    return false;
  }
  const payload=JSON.stringify({data:sgdiLegacySnapshot()});
  const url=sgdiApiUrl("/api/irongs/db",false);
  sgdiSaveQueue=sgdiSaveQueue.catch(()=>{}).then(async()=>{
    const res=await fetch(url,{method:"PUT",headers:sgdiAuthHeaders(),body:payload,cache:"no-store"});
    const out=await res.json().catch(()=>({ok:false,error:"Réponse API invalide"}));
    if(!res.ok||out.ok===false){
      const detail=Array.isArray(out.detail)?out.detail.map(d=>d.msg||JSON.stringify(d)).join(", "):out.detail;
      throw new Error(out.error||detail||out.message||("Erreur API "+res.status));
    }
    window.__SGDI_BACKEND_ENABLED__=true;
    sgdiPostgresReady=true;
    sgdiDirty=false;
    uiSaveState("Sauvegardé dans PostgreSQL","success");
    return out.data===undefined?out:out.data;
  }).catch(e=>{
    const msg="Sauvegarde PostgreSQL échouée : "+(e.message||e);
    sgdiServerOnlyFailure(msg);
    uiSaveState("Sauvegarde échouée","error");
    return null;
  });
  return true;
}
function sgdiFlushSaveQueue(){return sgdiSaveQueue}
async function sgdiPullState(options){
  const opt=options||{};
  if(!sgdiBackendShouldUse()||!sgdiAuthToken())return null;
  if(sgdiDirty&&!opt.force)return db;
  try{
    const remote=await sgdiApi("/api/irongs/db",{method:"GET",legacy:false});
    if(remote&&typeof remote==="object"&&!Array.isArray(remote)){
      window.__SGDI_BACKEND_ENABLED__=true;
      hydrateDB(remote);
      sanitizeCandidatesInDB();
      sgdiPostgresReady=true;
      if(typeof loadCustomSocietes==="function")loadCustomSocietes();
      await sgdiLoadAuthState();
      if(opt.deferSql){
        setTimeout(()=>sgdiBackgroundSqlSync({silent:opt.silent,render:opt.render}),50);
      }else if(!opt.light){
        await sgdiBackgroundSqlSync({silent:opt.silent,render:false,blocking:true});
      }
      const purged=typeof purgeRemovedSocieteData==="function"?purgeRemovedSocieteData(db):false;
      if(typeof normalizePostesInDB==="function")normalizePostesInDB();
      const pruned=pruneEmptyCandidates();
      if(purged||pruned)sgdiBackendSave();
      if(opt.render&&typeof render==="function")render();
      if(!opt.silent&&typeof toast==="function")toast("Données chargées depuis le backend","success");
      return db;
    }
  }catch(e){
    if(!opt.silent&&typeof toast==="function")toast("Backend indisponible : "+(e.message||e),"error");
  }
  return null;
}
let demandesPersonnelRefreshing=false;
let demandesPersonnelKnownIds=null;
let demandesPersonnelLastOpenCount=0;
function demandePersonnelOpenCount(){
  const list=(db&&Array.isArray(db.demandesPersonnel)&&typeof incomingPortalDemandesPersonnel==="function")?incomingPortalDemandesPersonnel():(db&&Array.isArray(db.demandesPersonnel)?db.demandesPersonnel:[]);
  return list.filter(d=>["nouveau","en_cours"].includes(d.statut||"nouveau")).length;
}
function initDemandesPersonnelWatcher(){
  const list=(db&&Array.isArray(db.demandesPersonnel)&&typeof incomingPortalDemandesPersonnel==="function")?incomingPortalDemandesPersonnel():(db&&Array.isArray(db.demandesPersonnel)?db.demandesPersonnel:[]);
  demandesPersonnelKnownIds=new Set(list.map(d=>String(d.id||d.ref||"")).filter(Boolean));
  demandesPersonnelLastOpenCount=demandePersonnelOpenCount();
}
function playDemandePersonnelSound(){
  try{
    const Ctx=window.AudioContext||window.webkitAudioContext;
    if(!Ctx)return;
    const ctx=window.__SGDI_DP_AUDIO_CTX__||(window.__SGDI_DP_AUDIO_CTX__=new Ctx());
    if(ctx.state==="suspended")ctx.resume().catch(()=>{});
    const osc=ctx.createOscillator();
    const gain=ctx.createGain();
    osc.type="sine";
    osc.frequency.setValueAtTime(880,ctx.currentTime);
    osc.frequency.setValueAtTime(660,ctx.currentTime+0.12);
    gain.gain.setValueAtTime(0.001,ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.18,ctx.currentTime+0.02);
    gain.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+0.34);
    osc.connect(gain);gain.connect(ctx.destination);
    osc.start();
    osc.stop(ctx.currentTime+0.36);
  }catch(e){}
}
function unlockDemandePersonnelSound(){
  try{
    const Ctx=window.AudioContext||window.webkitAudioContext;
    if(!Ctx||window.__SGDI_DP_AUDIO_CTX__)return;
    const ctx=new Ctx();
    window.__SGDI_DP_AUDIO_CTX__=ctx;
    if(ctx.state==="suspended")ctx.resume().catch(()=>{});
  }catch(e){}
}
document.addEventListener("click",unlockDemandePersonnelSound,{once:true});
document.addEventListener("keydown",unlockDemandePersonnelSound,{once:true});
async function refreshDemandesPersonnelFromPostgres(options){
  const opt=options||{};
  if(demandesPersonnelRefreshing||!sgdiAuthToken()||!db)return null;
  demandesPersonnelRefreshing=true;
  try{
    if(!demandesPersonnelKnownIds)initDemandesPersonnelWatcher();
    const res=await sgdiApi("/api/irongs/collections/demandesPersonnel",{method:"GET",legacy:false});
    const data=Array.isArray(res)?res:(Array.isArray(res&&res.data)?res.data:[]);
    const previousIds=demandesPersonnelKnownIds||new Set();
    const previousOpen=demandesPersonnelLastOpenCount||0;
    const newIds=data.map(d=>String(d.id||d.ref||"")).filter(Boolean).filter(id=>!previousIds.has(id));
    const before=JSON.stringify(db.demandesPersonnel||[]);
    const after=JSON.stringify(data);
    if(before!==after){
      db.demandesPersonnel=data;
      const movedStructure=typeof migrateStructureDemandes==="function"?migrateStructureDemandes():0;
      if(movedStructure&&typeof sgdiBackendSave==="function")sgdiBackendSave();
      demandesPersonnelKnownIds=new Set(data.map(d=>String(d.id||d.ref||"")).filter(Boolean));
      demandesPersonnelLastOpenCount=demandePersonnelOpenCount();
      renderSidebar();
      const h=(location.hash||"").slice(2);
      if(opt.render||h.startsWith("demandes_personnel"))renderView();
      if((newIds.length||demandePersonnelOpenCount()>previousOpen)&&!opt.mute){
        playDemandePersonnelSound();
        if(typeof toast==="function")toast("Nouvelle demande personnel reçue","info");
      }
    }
    return db.demandesPersonnel;
  }catch(e){
    if(!opt.silent&&typeof toast==="function")toast("Actualisation demandes impossible : "+(e.message||e),"error");
  }finally{
    demandesPersonnelRefreshing=false;
  }
  return null;
}
