function toast(msg,type="info"){
  const clean=stripCryptogramText(msg);
  // Les notifications ne créent plus de messages dans la boîte de dialogue.
  const h=document.getElementById("toast-host");
  if(!h)return;
  const safeType=["success","error","info","warning"].includes(type)?type:"info";
  h.innerHTML=`<div class="message-toast message-${safeType}" role="status"><div class="message-text">${escapeHTML(clean)}</div><button type="button" class="message-close" aria-label="Fermer" onclick="closeMessageToast()">×</button></div>`;
  clearTimeout(window.__sgdiToastTimer);
  window.__sgdiToastTimer=setTimeout(closeMessageToast,3600);
}
