function handleSocieteImageUpload(input){
  const f=input&&input.files&&input.files[0];if(!f)return;
  if(f.size>2*1024*1024){toast("Image > 2 Mo","error");input.value="";return}
  const r=new FileReader();
  r.onload=e=>{
    const url=e.target.result;
    const hidden=document.querySelector('.modal-bg [name="image"]');
    if(hidden)hidden.value=url;
    const holder=document.getElementById("societe-image-holder");
    if(holder)holder.innerHTML=`<img src="${url}" alt="Logo société" style="width:58px;height:58px;border-radius:14px;object-fit:cover;border:1px solid #cbd5e1"/><button type="button" class="btn btn-secondary" onclick="document.getElementById('societe-image-input').click()">Changer image</button><button type="button" class="btn btn-ghost text-red-600" onclick="removeSocieteImage()">Retirer</button>`;
  };
  r.readAsDataURL(f);
}
function removeSocieteImage(){
  const input=document.getElementById("societe-image-input");if(input)input.value="";
  const hidden=document.querySelector('.modal-bg [name="image"]');if(hidden)hidden.value="";
  const holder=document.getElementById("societe-image-holder");
  if(holder)holder.innerHTML=`<button type="button" class="btn btn-secondary" onclick="document.getElementById('societe-image-input').click()">Ajout image</button><span class="text-xs text-slate-500">Logo ou image de la société</span>`;
}
