function navigate(r){try{uiProgressStart();if(r.startsWith("materiel/fiche")||r==="materiel/fiches")sessionStorage.setItem("ficheContext","materiel");else if(r.startsWith("fiches")||r.startsWith("agents")||r.startsWith("effectif/agent"))sessionStorage.setItem("ficheContext",session?.transverse||"")}catch(e){}location.hash="#/"+r}
function setFicheContext(ctx){try{if(ctx)sessionStorage.setItem("ficheContext",ctx);else sessionStorage.removeItem("ficheContext")}catch(e){}}
function goBackSmart(){if(history.length>1)history.back();else navigate(session?.transverse?session.transverse+"/dashboard":"dashboard")}
function ficheContext(){try{return sessionStorage.getItem("ficheContext")||session?.transverse||""}catch(e){return session?.transverse||""}}
function isDrhFicheContext(){return ficheContext()==="drh"}
function isOpsFicheContext(){return ficheContext()==="ops"}
function isMaterielFicheContext(){return ficheContext()==="materiel"||(location.hash||"").includes("#/materiel/fiche")}
function onGlobalSearch(v){currentSearch=v||"";filterDomBySearch();renderGlobalSearchResults(currentSearch)}
function clearSearch(){currentSearch="";render()}
function clearSearchHighlights(root){
  (root||document).querySelectorAll("mark.ui-search-hit").forEach(m=>m.replaceWith(document.createTextNode(m.textContent||"")));
}
function deepSearchText(value,seen){
  seen=seen||new Set();
  if(value===null||value===undefined)return"";
  if(typeof value==="string"||typeof value==="number"||typeof value==="boolean")return String(value);
  if(value instanceof Date)return value.toISOString();
  if(typeof value!=="object")return"";
  if(seen.has(value))return"";
  seen.add(value);
  if(Array.isArray(value))return value.map(v=>deepSearchText(v,seen)).join(" ");
  return Object.entries(value).map(([k,v])=>`${k} ${deepSearchText(v,seen)}`).join(" ");
}
function normalizedSearchText(v){
  return String(v||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"");
}
function domSearchText(el){
  const fields=[el.textContent||""];
  el.querySelectorAll("input,select,textarea").forEach(f=>{
    fields.push(f.value||"");
    fields.push(f.getAttribute("placeholder")||"");
    if(f.tagName==="SELECT")fields.push(f.options?.[f.selectedIndex]?.textContent||"");
  });
  [...el.attributes||[]].forEach(a=>{if(a.name.startsWith("data-"))fields.push(a.value)});
  return fields.join(" ");
}
function globalSearchScopeAllows(item){
  if(!item||!item.obj)return true;
  if(isAdmin())return true;
  const s=mySoc();
  if(!s)return true;
  const obj=item.obj;
  return !obj.societe||obj.societe===s||obj.society===s;
}
function globalSearchItems(){
  if(!db)return[];
  const make=(type,label,arr,routeFn,titleFn,metaFn)=>Array.isArray(arr)?arr.map(o=>({type,label,obj:o,route:routeFn(o),title:titleFn(o),meta:metaFn(o),text:deepSearchText(o)})):[];
  const rows=[
    ...make("agent","Employé",db.agents,o=>`effectif/agent/${o.id}`,o=>`${o.matricule||""} ${o.nom||""} ${o.prenom||""}`.trim(),o=>`${o.societe||""} · ${o.fonction||o.poste||""} · ${o.statut||""}`),
    ...make("candidat","Candidat",db.candidats,o=>candidatIsArchived(o)?`candidats_archives/${o.id}`:candidatIsReserve(o)?`reserve/${o.id}`:`recrutement/${o.id}`,o=>`${o.nom||""} ${o.prenom||""}`.trim(),o=>`${o.societe||""} · ${o.posteSouhaite||""} · ${o.wilaya||""}`),
    ...make("site","Site",db.sites,o=>`sites/${o.id}`,o=>o.nom||o.site||"Site",o=>`${o.societe||""} · ${o.client||""} · ${o.adresse||""}`),
    ...make("article","Article",db.stockArticles,o=>`materiel/article/${o.id}`,o=>`${o.code||""} ${o.designation||o.nom||""}`.trim(),o=>`${o.societe||""} · ${o.categorie||""} · ${o.sousCategorie||""}`),
    ...make("fournisseur","Fournisseur",db.fournisseurs,o=>`materiel/fournisseur/${o.id}`,o=>o.nom||o.raisonSociale||"Fournisseur",o=>`${o.societe||""} · ${o.tel||o.telephone||""} · ${o.email||""}`),
    ...make("magasin","Magasin",db.magasins,o=>`materiel/magasin/${o.id}`,o=>o.nom||"Magasin",o=>`${o.societe||""} · ${o.localisation||o.adresse||""}`),
    ...make("client","Client",db.clients,o=>`commercial/clients`,o=>o.nom||o.raisonSociale||"Client",o=>`${o.societe||""} · ${o.contact||""} · ${o.tel||""}`),
    ...make("prestation","Prestation",db.catalogue,o=>`commercial/prestations`,o=>`${o.code||""} ${o.nom||o.designation||""}`.trim(),o=>`${o.societe||""} · ${o.categorie||""} · ${o.theme||""}`),
    ...make("incident","Evènement",db.incidents,o=>`incidents`,o=>o.titre||o.type||"Evènement",o=>`${o.statut||""} · ${formatDate(o.date||o.createdAt)}`),
    ...make("conge","Congé",db.conges,o=>`conges`,o=>o.type||"Congé",o=>`${o.statut||""} · ${formatDate(o.du)} - ${formatDate(o.au)}`),
    ...make("facture","Facture",db.factures,o=>`facturation/factures`,o=>o.numero||o.num||"Facture",o=>`${o.societe||""} · ${o.client||""} · ${money(o.total||o.montant)}`),
    ...make("devis","Devis",db.devis,o=>`facturation/devis`,o=>o.numero||o.num||"Devis",o=>`${o.societe||""} · ${o.client||""} · ${money(o.total||o.montant)}`)
  ];
  if(isAdmin())rows.push(...make("user","Utilisateur",db.users,o=>`admin/users`,o=>`${o.username||""} ${o.nom||""}`.trim(),o=>`${o.role||""} · ${o.niveau||""}`));
  return rows.filter(globalSearchScopeAllows);
}
function renderGlobalSearchResults(q){
  const box=document.getElementById("global-search-results");
  if(!box)return;
  const needle=normalizedSearchText(q).trim();
  if(needle.length<2){box.classList.remove("active");box.innerHTML="";return}
  const results=globalSearchItems().map(item=>{
    const hay=normalizedSearchText([item.type,item.title,item.meta,item.text].join(" "));
    if(!hay.includes(needle))return null;
    const idx=hay.indexOf(needle);
    return{...item,score:idx===0?3:hay.includes(" "+needle)?2:1};
  }).filter(Boolean).sort((a,b)=>b.score-a.score||String(a.title).localeCompare(String(b.title))).slice(0,12);
  box.classList.add("active");
  box.innerHTML=results.length?`<div class="p-2 text-[11px] text-slate-500 font-bold uppercase tracking-wider">Résultats dans toutes les données PostgreSQL</div>${results.map(r=>`<button type="button" class="global-search-row" onclick="openGlobalSearchResult('${escapeHTML(r.route)}')">
    <div><div class="global-search-type">${escapeHTML(r.label)}</div><div class="global-search-title">${escapeHTML(r.title||"Sans titre")}</div><div class="global-search-meta">${escapeHTML(r.meta||"")}</div></div>
    <span class="global-search-badge">Ouvrir</span>
  </button>`).join("")}`:`<div class="p-4 text-center text-sm text-slate-500">Aucun résultat dans les données enregistrées.</div>`;
}
function openGlobalSearchResult(route){
  document.getElementById("global-search-results")?.classList.remove("active");
  navigate(route);
}
function highlightSearchText(el,q){
  if(!q||el.dataset.uiHighlighting==="1")return;
  el.dataset.uiHighlighting="1";
  try{
    const walker=document.createTreeWalker(el,NodeFilter.SHOW_TEXT,{
      acceptNode(node){
        const p=node.parentElement;
        if(!p||["SCRIPT","STYLE","TEXTAREA","INPUT","SELECT","OPTION","MARK","BUTTON"].includes(p.tagName))return NodeFilter.FILTER_REJECT;
        return (node.nodeValue||"").toLowerCase().includes(q)?NodeFilter.FILTER_ACCEPT:NodeFilter.FILTER_SKIP;
      }
    });
    const nodes=[];
    while(walker.nextNode())nodes.push(walker.currentNode);
    nodes.slice(0,8).forEach(n=>{
      const text=n.nodeValue||"",idx=text.toLowerCase().indexOf(q);
      if(idx<0)return;
      const mark=document.createElement("mark");
      mark.className="ui-search-hit";
      mark.textContent=text.slice(idx,idx+q.length);
      const frag=document.createDocumentFragment();
      frag.appendChild(document.createTextNode(text.slice(0,idx)));
      frag.appendChild(mark);
      frag.appendChild(document.createTextNode(text.slice(idx+q.length)));
      n.parentNode.replaceChild(frag,n);
    });
  }finally{delete el.dataset.uiHighlighting}
}
function filterDomBySearch(){
  const q=normalizedSearchText(currentSearch).trim();
  const rows=[...document.querySelectorAll("[data-searchable]")];
  clearSearchHighlights(document.getElementById("view")||document);
  let visible=0;
  rows.forEach(el=>{
    if(!q){el.style.display="";visible++;return}
    const t=normalizedSearchText(domSearchText(el));
    const ok=t.includes(q);
    el.style.display=ok?"":"none";
    if(ok){visible++;highlightSearchText(el,q)}
  });
  const view=document.getElementById("view"),old=document.getElementById("ui-empty-search");
  if(old)old.remove();
  if(q&&rows.length&&visible===0&&view)view.insertAdjacentHTML("beforeend",`<div id="ui-empty-search" class="ui-empty-search">Aucun résultat pour <strong>${escapeHTML(currentSearch)}</strong></div>`);
}
function dialogueIsOpen(){return sessionStorage.getItem("dialogueOpen")!=="0"}
function dialogueToggle(open){
  const next=open===undefined?!dialogueIsOpen():!!open;
  sessionStorage.setItem("dialogueOpen",next?"1":"0");
  if(next)dialogueMarkRead();
  render();
}
function dialogueIncomingUnreadItems(){
  if(!session)return[];
  const u=session.username;
  return (db.echanges||[]).filter(m=>m.type==="message"&&m.to!=="all"&&!dialogueMessageArchived(m)&&m.from!==u&&(m.to===u||isAdmin())&&(!m.luPar||!m.luPar.includes(u)));
}
function dialoguePlaySound(){
  try{
    const Ctx=window.AudioContext||window.webkitAudioContext;if(!Ctx)return;
    const ctx=new Ctx();
    const o=ctx.createOscillator();const g=ctx.createGain();
    o.type="sine";o.frequency.value=880;g.gain.value=.001;
    o.connect(g);g.connect(ctx.destination);
    const t=ctx.currentTime;
    g.gain.exponentialRampToValueAtTime(.08,t+.02);
    g.gain.exponentialRampToValueAtTime(.001,t+.18);
    o.start(t);o.stop(t+.2);
  }catch(e){}
}
function dialogueCheckNewMessages(){
  if(!session||!db)return;
  const ids=dialogueIncomingUnreadItems().map(m=>m.id).sort();
  const key="dialogueUnreadIds:"+session.username;
  const prev=(sessionStorage.getItem(key)||"").split(",").filter(Boolean);
  const hasBaseline=sessionStorage.getItem(key)!==null;
  const fresh=ids.filter(id=>!prev.includes(id));
  sessionStorage.setItem(key,ids.join(","));
  if(hasBaseline&&fresh.length){dialoguePlaySound();if(typeof toast==="function")toast("Nouveau message reçu","info")}
}
function dialogueMarkReceived(){
  if(!session||!db||!db.echanges)return;
  const u=session.username;let changed=false;
  dialogueVisibleItems().forEach(m=>{
    if(dialogueMessageArchived(m)||m.from===u)return;
    if(!m.receivedBy)m.receivedBy=[];
    if(!m.receivedBy.includes(u)){m.receivedBy.push(u);changed=true}
  });
  if(changed)saveDB();
}
function dialogueAttachmentHTML(m){
  const files=Array.isArray(m.attachments)?m.attachments:[];
  if(!files.length)return "";
  return files.map((f,i)=>'<a class="chat-attachment" href="'+escapeHTML(f.data||'#')+'" download="'+escapeHTML(f.name||('piece-'+(i+1)))+'">📎 '+escapeHTML(f.name||('Pièce '+(i+1)))+'</a>').join('');
}
function dialogueReadAttachment(file){
  return new Promise((resolve,reject)=>{
    if(!file)return resolve(null);
    if(file.size>3*1024*1024)return reject(new Error('Pièce jointe > 3 Mo'));
    const r=new FileReader();
    r.onload=e=>resolve({name:file.name,type:file.type||'application/octet-stream',size:file.size,data:e.target.result});
    r.onerror=()=>reject(new Error('Lecture pièce jointe impossible'));
    r.readAsDataURL(file);
  });
}
function dialogueFileChanged(input){
  const f=input&&input.files&&input.files[0];
  const form=input?input.closest('form'):null;
  const n=form?form.querySelector('[data-dialogue-file-name]'):null;
  if(n)n.textContent=f?'Pièce jointe : '+f.name:'Aucune pièce jointe';
}
function dialogueMessageStatus(m){
  if(!session||!m||m.from!==session.username)return"";
  if((m.luPar||[]).includes(m.to))return '<div class="chat-status read">✓✓ Lu</div>';
  if((m.receivedBy||[]).includes(m.to))return '<div class="chat-status received">✓✓ Reçu</div>';
  return '<div class="chat-status sent">✓ Envoyé</div>';
}
function dialogueFolder(){
  const v=sessionStorage.getItem("dialogueFolder")||"inbox";
  return ["inbox","sent","archived"].includes(v)?v:"inbox";
}
function dialogueMessageArchived(m){return !!(session&&m&&Array.isArray(m.archivedBy)&&m.archivedBy.includes(session.username))}
function dialogueFolderItems(folder){
  const u=session?.username||"";
  const f=folder||dialogueFolder();
  return dialogueVisibleItems().filter(m=>{
    const archived=dialogueMessageArchived(m);
    if(f==="archived")return archived;
    if(archived)return false;
    if(f==="sent")return m.from===u;
    return m.to===u||(isAdmin()&&m.from!==u);
  });
}
function dialogueFolderCounts(){
  const u=session?.username||"";
  const all=dialogueVisibleItems();
  return {
    inbox:all.filter(m=>!dialogueMessageArchived(m)&&(m.to===u||(isAdmin()&&m.from!==u))).length,
    sent:all.filter(m=>!dialogueMessageArchived(m)&&m.from===u).length,
    archived:all.filter(m=>dialogueMessageArchived(m)).length
  };
}
function dialogueSetFolder(folder){
  sessionStorage.setItem("dialogueFolder",folder||"inbox");
  const peers=dialogueConversationUsers(folder||"inbox");
  sessionStorage.setItem("dialoguePeer",peers[0]?.key||"");
  dialogueCheckNewMessages();
  render();
}
function dialogueArchivePeer(peer,restore){
  if(!session||!db||!db.echanges||!peer)return;
  const u=session.username;
  let changed=false;
  dialogueThreadItems(peer).forEach(m=>{
    if(!m.archivedBy)m.archivedBy=[];
    const has=m.archivedBy.includes(u);
    if(restore&&has){m.archivedBy=m.archivedBy.filter(x=>x!==u);changed=true}
    if(!restore&&!has){m.archivedBy.push(u);changed=true}
  });
  if(changed){saveDB();toast(restore?"Conversation restaurée":"Conversation archivée","success")}
  render();
}
function dialogueSelectedRecipientChips(form){
  if(!form)return;
  const box=form.querySelector('[data-dialogue-selected]');
  if(!box)return;
  const values=[...form.querySelectorAll('input[name="to"]:checked')].map(i=>i.value);
  const users=db.users||[];
  box.innerHTML=values.length?values.map(v=>{
    const u=users.find(x=>x.username===v);
    return '<span class="dialogue-recipient-chip">'+escapeHTML(u?(u.nom||u.username):v)+'</span>';
  }).join(''):'Aucun destinataire sélectionné';
}
function dialogueVisibleItems(){
  const all=(db.echanges||[]).slice().sort((a,b)=>new Date(a.date)-new Date(b.date));
  const messages=all.filter(m=>m.type==="message"&&m.to!=="all");
  if(isAdmin())return messages;
  const u=session?session.username:"";
  return messages.filter(m=>m.from===u||m.to===u);
}
function dialoguePeerKey(m){
  if(!session||!m)return"admin";
  const u=session.username;
  return m.from===u?(m.to||"admin"):(m.from||"admin");
}
function dialogueSelectedPeer(){
  const saved=sessionStorage.getItem("dialoguePeer")||"";
  const peers=dialogueConversationUsers();
  if(saved&&peers.some(p=>p.key===saved))return saved;
  return peers[0]?.key||"";
}
function dialogueSetPeer(peer){sessionStorage.setItem("dialoguePeer",peer||"");dialogueMarkRead(peer);dialogueCheckNewMessages();render()}
function dialogueConversationUsers(folder){
  const users=(db.users||[]).filter(u=>u.username!==session?.username);
  const map=new Map();
  dialogueFolderItems(folder).forEach(m=>{
    const key=dialoguePeerKey(m);
    const user=users.find(u=>u.username===key);
    if(!map.has(key))map.set(key,{key,label:user?(user.nom||user.username):(key==="admin"?"Administrateur":key),sub:user?String(user.role||"").toUpperCase():"Conversation",unread:0,lastDate:m.date||""});
    const row=map.get(key);
    if(new Date(m.date||0)>new Date(row.lastDate||0))row.lastDate=m.date||"";
    if(m.to===session.username&&(!m.luPar||!m.luPar.includes(session.username)))row.unread++;
  });
  return [...map.values()].sort((a,b)=>((b.unread||0)-(a.unread||0))||(new Date(b.lastDate||0)-new Date(a.lastDate||0))||String(a.label).localeCompare(String(b.label)));
}
function dialogueThreadItems(peer){
  const u=session?.username||"";
  return dialogueFolderItems().filter(m=>{
    if(!peer)return false;
    return (m.from===u&&m.to===peer)||(m.from===peer&&m.to===u)||(isAdmin()&&(m.from===peer||m.to===peer));
  }).sort((a,b)=>new Date(a.date)-new Date(b.date));
}
function dialogueMarkRead(peer){
  if(!session||!db||!db.echanges)return;
  const u=session.username;
  const target=peer||sessionStorage.getItem("dialoguePeer")||dialogueSelectedPeer();
  const items=target?dialogueThreadItems(target):dialogueVisibleItems();
  let changed=false;
  items.forEach(m=>{if(!m.luPar)m.luPar=[];if(!m.luPar.includes(u)){m.luPar.push(u);changed=true}});
  if(changed)saveDB();
}
function dialogueUsersOptions(selected){
  const users=(db.users||[]).filter(u=>u.username!==session.username);
  const opts=users.map(u=>'<option value="'+escapeHTML(u.username)+'" '+(selected===u.username?'selected':'')+'>'+escapeHTML(u.nom||u.username)+' · '+escapeHTML(u.role||'')+'</option>').join('');
  return '<select class="select" name="to">'+opts+'</select>';
}
function dialogueRecipientsHTML(selected){
  const users=(db.users||[]).filter(u=>u.username!==session.username);
  if(!users.length)return '<div class="dialogue-recipients"><span class="text-xs text-slate-500">Aucun destinataire disponible</span></div><div class="dialogue-selected-recipients" data-dialogue-selected>Aucun destinataire sélectionné</div>';
  const list='<div class="dialogue-recipients" aria-label="Destinataires">'+users.map(u=>{
    const checked=u.username===selected?' checked':'';
    const label=(u.nom||u.username)+(u.role?' · '+u.role:'');
    return '<label class="dialogue-recipient"><input type="checkbox" name="to" value="'+escapeHTML(u.username)+'"'+checked+' onchange="dialogueSelectedRecipientChips(this.form)"><span>'+escapeHTML(label)+'</span></label>';
  }).join('')+'</div>';
  const selectedUsers=users.filter(u=>u.username===selected);
  const chips=selectedUsers.length?selectedUsers.map(u=>'<span class="dialogue-recipient-chip">'+escapeHTML(u.nom||u.username)+'</span>').join(''):'Aucun destinataire sélectionné';
  return list+'<div class="dialogue-selected-recipients" data-dialogue-selected>'+chips+'</div>';
}
function importanceBadge(v,extraClass){
  const imp=v||"Normal";
  if(imp==="Très élevée")return'<span class="pill pill-red '+(extraClass||'')+'" style="background:#7f1d1d;color:#fff">Très élevée</span>';
  if(imp==="Élevée")return'<span class="pill pill-red '+(extraClass||'')+'">Élevée</span>';
  return'<span class="pill pill-gray '+(extraClass||'')+'">Normal</span>';
}
function dialogueBoxHTML(){
  if(!session)return"";
  const open=dialogueIsOpen();
  dialogueMarkReceived();
  dialogueCheckNewMessages();
  const folder=dialogueFolder();
  const selected=dialogueSelectedPeer();
  if(open)dialogueMarkRead(selected);
  const peers=dialogueConversationUsers(folder);
  const peer=peers.find(p=>p.key===selected)||peers[0]||{key:"",label:"Nouvelle conversation",sub:""};
  const unread=dialogueIncomingUnreadItems().length;
  const counts=dialogueFolderCounts();
  const foldersHTML=[
    {key:"inbox",label:"Messages reçus",count:counts.inbox},
    {key:"sent",label:"Messages envoyés",count:counts.sent},
    {key:"archived",label:"Messages archivés",count:counts.archived}
  ].map(f=>'<button class="dialogue-folder '+(folder===f.key?'active':'')+'" onclick="dialogueSetFolder(\''+f.key+'\')"><span>'+f.label+'</span><span class="count">'+f.count+'</span></button>').join('');
  const usersHTML=peers.map(p=>'<button class="dialogue-user '+(p.key===selected?'active ':'')+(p.unread?'has-unread':'')+'" onclick="dialogueSetPeer(\''+escapeHTML(p.key)+'\')"><span>'+escapeHTML(p.label)+'</span>'+(p.unread?'<span class="dot">'+p.unread+'</span>':'')+'<div style="font-size:9px;opacity:.7;margin-top:3px">'+escapeHTML(p.sub||'')+'</div></button>').join('');
  const archiveButton=selected?'<button class="btn btn-ghost dialogue-slim-btn" onclick="dialogueArchivePeer(\''+escapeHTML(selected)+'\','+(folder==="archived"?'true':'false')+')">'+(folder==="archived"?'Restaurer':'Archiver')+'</button>':'';
  return '<div class="dialogue-modal-backdrop no-print '+(open?'':'closed')+'" onclick="if(event.target===this)dialogueToggle(false)">'+
    '<aside class="dialogue-panel" aria-label="Boîte de dialogue interne">'+
      '<div class="dialogue-head"><div class="dialogue-title">MESSAGERIE SGDI'+(unread?'<span class="dialogue-red-light"></span>':'')+'</div><div class="dialogue-head-row"><div class="dialogue-subtitle">Messages directs entre utilisateurs</div><button class="btn btn-ghost dialogue-slim-btn" onclick="dialogueToggle(false)">Fermer</button></div></div>'+
      '<div class="dialogue-layout"><div class="dialogue-users"><div class="dialogue-folders">'+foldersHTML+'</div>'+(usersHTML||'<div class="text-xs text-slate-500">Aucune conversation</div>')+'</div><div class="dialogue-chat">'+
        '<div class="dialogue-chat-head"><div class="flex items-center justify-between gap-2"><div>'+escapeHTML(peer.label)+' <span class="text-[10px] text-slate-500 font-normal">'+escapeHTML(peer.sub||'')+'</span></div>'+archiveButton+'</div></div>'+
        '<div class="dialogue-thread" id="dialogue-body">'+feedRowsHTML(selected)+'</div>'+dialogueComposerHTML(selected)+
      '</div></div></aside></div>';
}
function feedRowsHTML(peer){
  const selected=peer||dialogueSelectedPeer();
  const items=dialogueThreadItems(selected);
  if(!items.length)return '<div class="text-center text-xs text-slate-500 mt-8">Aucun message. Lancez la conversation.</div>';
  return items.map(m=>{
    const mine=m.from===session.username;
    const from=(db.users||[]).find(u=>u.username===m.from);
    return '<div class="chat-bubble '+(mine?'mine':'theirs')+'">'+(m.sujet?'<div class="font-bold mb-1">'+escapeHTML(m.sujet)+'</div>':'')+'<div>'+escapeHTML(m.message||'')+'</div><div class="chat-meta">'+escapeHTML(mine?'Moi':(from?from.nom:m.from||'—'))+' · '+new Date(m.date).toLocaleString('fr-FR')+'</div>'+dialogueAttachmentHTML(m)+dialogueMessageStatus(m)+'</div>';
  }).join('');
}
function dialogueComposerHTML(peer){
  const selected=peer||dialogueSelectedPeer();
  return '<form class="dialogue-composer" onsubmit="event.preventDefault();dialogueSend(this)">'+dialogueRecipientsHTML(selected)+'<input type="file" name="attachment" class="hidden" onchange="dialogueFileChanged(this)"/><div style="grid-column:1/3"><button type="button" class="dialogue-attach" title="Ajouter pièce jointe" onclick="this.form.attachment.click()"><span aria-hidden="true">📎</span><span>Ajouter pièce jointe</span></button></div><textarea class="input" name="message" placeholder="Écrire un message..." onkeydown="if(event.key===\'Enter\'&&!event.shiftKey){event.preventDefault();this.form.requestSubmit();}"></textarea><button class="dialogue-send" title="Envoyer">➤</button><div class="dialogue-file-name" data-dialogue-file-name>Aucune pièce jointe</div></form>';
}
function refreshRealtimeFeed(){
  const body=document.getElementById("dialogue-body");
  if(!body||!db||!session)return;
  const peer=dialogueSelectedPeer();
  const wasBottom=body.scrollTop+body.clientHeight>=body.scrollHeight-40;
  body.innerHTML=feedRowsHTML(peer);
  stripCryptogrammes(body);
  if(wasBottom)body.scrollTop=body.scrollHeight;
}
async function dialogueSend(form){
  const fd=new FormData(form);
  const msg=(fd.get("message")||"").toString().trim();
  const recipients=[...new Set(fd.getAll("to").map(v=>String(v||"").trim()).filter(v=>v&&v!=="all"&&v!==session.username))];
  if(!recipients.length){toast("Choisissez au moins un utilisateur destinataire","error");return}
  const attachmentFile=form.attachment&&form.attachment.files?form.attachment.files[0]:null;
  let attachment=null;
  try{attachment=await dialogueReadAttachment(attachmentFile)}catch(e){toast(e.message||String(e),"error");return}
  if(!msg&&!attachment){toast("Message ou pièce jointe obligatoire","error");return}
  if(!db.echanges)db.echanges=[];
  const createdAt=new Date().toISOString();
  recipients.forEach(to=>db.echanges.push({id:uid("ech"),date:createdAt,from:session.username,to,sujet:"",importance:"Normal",message:msg,attachments:attachment?[attachment]:[],obligation:"",droit:"",conduite:"",receivedBy:[],luPar:[session.username],type:"message"}));
  if(db.echanges.length>800)db.echanges=db.echanges.slice(-800);
  saveDB();
  sessionStorage.setItem("dialogueOpen","1");
  sessionStorage.setItem("dialoguePeer",recipients[0]);
  form.reset();
  toast(recipients.length>1?"Message envoyé à "+recipients.length+" utilisateurs":"Message envoyé","success");
  render();
  setTimeout(()=>{const b=document.getElementById("dialogue-body");if(b)b.scrollTop=b.scrollHeight},50);
}
