function renderLogin(){
  document.getElementById("app").innerHTML=`<div class="min-h-screen flex items-center justify-center p-6" style="background:#f8fafc;color:#0f172a">
    <div class="w-full max-w-sm">
      <div class="text-center mb-8">
        <div class="text-4xl font-black tracking-wide text-slate-950">SGDI</div>
        <div class="text-sm text-slate-500 mt-1 tracking-widest uppercase">Algérie</div>
      </div>
      <div class="p-7 rounded-xl" style="background:#ffffff;border:1px solid #e2e8f0;box-shadow:0 24px 60px rgba(15,23,42,.10)">
        <form id="login-form" onsubmit="event.preventDefault();login(this.username.value,this.password.value)">
          <label class="block text-xs font-semibold text-slate-600 mb-2">Identifiant</label>
          <input class="input mb-4" style="background:#fff;color:#0f172a;border-color:#cbd5e1" name="username"  autofocus/>
          <label class="block text-xs font-semibold text-slate-600 mb-2">Mot de passe</label>
          <input class="input mb-4" style="background:#fff;color:#0f172a;border-color:#cbd5e1" type="password" name="password" />
          <button class="btn w-full justify-center" style="background:#043970;color:#111;font-weight:800">Se connecter</button>
        </form>
      </div>
    </div>
    <button type="button" class="login-admin-system-shortcut" onclick="openAdminSystemPasswordModal(document.getElementById('login-form'))" title="Administration système" aria-label="Administration système">
      <span aria-hidden="true">⚙</span>
      <span>Administration système</span>
    </button>
  </div>`;
}

/* ---- DASHBOARD ---- */
function dashboardModuleShortcuts(){
  const modules=[
    {key:"drh",title:"DRH",desc:"Candidatures, contrats, fiches, badges, effectif",metric:()=>`${(db.agents||[]).length} employés`,roles:["rh","admin"]},
    {key:"ops",title:"OPS",desc:"Sites, affectations, mouvements et feuilles de présence",metric:()=>`${(db.sites||[]).filter(s=>s.actif).length} sites`,roles:["rh","dispatch","admin"]},
    {key:"materiel",title:"MATERIEL / EQUIPEMENT",desc:"Articles, magasins, fournisseurs, dotations, reversements",metric:()=>`${(db.stockArticles||[]).length} articles`,roles:["rh","dispatch","admin"]},
    {key:"facturation",title:"FINANCES / COMPTABILITE",desc:"Factures, paiements, caisse, avances et situation",metric:()=>`${(db.factures||[]).length} factures`,roles:["rh","admin"]},
    {key:"commercial",title:"COMMERCIAL",desc:"Clients, contrats, prestations et opportunités",metric:()=>`${(db.clients||[]).length} clients`,roles:["rh","admin"]}
  ];
  const role=session?.role||"agent";
  const visible=modules.filter(m=>m.roles.includes(role));
  if(!visible.length)return"";
  return`<div class="dash-module-grid">
      ${visible.map(m=>`<button type="button" onclick="${session?.societe?`enterSocieteStructure('${m.key}')`:`enterTransverseModule('${m.key}')`}" class="dash-module">
        <div>
          <div class="dash-module-title">${escapeHTML(m.title)}</div>
          <div class="dash-module-desc">${escapeHTML(m.desc)}</div>
        </div>
        <div class="dash-module-foot"><span>${escapeHTML(m.metric())}</span><span>Ouvrir</span></div>
      </button>`).join("")}
    </div>`;
}
function renderDashboard(view){
  const filter=mySoc()||sessionStorage.getItem("dashSociete")||"";
  const lockSoc=!!mySoc();
  const matchSoc=a=>!filter||a.societe===filter;
  const agentsSoc=(db.agents||[]).filter(matchSoc);
  const agentsActifs=agentsSoc.filter(a=>a.statut==="actif");
  const sitesActifs=(db.sites||[]).filter(s=>{if(!s.actif)return false;if(!filter)return true;return db.agents.some(a=>a.affectationCourante?.siteId===s.id&&a.societe===filter)});
  const candidatsReserve=(db.candidats||[]).filter(c=>candidatIsReserve(c)&&(!filter||c.societe===filter));
  const candidatsNouveaux=(db.candidats||[]).filter(c=>!candidatIsReserve(c)&&!candidatIsArchived(c)&&(!filter||c.societe===filter));
  const enConge=db.agents.filter(a=>matchSoc(a)&&db.conges.some(c=>c.agentId===a.id&&c.statut==="approuve"&&c.type!=="Maladie"&&inRange(c)));
  const enMaladie=db.agents.filter(a=>matchSoc(a)&&db.conges.some(c=>c.agentId===a.id&&c.statut==="approuve"&&c.type==="Maladie"&&inRange(c)));
  const absents=db.agents.filter(a=>a.statut==="absent"&&matchSoc(a));
  const suspendus=db.agents.filter(a=>a.statut==="suspendu"&&matchSoc(a));
  const nbIncidentsOpen=(db.incidents||[]).filter(i=>i.statut==="en_cours").length;
  const nbCongesPending=(db.conges||[]).filter(c=>c.statut==="en_attente").length;
  const nbFinEssai30=db.agents.filter(a=>matchSoc(a)&&a.dateFinEssai&&daysBetween(today(),a.dateFinEssai)>=0&&daysBetween(today(),a.dateFinEssai)<=30).length;
  const finContrats30=agentsSoc.filter(a=>a.dateFinContrat&&daysBetween(today(),a.dateFinContrat)>=0&&daysBetween(today(),a.dateFinContrat)<=30);
  const clientsAlerte=(db.clients||[]).filter(c=>(!filter||c.societe===filter)&&c.dateFinContrat&&daysBetween(today(),c.dateFinContrat)<=30);
  const stockKpi=typeof stockSummaryKPI==="function"?stockSummaryKPI():{enRupture:0,enAlerte:0,totalArticles:(db.stockArticles||[]).length,totalValeur:0};
  const fpToday=(db.feuillePresence||[]).filter(f=>f.date===today()&&(!filter||f.societe===filter));
  const fpPointes=fpToday.filter(f=>f.heureArrivee).length;
  const fpRate=fpToday.length?Math.round(fpPointes*100/fpToday.length):0;
  const socRows=SOCIETES.map(s=>{
    const ag=(db.agents||[]).filter(a=>a.societe===s);
    const act=ag.filter(a=>a.statut==="actif").length;
    const cand=(db.candidats||[]).filter(c=>c.societe===s&&!candidatIsArchived(c)).length;
    const siteIds=new Set(ag.map(a=>a.affectationCourante?.siteId).filter(Boolean));
    const sites=(db.sites||[]).filter(st=>st.actif&&siteIds.has(st.id)).length;
    const pct=ag.length?Math.round(act*100/ag.length):0;
    return{s,ag:ag.length,act,cand,sites,pct};
  });
  const recent=[...(db.echanges||[]).map(x=>({date:x.date,title:x.sujet||"Fil d'actualité",text:x.message||"",route:""})),...(db.incidents||[]).map(x=>({date:x.date||x.createdAt,title:"Evènement",text:x.titre||x.description||"",route:"incidents"})),...(db.conges||[]).map(x=>({date:x.createdAt||x.du,title:"Congé",text:x.type||x.statut||"",route:"conges"}))].filter(x=>x.date).sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,7);
  const alerts=[
    {n:nbIncidentsOpen,title:"Evènements en cours",text:"Main courante et incidents ouverts",route:"incidents",type:nbIncidentsOpen?"danger":"info"},
    {n:nbCongesPending,title:"Congés en attente",text:"Demandes à valider ou refuser",route:"conges",type:nbCongesPending?"warn":"info"},
    {n:nbFinEssai30,title:"Fin période d'essai",text:"Échéances dans les 30 jours",route:"effectif/actifs",type:nbFinEssai30?"warn":"info"},
    {n:finContrats30.length,title:"Fin contrats personnel",text:"Contrats à renouveler ou clôturer",route:"effectif/actifs",type:finContrats30.length?"danger":"info"},
    {n:clientsAlerte.length,title:"Fin contrats clients",text:"Alertes commerciales à 30 jours",route:"commercial/clients",type:clientsAlerte.length?"warn":"info"},
    {n:(stockKpi.enRupture||0)+(stockKpi.enAlerte||0),title:"Stock critique",text:"Rupture ou stock bas",route:"materiel/articles",type:((stockKpi.enRupture||0)+(stockKpi.enAlerte||0))?"danger":"info"}
  ];
  view.innerHTML=`<div class="dash-shell">
    <section class="dash-kpi-grid">
      ${dashboardKpi("Effectif actif",agentsActifs.length,`${agentsSoc.length} total`,"effectif/actifs","ok")}
      ${dashboardKpi("Sites actifs",sitesActifs.length,"Sites opérationnels","sites/actifs","ok")}
      ${dashboardKpi("Candidats",candidatsReserve.length,`${candidatsNouveaux.length} à compléter`,"reserve","info")}
      ${dashboardKpi("Pointage du jour",fpRate+"%",`${fpPointes}/${fpToday.length||0} lignes`,"pointage/quotidien",fpRate<80&&fpToday.length?"warn":"ok")}
      ${dashboardKpi("Absence / maladie",absents.length+enMaladie.length,`${absents.length} absence · ${enMaladie.length} maladie`,"effectif/absents",(absents.length+enMaladie.length)?"danger":"ok")}
      ${dashboardKpi("Congés",enConge.length,`${nbCongesPending} en attente`,"conges",nbCongesPending?"warn":"ok")}
      ${dashboardKpi("Stock critique",(stockKpi.enRupture||0)+(stockKpi.enAlerte||0),`${stockKpi.totalArticles||0} articles`,"materiel/articles",((stockKpi.enRupture||0)+(stockKpi.enAlerte||0))?"danger":"ok")}
      ${dashboardKpi("Contrats à suivre",finContrats30.length+clientsAlerte.length,`${finContrats30.length} RH · ${clientsAlerte.length} clients`,"commercial/clients",(finContrats30.length+clientsAlerte.length)?"warn":"ok")}
    </section>

    <section class="dash-panel">
      <div class="dash-panel-head"><div class="dash-panel-title">Modules et fonctionnalités</div><button class="btn btn-ghost text-xs" onclick="openCommandPalette()">Tout rechercher</button></div>
      <div class="dash-panel-body">${dashboardModuleShortcuts()}</div>
    </section>

    <section class="dash-layout">
      <div class="dash-panel">
        <div class="dash-panel-head"><div class="dash-panel-title">Situation par société</div><span class="text-xs text-slate-500">${filter?"Filtré":"Vue globale"}</span></div>
        <div class="dash-panel-body">
          <div class="dash-mini-list">${socRows.map(r=>`<button class="dash-mini-row text-left w-full" onclick="setDashSociete('${escapeHTML(r.s)}')" data-searchable>
            <div style="min-width:180px"><div class="font-bold text-sm">${escapeHTML(r.s)}</div><div class="text-[11px] text-slate-500">${r.act}/${r.ag} actifs · ${r.sites} sites · ${r.cand} candidats</div></div>
            <div class="flex-1"><div class="dash-bar"><span style="width:${r.pct}%"></span></div></div>
            <div class="font-black text-sm">${r.pct}%</div>
          </button>`).join("")}</div>
        </div>
      </div>
      <div class="dash-panel">
        <div class="dash-panel-head"><div class="dash-panel-title">Centre d'alertes</div><span class="pill ${alerts.some(a=>a.n)?"pill-red":"pill-green"}">${alerts.reduce((s,a)=>s+a.n,0)}</span></div>
        <div class="dash-panel-body"><div class="dash-mini-list">
          ${alerts.map(a=>`<button class="dash-alert ${a.type}" onclick="navigate('${a.route}')" data-searchable>
            <div><div class="dash-alert-title">${escapeHTML(a.title)}</div><div class="dash-alert-text">${escapeHTML(a.text)}</div></div>
            <span class="pill ${a.type==="danger"?"pill-red":a.type==="warn"?"pill-amber":"pill-blue"}">${a.n}</span>
          </button>`).join("")}
        </div></div>
      </div>
    </section>

    <section class="dash-layout">
      <div class="dash-panel">
        <div class="dash-panel-head"><div class="dash-panel-title">Actions fréquentes</div><span class="text-xs text-slate-500">Accès direct</span></div>
        <div class="dash-panel-body"><div class="grid grid-cols-1 md:grid-cols-3 gap-2">
          ${dashboardAction("Candidats en réserve","Liste et activation","reserve")}
          ${dashboardAction("Créer / modifier site","Effectifs et relèves","sites/nouveau")}
          ${dashboardAction("Générer présence","Pointage du jour","pointage/quotidien")}
          ${dashboardAction("Ordre de mouvement","Mouvement personnel","ops/mouvements")}
          ${dashboardAction("Dotation matériel","Sortie stock personnel","materiel/dotation")}
          ${dashboardAction("Inventaire articles","Contrôle stock","materiel/articles")}
          ${dashboardAction("Nouveau client","Contrat commercial","commercial/clients")}
          ${dashboardAction("Administration","Droits et paramètres","admin/dashboard")}
        </div></div>
      </div>
      <div class="dash-panel">
        <div class="dash-panel-head"><div class="dash-panel-title">Activité récente</div><span class="text-xs text-slate-500">${recent.length}</span></div>
        <div class="dash-panel-body"><div class="dash-mini-list">
          ${recent.length?recent.map(r=>`<div class="dash-mini-row" data-searchable><div><div class="font-bold text-xs">${escapeHTML(r.title||"Activité")}</div><div class="text-[11px] text-slate-500">${escapeHTML(String(r.text||"").slice(0,80))}</div></div><div class="text-[10px] text-slate-400 whitespace-nowrap">${formatDate(r.date)}</div></div>`).join(""):`<div class="text-sm text-slate-500 text-center p-4">Aucune activité récente.</div>`}
        </div></div>
      </div>
    </section>
  </div>`;
}
function dashboardKpi(label,value,sub,route,status){
  const dot=status==="danger"?"danger":status==="warn"?"warn":"";
  return`<a class="dash-kpi" href="#/${route}" data-searchable>
    <div class="flex items-center justify-between"><div class="label">${escapeHTML(label)}</div><span class="dash-status-dot ${dot}"></span></div>
    <div class="value">${escapeHTML(value)}</div>
    <div class="sub">${escapeHTML(sub||"")}</div>
  </a>`;
}
function dashboardAction(title,desc,route){
  return`<button type="button" class="dash-alert info text-left" onclick="navigate('${route}')" data-searchable>
    <div><div class="dash-alert-title">${escapeHTML(title)}</div><div class="dash-alert-text">${escapeHTML(desc)}</div></div>
    <span class="text-xs font-black text-slate-400">Ouvrir</span>
  </button>`;
}
function setDashSociete(v){sessionStorage.setItem("dashSociete",v||"");renderView()}
function kpiCard(label,val,icon,color){const c={amber:"#043970",blue:"#043970",indigo:"#6366f1",green:"#043970",red:"#ef4444"};return`<div class="card p-5"><div class="flex items-center justify-between mb-3"><div class="text-3xl" style="color:${c[color]}">${icon}</div><h3 class="text-right">${label}</h3></div><div class="text-4xl font-bold">${val}</div></div>`}
function kpiCardLink(label,val,icon,color,href){const c={amber:"#043970",blue:"#043970",indigo:"#6366f1",green:"#043970",red:"#ef4444"};return`<a href="${href}" class="card p-5 block hover:shadow-md transition-shadow" style="cursor:pointer;text-decoration:none;color:inherit"><div class="flex items-center justify-between mb-3"><div class="text-3xl" style="color:${c[color]}">${icon}</div><h3 class="text-right">${label}</h3></div><div class="text-4xl font-bold">${val}</div><div class="text-xs text-slate-400 mt-1">→ Cliquer pour voir la liste</div></a>`}

