function renderDossiers(view){
  const people=[...db.agents.map(a=>({type:"agent",id:a.id,nom:`${a.nom} ${a.prenom}`,matricule:a.matricule,photo:a.photo,societe:a.societe,statut:a.statut,cvFile:a.cvFile,documents:a.documents||{}})),...db.candidats.map(c=>({type:"candidat",id:c.id,nom:`${c.nom} ${c.prenom}`,matricule:"—",photo:c.photo,societe:c.societe,statut:c.statut,cvFile:c.cvFile,documents:c.documents||{}}))];
  const totalPieces=people.reduce((s,p)=>s+Object.keys(p.documents||{}).length+(p.cvFile?1:0),0);
  view.innerHTML=`<h1 class="text-2xl font-bold mb-2">📁 Dossier administratif</h1>
    <p class="text-slate-500 text-sm mb-6">Archive de toutes les pièces téléversées — candidats et agents.</p>
    <div class="grid grid-4 mb-6">${kpiCard("Dossiers agents",db.agents.length,"👮","amber")}${kpiCard("Candidats",db.candidats.length,"📝","indigo")}${kpiCard("Pièces archivées",totalPieces,"📄","blue")}${kpiCard("Sociétés",SOCIETES.length,"🏢","green")}</div>
    <div class="card overflow-hidden"><table>
      <thead><tr><th>Personne</th><th>Type</th><th>Matricule</th><th>Société</th><th>Pièces</th><th>Complétude</th><th></th></tr></thead>
      <tbody>${people.map(p=>{const nb=Object.keys(p.documents||{}).length+(p.cvFile?1:0);const pct=Math.min(100,Math.round(nb/10*100));const link=p.type==="agent"?`#/agents/${p.id}`:`#/reserve/${p.id}`;return`<tr data-searchable><td><div class="flex items-center gap-2"><div class="avatar">${p.photo?`<img src="${p.photo}"/>`:escapeHTML(p.nom.slice(0,1))}</div>${escapeHTML(p.nom)}</div></td><td>${p.type==="agent"?'<span class="pill pill-green">Agent</span>':'<span class="pill pill-indigo">Candidat</span>'}</td><td class="font-mono">${safe(p.matricule)}</td><td class="text-xs">${safe(p.societe)}</td><td><div class="flex flex-wrap gap-1">${p.cvFile?'<span class="pill pill-blue">CV</span>':''}${Object.keys(p.documents||{}).map(k=>`<span class="pill pill-gray">${k.slice(0,4)}</span>`).join("")}</div></td><td><div class="h-2 bg-slate-100 rounded-full w-24"><div class="h-full bg-amber-500 rounded-full" style="width:${pct}%"></div></div><div class="text-xs text-slate-500 mt-1">${pct}%</div></td><td><a class="btn btn-ghost text-xs" href="${link}">Ouvrir →</a></td></tr>`}).join("")}</tbody>
    </table></div>`;
}

/* ---- PHOTO / DOC HELPERS ---- */
function compressImage(dataUrl,maxDim,quality){
  return new Promise((resolve)=>{
    if(typeof maxDim!=="number")maxDim=600;
    if(typeof quality!=="number")quality=0.7;
    try{
      const img=new Image();
      img.onload=()=>{
        let w=img.width,h=img.height;
        if(w>maxDim||h>maxDim){const r=Math.min(maxDim/w,maxDim/h);w=Math.round(w*r);h=Math.round(h*r)}
        const c=document.createElement("canvas");c.width=w;c.height=h;
        const ctx=c.getContext("2d");ctx.fillStyle="#ffffff";ctx.fillRect(0,0,w,h);ctx.drawImage(img,0,0,w,h);
        try{resolve(c.toDataURL("image/jpeg",quality))}catch(e){resolve(dataUrl)}
      };
      img.onerror=()=>resolve(dataUrl);
      img.src=dataUrl;
    }catch(e){resolve(dataUrl)}
  });
}
function handlePhotoUpload(inputId,targetHidden,previewId){
  const inp=document.getElementById(inputId);if(!inp||!inp.files[0])return;
  const f=inp.files[0];
  if(f.size>5*1024*1024){toast("Photo > 5 Mo · trop volumineuse","error");return}
  const afterPaint=()=>new Promise(resolve=>{
    const raf=window.requestAnimationFrame||((cb)=>setTimeout(cb,16));
    raf(()=>raf(resolve));
  });
  const setPreview=src=>{
    const html=`<img src="${src}" alt="" style="width:100%;height:100%;object-fit:cover;display:block;background:#fff"/>`;
    const prev=document.getElementById(previewId);
    if(prev){prev.classList.remove("field-error-box");prev.innerHTML=html;prev.dataset.hasPhoto="1"}
    document.querySelector(`[data-remove-photo="${targetHidden}"]`)?.classList.remove("hidden");
  };
  let instantUrl="";
  try{instantUrl=URL.createObjectURL(f);setPreview(instantUrl)}catch(e){}
  const r=new FileReader();
  r.onload=async e=>{
    const raw=e.target.result;
    const targetEl=document.getElementById(targetHidden);
    if(targetEl)targetEl.value=raw;
    if(!instantUrl)setPreview(raw);
    await afterPaint();
    const compressed=await compressImage(raw,1000,0.9);
    const finalSize=Math.round(compressed.length/1024);
    if(targetEl){targetEl.value=compressed;targetEl.dispatchEvent(new Event("change",{bubbles:true}))}
    setPreview(compressed);
    if(instantUrl)URL.revokeObjectURL(instantUrl);
    if(finalSize>500&&typeof toast==="function")toast("📷 Photo compressée à "+finalSize+" Ko","info");
  };
  r.onerror=()=>{if(instantUrl)URL.revokeObjectURL(instantUrl)};
  r.readAsDataURL(f);
}
function removePhoto(targetHidden,previewId){const h=document.getElementById(targetHidden);if(h){h.value="";h.dispatchEvent(new Event("change",{bubbles:true}))}const p=document.getElementById(previewId);if(p){p.innerHTML="👤";p.dataset.hasPhoto="0";p.classList.add("field-error-box")}}
function photoField(currentPhoto,hiddenName="photo"){const id=Math.random().toString(36).slice(2,8);return`<div class="candidate-photo-field flex items-start gap-4"><div id="photo-preview-${id}" class="candidate-photo-preview bg-white border border-slate-300 rounded-lg flex items-center justify-center text-5xl overflow-hidden" data-has-photo="${currentPhoto?"1":"0"}">${currentPhoto?`<img src="${currentPhoto}" alt="" style="width:100%;height:100%;object-fit:cover;display:block;background:#fff"/>`:"👤"}</div><div class="flex flex-col gap-2"><input type="hidden" id="photo-hidden-${id}" name="${hiddenName}" value="${currentPhoto||""}"/><input id="photo-input-${id}" type="file" accept="image/*" class="hidden" onchange="handlePhotoUpload('photo-input-${id}','photo-hidden-${id}','photo-preview-${id}')"/><button type="button" class="btn btn-secondary text-xs" onclick="document.getElementById('photo-input-${id}').click()">📷 ${currentPhoto?"Changer":"Ajouter"}</button><button type="button" class="btn btn-ghost text-xs ${currentPhoto?"":"hidden"}" data-remove-photo="photo-hidden-${id}" onclick="removePhoto('photo-hidden-${id}','photo-preview-${id}')">✕ Retirer</button><div class="text-[10px] text-slate-500">Photo nette sur fond blanc · JPG/PNG</div></div></div>`}
function handleDocUpload(key,inputId,holderId){const inp=document.getElementById(inputId);if(!inp||!inp.files[0])return;const f=inp.files[0];if(f.size>5*1024*1024){toast("Fichier > 5 Mo","error");return}const r=new FileReader();r.onload=e=>{const urlI=document.querySelector(`[name="doc_${key}_url"]`);const nmI=document.querySelector(`[name="doc_${key}_name"]`);const vc=document.querySelector(`[name="verif${key}"]`);if(urlI)urlI.value=e.target.result;if(nmI)nmI.value=f.name;if(vc){vc.checked=true;vc.dispatchEvent(new Event("change",{bubbles:true}))}document.getElementById(holderId).innerHTML=`<div class="text-xs text-emerald-600">✅ ${escapeHTML(f.name)}</div><button type="button" class="btn btn-ghost text-xs mt-1" onclick="viewDoc('${e.target.result}','${escapeHTML(f.name)}')">👁 Voir</button><button type="button" class="btn btn-ghost text-xs mt-1 text-red-600" onclick="removeDoc('${key}','${holderId}')">✕ Retirer</button>`;toast(`Pièce "${key}" téléversée`,"success")};r.readAsDataURL(f)}
function removeDoc(key,holderId){const urlI=document.querySelector(`[name="doc_${key}_url"]`);const nmI=document.querySelector(`[name="doc_${key}_name"]`);if(urlI)urlI.value="";if(nmI)nmI.value="";const id=Math.random().toString(36).slice(2,8);document.getElementById(holderId).innerHTML=`<input id="docinp-${id}" type="file" accept="image/*,.pdf" class="hidden" onchange="handleDocUpload('${key}','docinp-${id}','${holderId}')"/><button type="button" class="btn btn-secondary text-xs" onclick="document.getElementById('docinp-${id}').click()">📤 Téléverser</button>`}
function viewDoc(url,name){openModal(`<div class="p-2"><div class="flex justify-between items-center mb-3"><h3 class="font-bold">${escapeHTML(name)}</h3><button class="btn btn-ghost" onclick="closeModal()">✕</button></div>${url.startsWith("data:image")?`<img src="${url}" class="w-full rounded-lg"/>`:`<iframe src="${url}" class="w-full rounded-lg" style="height:70vh"></iframe>`}<a href="${url}" download="${escapeHTML(name)}" class="btn btn-primary mt-3">⬇ Télécharger</a></div>`)}
function viewAgentArchivedDoc(agentId,key,label){
  const a=db.agents.find(x=>x.id===agentId);
  const d=a&&a.documents&&a.documents[key];
  if(!d||!d.url){toast(`Aucun document archivé : ${label}`,"error");return}
  viewDoc(d.url,d.name||label);
}
function docUploadField(key,label,eu,en){const id=Math.random().toString(36).slice(2,8);const h=`doch-${id}`;const inner=eu?`<div class="text-xs text-emerald-600">✅ ${escapeHTML(en||"fichier")}</div><button type="button" class="btn btn-ghost text-xs mt-1" onclick="viewDoc('${eu}','${escapeHTML(en||"fichier")}')">👁 Voir</button><button type="button" class="btn btn-ghost text-xs mt-1 text-red-600" onclick="removeDoc('${key}','${h}')">✕ Retirer</button>`:`<input id="docinp-${id}" type="file" accept="image/*,.pdf" class="hidden" onchange="handleDocUpload('${key}','docinp-${id}','${h}')"/><button type="button" class="btn btn-secondary text-xs" onclick="document.getElementById('docinp-${id}').click()">📤 Téléverser</button>`;return`<input type="hidden" name="doc_${key}_url" value="${eu||""}"/><input type="hidden" name="doc_${key}_name" value="${en||""}"/><div id="${h}">${inner}</div>`}
function handleCvUpload(inputId){const inp=document.getElementById(inputId);if(!inp||!inp.files[0])return;const f=inp.files[0];if(f.size>5*1024*1024){toast("CV > 5 Mo","error");return}const r=new FileReader();r.onload=e=>{document.querySelector('[name="cv_url"]').value=e.target.result;document.querySelector('[name="cv_name"]').value=f.name;document.getElementById("cv-holder").innerHTML=`<div class="text-xs text-emerald-600">✅ ${escapeHTML(f.name)}</div><div class="flex gap-2 mt-1"><button type="button" class="btn btn-ghost text-xs" onclick="viewDoc('${e.target.result}','${escapeHTML(f.name)}')">👁 Voir</button><button type="button" class="btn btn-ghost text-xs text-red-600" onclick="removeCv()">✕ Retirer</button></div>`};r.readAsDataURL(f)}
function removeCv(){document.querySelector('[name="cv_url"]').value="";document.querySelector('[name="cv_name"]').value="";const id=Math.random().toString(36).slice(2,8);document.getElementById("cv-holder").innerHTML=`<input id="cv-input-${id}" type="file" accept=".pdf,.doc,.docx,image/*" class="hidden" onchange="handleCvUpload('cv-input-${id}')"/><button type="button" class="btn btn-secondary text-xs" onclick="document.getElementById('cv-input-${id}').click()">📤 Téléverser le CV</button>`}

/* ---- RECRUTEMENT ---- */
function archivedCandidateDate(c){return String(c.archivedAt||c.updatedAt||c.createdAt||"").slice(0,10)}
function candidatIsArchived(c){
  const st=normalizeSocieteName(c&&c.statut);
  return st==="ARCHIVE"||st==="ARCHIVED"||st==="ARCHIVÉ"||st==="ARCHIVEE"||st==="ARCHIVÉE"||!!(c&&(c.archivedAt||c.motifArchive||c.commentaireArchive));
}
function candidatArchiveSourceLabel(c){return c&&c.archiveSource==="reserve"?"Candidat en réserve":"Candidat"}
function archiveCandidateFilters(){
  try{return JSON.parse(sessionStorage.getItem("archiveCandidateFilters")||"{}")}catch(e){return{}}
}
function setArchiveCandidateFilter(key,value){
  const f=archiveCandidateFilters();
  f[key]=value||"";
  sessionStorage.setItem("archiveCandidateFilters",JSON.stringify(f));
  renderView();
}
function resetArchiveCandidateFilters(){
  sessionStorage.removeItem("archiveCandidateFilters");
  renderView();
}
function renderRecrutementDashboard(view){
  cleanupDuplicateCandidates(true);
  const socFilter=(isDrhModuleContext()?drhActiveSocieteFilter():currentStructureSocieteFilter())||mySoc()||sessionStorage.getItem("dashSociete")||"";
  const allowed=(isDrhModuleContext()&&!socFilter)?drhAuthorizedSocieties():[];
  let all=(db.candidats||[]).slice();
  if(socFilter)all=all.filter(c=>c.societe===socFilter);else if(allowed.length)all=all.filter(c=>allowed.includes(c.societe));
  const archives=all.filter(candidatIsArchived);
  const reserves=all.filter(c=>candidatIsReserve(c));
  const nouvelles=all.filter(c=>!candidatIsArchived(c)&&!candidatIsReserve(c));
  const favorables=reserves.filter(c=>c.avisDecision==="Favorable").length;
  const sansAvis=reserves.filter(c=>!c.avisDecision).length;
  const bySoc={};all.forEach(c=>{const k=c.societe||"Non renseignée";bySoc[k]=(bySoc[k]||0)+1});
  const byPoste={};reserves.forEach(c=>{const k=c.posteSouhaite||"Non renseigné";byPoste[k]=(byPoste[k]||0)+1});
  const topSoc=Object.entries(bySoc).sort((a,b)=>b[1]-a[1]).slice(0,4);
  const topPostes=Object.entries(byPoste).sort((a,b)=>b[1]-a[1]).slice(0,5);
  const reserveRows=reserves.slice().sort((a,b)=>String(b.createdAt||"").localeCompare(String(a.createdAt||"")));
  const scope=socFilter?escapeHTML(socFilter):(allowed.length?"Sociétés autorisées":"Toutes sociétés");
  const card=(title,count,sub,route,color,icon)=>`<button type="button" class="card p-5 text-left kpi-clickable" onclick="navigate('${route}')" style="border-left:5px solid ${color};min-height:132px;background:#fff"><div class="flex items-start justify-between gap-3"><div><div class="text-xs uppercase font-black text-slate-500">${escapeHTML(title)}</div><div class="text-4xl font-black mt-2" style="color:${color}">${count}</div><div class="text-xs text-slate-400 mt-2">${escapeHTML(sub||"Cliquer pour ouvrir")}</div></div></div></button>`;
  const bar=(label,n,total,color)=>{const pct=total?Math.round(n/total*100):0;return`<button type="button" class="dash-mini-row text-left w-full" onclick="navigate('reserve')" data-searchable><div style="min-width:190px"><div class="font-bold text-sm">${escapeHTML(label)}</div><div class="text-[11px] text-slate-500">${n} candidat(s)</div></div><div class="flex-1"><div class="dash-bar"><span style="width:${pct}%;background:${color}"></span></div></div><div class="font-black text-sm">${pct}%</div></button>`};
  view.innerHTML=`<div class="mb-5 flex items-start justify-between gap-3 flex-wrap"><div><h1 class="text-2xl font-black uppercase">CANDIDAT</h1><p class="text-sm text-slate-500">Statistiques et accès rapides · ${scope}</p></div><button class="btn btn-primary recrutement-add-btn" onclick="navigate('reserve/nouveau')">Ajouter candidat</button></div>
    <div class="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4 mb-5">
      ${card("Ajouter candidats",reserves.length,"Candidats en réserve","reserve","#043970","👥")}
      ${card("Candidats archivés",archives.length,"Dossiers archivés","candidats_archives","#64748b","🗄")}
      ${card("Nouvelles fiches",nouvelles.length,"Fiches non finalisées","reserve","#f59e0b","📝")}
      ${card("Avis favorables",favorables,`${sansAvis} sans avis`,"reserve","#16a34a","✅")}
    </div>
    <div class="grid grid-cols-1 xl:grid-cols-2 gap-4">
      <div class="card p-4"><div class="flex items-center justify-between mb-3"><h3 class="font-black">Répartition par société</h3><span class="pill pill-blue">${all.length}</span></div><div class="dash-mini-list">${topSoc.length?topSoc.map(([k,n])=>bar(k,n,all.length,"#043970")).join(""):`<div class="p-8 text-center text-slate-500">Aucune donnée recrutement.</div>`}</div></div>
      <div class="card p-4"><div class="flex items-center justify-between mb-3"><h3 class="font-black">Postes demandés en réserve</h3><span class="pill pill-amber">${reserves.length}</span></div><div class="dash-mini-list">${topPostes.length?topPostes.map(([k,n])=>bar(k,n,reserves.length,"#f59e0b")).join(""):`<div class="p-8 text-center text-slate-500">Aucun candidat en réserve.</div>`}</div></div>
    </div>
    <div class="card overflow-hidden mt-4">
      <div class="flex items-center justify-between gap-3 p-4 border-b border-slate-100 flex-wrap">
        <div><h3 class="font-black">Liste des candidats en réserve</h3><div class="text-xs text-slate-500">${reserveRows.length} candidat(s) affiché(s) · ${scope}</div></div>
        <button type="button" class="btn candidate-reserve-page-btn text-xs" onclick="navigate('reserve')">Voir la page réserve</button>
      </div>
      ${reserveRows.length?`<div class="overflow-x-auto"><table><thead><tr><th>Candidat</th><th>Poste</th><th>Société</th><th>Téléphone</th><th>Avis</th><th>Date</th><th>Statut</th><th></th></tr></thead><tbody>${reserveRows.map(c=>candidateListRowHTML(c,"reserve")).join("")}</tbody></table></div>`:`<div class="p-10 text-center text-slate-500">Aucun candidat en réserve.</div>`}
    </div>`;
}
function recrutementModeToApi(mode){return mode==="archive"?"archive":mode==="reserve"?"reserve":"new"}
function recrutementPageStorageKey(mode){return "recrutementPage:"+recrutementModeToApi(mode)+":"+((isDrhModuleContext()?drhActiveSocieteFilter():currentStructureSocieteFilter())||mySoc()||sessionStorage.getItem("dashSociete")||"")}
function recrutementCurrentPage(mode){return Math.max(parseInt(sessionStorage.getItem(recrutementPageStorageKey(mode))||"1",10)||1,1)}
function setRecrutementPage(mode,page){sessionStorage.setItem(recrutementPageStorageKey(mode),String(Math.max(parseInt(page||1,10)||1,1)));renderView()}
function upsertServerCandidate(row){
  const c=candidateFromApi(row);
  if(!db)db={};
  if(!Array.isArray(db.candidats))db.candidats=[];
  const existing=db.candidats.find(x=>String(x.backendId||"")===String(c.backendId)||String(x.id||"")===String(c.id));
  if(existing)Object.assign(existing,c);else db.candidats.push(c);
  stashCandidatForRoute(existing||c,[c.id,c.backendId]);
  return existing||c;
}
function candidateListRowHTML(c,mode){
  const route=mode==="archive"?"candidats_archives":mode==="reserve"?"reserve":"recrutement";
  const archived=mode==="archive";
  const rowClick=mode==="reserve"?` onclick="navigate('reserve/${jsString(c.id)}')" class="cursor-pointer hover:bg-slate-50"`:"";
  return `<tr data-searchable data-candidate-id="${escapeHTML(c.id)}" data-backend-id="${escapeHTML(c.backendId||"")}"${rowClick}>
    <td><div class="flex items-center gap-2"><div class="avatar">${c.photo?`<img src="${c.photo}"/>`:escapeHTML((c.prenom||"?").slice(0,1))}</div><div><div class="font-semibold">${escapeHTML((c.nom||"")+" "+(c.prenom||""))}</div><div class="text-xs text-slate-500">${escapeHTML(c.email||"")}</div></div></div></td>
    <td>${safe(c.posteSouhaite)}</td>
    <td><span class="pill pill-indigo">${safe(c.societe)}</span></td>
    ${archived?`<td><span class="pill pill-blue">${escapeHTML(candidatArchiveSourceLabel(c))}</span></td><td><span class="pill pill-gray">${safe(c.wilaya||"—")}</span></td>`:""}
    <td>${safe(c.telephone)}</td>
    <td>${c.avisDecision?`<span class="pill ${c.avisDecision==="Favorable"?"pill-green":c.avisDecision==="Défavorable"?"pill-red":"pill-amber"}">${escapeHTML(c.avisDecision)}</span>`:"—"}</td>
    <td class="text-xs">${archived?`${formatDate(c.archivedAt||c.updatedAt||c.createdAt)}<div class="text-[11px] text-slate-500">${escapeHTML(c.motifArchive||"—")}</div>`:formatDate(c.createdAt)}</td>
    <td>${archived?'<span class="pill pill-gray">Archivé</span>':candidatIsReserve(c)?'<span class="pill pill-amber">Réserve</span>':'<span class="pill pill-blue">Nouvelle</span>'}</td>
    <td class="text-right">${mode==="reserve"?`<button type="button" class="btn btn-ghost text-lg leading-none px-3" title="Actions" onclick="event.stopPropagation();openReserveCandidateActions('${jsString(c.id)}')">⋯</button>`:`<a class="btn btn-ghost text-xs" href="#/${route}/${escapeHTML(c.id)}">Ouvrir →</a>`}</td>
  </tr>`;
}
async function renderRecrutementServer(view,mode){
  const title=mode==="archive"?"Candidats archivés":mode==="reserve"?"Candidats en réserve":"Nouvelles candidatures";
  const st=mode==="archive"?"Dossiers archivés depuis les nouvelles candidatures et les candidats en réserve.":mode==="reserve"?"Candidats validés, en attente de recrutement.":"Candidats à présélectionner pour la fiche de renseignement.";
  const socFilter=(isDrhModuleContext()?drhActiveSocieteFilter():currentStructureSocieteFilter())||mySoc()||sessionStorage.getItem("dashSociete")||"";
  const page=recrutementCurrentPage(mode);
  const pageSize=25;
  const addButton=mode==="reserve"?`<button class="btn btn-primary recrutement-add-btn" onclick="navigate('reserve/nouveau')">Ajouter candidat</button>`:"";
  view.innerHTML=`<div class="flex items-center justify-between mb-6"><div><h1 class="text-2xl font-bold">${title}</h1><p class="text-slate-500 text-sm">${st}</p></div>${addButton}</div><div class="card p-8 text-center text-slate-500">Chargement PostgreSQL...</div>`;
  try{
    const result=await SGDI.rh.candidatesPage({mode:recrutementModeToApi(mode),society:socFilter,page,page_size:pageSize});
    const cs=(result.items||[]).map(upsertServerCandidate);
    const pages=result.pages||1;
    const pagination=`<div class="flex items-center justify-between gap-2 p-3 border-t border-slate-100 text-sm"><div class="text-slate-500">${result.total||0} candidat(s) · page ${result.page||1}/${pages}</div><div class="flex gap-2"><button class="btn btn-ghost text-xs" ${result.page<=1?"disabled":""} onclick="setRecrutementPage('${mode}',${(result.page||1)-1})">Précédent</button><button class="btn btn-ghost text-xs" ${result.page>=pages?"disabled":""} onclick="setRecrutementPage('${mode}',${(result.page||1)+1})">Suivant</button></div></div>`;
    view.innerHTML=`<div class="flex items-center justify-between mb-6"><div><h1 class="text-2xl font-bold">${title}</h1><p class="text-slate-500 text-sm">${st} · source PostgreSQL</p></div>${addButton}</div>
      <div class="grid grid-3 mb-4"><div class="card p-4"><div class="text-xs text-slate-500 uppercase">Total serveur</div><div class="text-3xl font-bold mt-1">${result.total||0}</div></div><div class="card p-4"><div class="text-xs text-slate-500 uppercase">Page affichée</div><div class="text-3xl font-bold mt-1">${cs.length}</div></div><div class="card p-4"><div class="text-xs text-slate-500 uppercase">Société</div><div class="text-sm font-bold mt-2">${escapeHTML(socFilter||"Toutes autorisées")}</div></div></div>
      ${cs.length===0?`<div class="card p-10 text-center text-slate-500">Aucun candidat.</div>`:`<div class="card overflow-hidden"><table><thead><tr><th>Candidat</th><th>Poste</th><th>Société</th>${mode==="archive"?"<th>Origine</th><th>Wilaya</th>":""}<th>Téléphone</th><th>Avis</th><th>${mode==="archive"?"Archivage":"Date"}</th><th>Statut</th><th></th></tr></thead><tbody>${cs.map(c=>candidateListRowHTML(c,mode)).join("")}</tbody></table>${pagination}</div>`}`;
    setTimeout(()=>applyLanguagePreference(view),0);
  }catch(e){
    console.warn("Liste candidats PostgreSQL indisponible",e);
    window.__sgdiLocalRecrutementFallback=true;
    try{renderRecrutement(view,mode)}finally{window.__sgdiLocalRecrutementFallback=false}
    toast("Lecture PostgreSQL candidats refusée : "+(e.message||e),"error");
  }
}
function renderRecrutement(view,mode){
  if(sgdiAuthToken()&&!window.__sgdiLocalRecrutementFallback){renderRecrutementServer(view,mode);return}
  cleanupDuplicateCandidates(true);
  const title=mode==="archive"?"Candidats archivés":mode==="reserve"?"Candidats en réserve":"Nouvelles candidatures";
  const socFilter=(isDrhModuleContext()?drhActiveSocieteFilter():currentStructureSocieteFilter())||mySoc()||sessionStorage.getItem("dashSociete")||"";
  const allowed=(isDrhModuleContext()&&!socFilter)?drhAuthorizedSocieties():[];
  let cs=db.candidats.filter(c=>mode==="archive"?candidatIsArchived(c):!candidatIsArchived(c)).filter(c=>mode==="archive"?true:mode==="reserve"?candidatIsReserve(c):!candidatIsReserve(c));
  if(socFilter)cs=cs.filter(c=>c.societe===socFilter);else if(allowed.length)cs=cs.filter(c=>allowed.includes(c.societe));
  const st=mode==="archive"?"Dossiers archivés depuis les nouvelles candidatures et les candidats en réserve.":mode==="reserve"?"Candidats validés, en attente de recrutement.":"Candidats à présélectionner pour la fiche de renseignement.";
  let statsHTML="";
  let archiveToolsHTML="";
  let archiveEmptyHTML="";
  if(mode==="archive"){
    const allArchived=cs.slice();
    const f=archiveCandidateFilters();
    const postes=[...new Set(allArchived.map(c=>c.posteSouhaite||"—"))].sort((a,b)=>a.localeCompare(b));
    const wilayas=[...new Set(allArchived.map(c=>c.wilaya||"—"))].sort((a,b)=>a.localeCompare(b));
    if(f.poste)cs=cs.filter(c=>(c.posteSouhaite||"—")===f.poste);
    if(f.wilaya)cs=cs.filter(c=>(c.wilaya||"—")===f.wilaya);
    if(f.dateFrom)cs=cs.filter(c=>archivedCandidateDate(c)>=f.dateFrom);
    if(f.dateTo)cs=cs.filter(c=>archivedCandidateDate(c)<=f.dateTo);
    cs.sort((a,b)=>{
      const da=archivedCandidateDate(a),dbb=archivedCandidateDate(b);
      return f.sortDate==="asc"?da.localeCompare(dbb):dbb.localeCompare(da);
    });
    const byPoste={};allArchived.forEach(c=>{const k=c.posteSouhaite||"—";byPoste[k]=(byPoste[k]||0)+1});
    const byWilaya={};allArchived.forEach(c=>{const k=c.wilaya||"—";byWilaya[k]=(byWilaya[k]||0)+1});
    archiveToolsHTML=`<div class="card p-4 mb-4">
      <div class="grid grid-6 gap-3 items-end">
        <div class="col-span-2"><label class="label">Métier</label><select class="select" onchange="setArchiveCandidateFilter('poste',this.value)"><option value="">Tous les métiers</option>${postes.map(p=>`<option value="${escapeHTML(p)}" ${f.poste===p?"selected":""}>${escapeHTML(p)} (${byPoste[p]||0})</option>`).join("")}</select></div>
        <div class="col-span-2"><label class="label">Adresse / Wilaya</label><select class="select" onchange="setArchiveCandidateFilter('wilaya',this.value)"><option value="">Toutes les wilayas</option>${wilayas.map(w=>`<option value="${escapeHTML(w)}" ${f.wilaya===w?"selected":""}>${escapeHTML(w)} (${byWilaya[w]||0})</option>`).join("")}</select></div>
        <div><label class="label">Du</label><input class="input" type="date" value="${escapeHTML(f.dateFrom||"")}" onchange="setArchiveCandidateFilter('dateFrom',this.value)"/></div>
        <div><label class="label">Au</label><input class="input" type="date" value="${escapeHTML(f.dateTo||"")}" onchange="setArchiveCandidateFilter('dateTo',this.value)"/></div>
        <div class="col-span-2"><label class="label">Classement par date</label><select class="select" onchange="setArchiveCandidateFilter('sortDate',this.value)"><option value="desc" ${f.sortDate!=="asc"?"selected":""}>Plus récent d'abord</option><option value="asc" ${f.sortDate==="asc"?"selected":""}>Plus ancien d'abord</option></select></div>
        <div class="col-span-4 flex items-center justify-between gap-3">
          <div class="text-sm text-slate-500"><b>${cs.length}</b> candidat(s) affiché(s) sur ${allArchived.length} archivé(s).</div>
          <button type="button" class="btn btn-ghost text-xs" onclick="resetArchiveCandidateFilters()">Réinitialiser</button>
        </div>
      </div>
    </div>`;
    if(!cs.length&&allArchived.length){
      archiveEmptyHTML=`<div class="card p-10 text-center text-slate-500">Aucun candidat ne correspond aux filtres sélectionnés.<div class="mt-3"><button type="button" class="btn btn-secondary text-xs" onclick="resetArchiveCandidateFilters()">Voir tous les candidats archivés</button></div></div>`;
    }
  }
  if(mode==="reserve"&&cs.length>0){
    const reserveSociete=currentStructureSocieteFilter()||mySoc()||sessionStorage.getItem("dashSociete")||"";
    const reserveStats=reserveSociete?cs.filter(c=>c.societe===reserveSociete):cs;
    const t=today();
    const byPoste={};reserveStats.forEach(c=>{const p=c.posteSouhaite||"—";byPoste[p]=(byPoste[p]||0)+1});
    const topPostes=Object.entries(byPoste).sort((a,b)=>b[1]-a[1]).slice(0,3);
    const favorables=reserveStats.filter(c=>c.avisDecision==="Favorable").length;
    const reserves=reserveStats.filter(c=>c.avisDecision==="Favorable avec réserves").length;
    const defavorables=reserveStats.filter(c=>c.avisDecision==="Défavorable").length;
    const sansAvis=reserveStats.filter(c=>!c.avisDecision).length;
    const ages=reserveStats.map(c=>c.dateNaissance?Math.floor(daysBetween(c.dateNaissance,t)/365.25):null).filter(x=>x!==null);
    const ageMoy=ages.length?Math.round(ages.reduce((s,x)=>s+x,0)/ages.length):0;
    const attentes=reserveStats.map(c=>daysBetween(c.createdAt||t,t)).filter(x=>x>=0);
    const attenteMoy=attentes.length?Math.round(attentes.reduce((s,x)=>s+x,0)/attentes.length):0;
    const attenteMax=attentes.length?Math.max(...attentes):0;
    const salaires=reserveStats.map(c=>parseFloat(c.salairePrevu)||0).filter(x=>x>0);
    const salaireMoy=salaires.length?Math.round(salaires.reduce((s,x)=>s+x,0)/salaires.length):0;
    const habiletes=reserveStats.filter(c=>c.habilitations?.serviceNational==="oui").length;
    const exServices=reserveStats.filter(c=>c.exServices==="Oui").length;
    statsHTML=`<div class="grid grid-4 mb-4">
      <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Total réserve</div><div class="text-3xl font-bold mt-1">${reserveStats.length}</div><div class="text-xs text-slate-400 mt-1">${reserveSociete?escapeHTML(reserveSociete):"Toutes sociétés"}</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Avis favorable</div><div class="text-3xl font-bold mt-1 text-emerald-600">${favorables}</div><div class="text-xs text-slate-400 mt-1">${reserves} avec réserves • ${defavorables} défav. • ${sansAvis} sans avis</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Attente moyenne</div><div class="text-3xl font-bold mt-1">${attenteMoy} j</div><div class="text-xs text-slate-400 mt-1">max : ${attenteMax} j</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Salaire prévu moyen</div><div class="text-3xl font-bold mt-1">${salaireMoy?money(salaireMoy):"—"}</div><div class="text-xs text-slate-400 mt-1">âge moyen : ${ageMoy||"—"} ans</div></div>
    </div>
    <div class="grid grid-1 gap-4 mb-6">
      <div class="card p-4"><h3 class="text-sm font-semibold mb-3">Top postes souhaités ${reserveSociete?`— ${escapeHTML(reserveSociete)}`:""}</h3>${topPostes.length===0?`<div class="text-xs text-slate-500 italic">Aucun candidat pour la société active.</div>`:topPostes.map(([p,n])=>{const pct=reserveStats.length?Math.round(n/reserveStats.length*100):0;return`<div class="text-sm mb-2"><div class="flex justify-between mb-1"><span>${escapeHTML(p)}</span><span class="text-slate-500">${n} (${pct}%)</span></div><div class="h-2 bg-slate-100 rounded-full"><div class="h-full bg-amber-500 rounded-full" style="width:${pct}%"></div></div></div>`}).join("")}<div class="grid grid-2 mt-4 pt-3 border-t border-slate-200 text-xs"><div><span class="text-slate-500">Service national :</span> <b>${habiletes}</b> / ${reserveStats.length}</div><div><span class="text-slate-500">Ex-services :</span> <b>${exServices}</b> / ${reserveStats.length}</div></div></div>
    </div>`;
  }
  const addButton=mode==="reserve"?`<button class="btn btn-primary recrutement-add-btn" onclick="navigate('reserve/nouveau')">Ajouter candidat</button>`:"";
  view.innerHTML=`<div class="flex items-center justify-between mb-6"><div><h1 class="text-2xl font-bold">${title}</h1><p class="text-slate-500 text-sm">${st}</p></div>${addButton}</div>
    ${statsHTML}
    ${archiveToolsHTML}
    ${cs.length===0?(archiveEmptyHTML||`<div class="card p-10 text-center text-slate-500">Aucun candidat.</div>`):`<div class="card overflow-hidden"><table>
      <thead><tr><th>Candidat</th><th>Poste</th><th>Société</th>${mode==="archive"?"<th>Origine</th><th>Wilaya</th>":""}<th>Téléphone</th><th>Avis</th><th>${mode==="archive"?"Archivage":"Date"}</th><th>Statut</th><th></th></tr></thead>
      <tbody>${cs.map(c=>`<tr data-searchable>
        <td><div class="flex items-center gap-2"><div class="avatar">${c.photo?`<img src="${c.photo}"/>`:escapeHTML((c.prenom||"?").slice(0,1))}</div><div><div class="font-semibold">${escapeHTML(c.nom+" "+c.prenom)}</div><div class="text-xs text-slate-500">${escapeHTML(c.email||"")}</div></div></div></td>
        <td>${safe(c.posteSouhaite)}</td>
        <td><span class="pill pill-indigo">${safe(c.societe)}</span></td>
        ${mode==="archive"?`<td><span class="pill pill-blue">${escapeHTML(candidatArchiveSourceLabel(c))}</span></td>`:""}
        ${mode==="archive"?`<td><span class="pill pill-gray">${safe(c.wilaya||"—")}</span></td>`:""}
        <td>${safe(c.telephone)}</td>
        <td>${c.avisDecision?`<span class="pill ${c.avisDecision==="Favorable"?"pill-green":c.avisDecision==="Défavorable"?"pill-red":"pill-amber"}">${c.avisDecision}</span>`:"—"}</td>
        <td class="text-xs">${mode==="archive"?`${formatDate(c.archivedAt||c.updatedAt||c.createdAt)}<div class="text-[11px] text-slate-500">${escapeHTML(c.motifArchive||"—")}</div>`:formatDate(c.createdAt)}</td>
        <td>${mode==="archive"?'<span class="pill pill-gray">Archivé</span>':candidatIsReserve(c)?'<span class="pill pill-amber">Réserve</span>':'<span class="pill pill-blue">Nouvelle</span>'}</td>
        <td class="text-right">${mode==="reserve"?`<button type="button" class="btn btn-ghost text-lg leading-none px-3" title="Actions" onclick="openReserveCandidateActions('${jsString(c.id)}')">⋯</button>`:`<a class="btn btn-ghost text-xs" href="#/${mode==="archive"?"candidats_archives":mode==="reserve"?"reserve":"recrutement"}/${c.id}">Ouvrir →</a>`}</td>
      </tr>`).join("")}</tbody></table></div>`}`;
}
async function recruterCandidat(id){
  const c=findCandidatById(id);if(!c)return;
  const draft={...c,statut:"a_contractualiser"};
  try{
    await persistCandidateToPostgres(draft);
    Object.assign(c,draft);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
    toast("Candidat envoyé vers contractualisation","success");
    navigate(`contrats/nouveau/${c.id}`);
  }catch(e){
    toast("Action refusée par PostgreSQL : "+(e.message||e),"error");
  }
}
function afficherCandidatReserve(id){closeModal();navigate(`reserve/${id}`)}
function modifierCandidatReserve(id){sessionStorage.setItem("candidatAutoEdit:"+id,"1");closeModal();navigate(`reserve/${id}`)}
function openReserveCandidateActions(id){
  const c=findCandidatById(id);if(!c){toast("Candidat introuvable","error");return}
  const name=String((c.nom||"")+" "+(c.prenom||"")).trim()||"Candidat";
  openModal(`<h3 class="font-bold text-lg mb-1">Actions candidat</h3><p class="text-sm text-slate-500 mb-4">${escapeHTML(name)} · ${escapeHTML(c.societe||"—")}</p>
    <div class="grid grid-cols-1 gap-2">
      <button type="button" class="btn btn-secondary justify-start" onclick="afficherCandidatReserve('${jsString(id)}')">👁 Afficher</button>
      <button type="button" class="btn btn-primary justify-start" onclick="modifierCandidatReserve('${jsString(id)}')">✎ Modifier</button>
      <button type="button" class="btn btn-ghost justify-start text-red-600" onclick="closeModal();openArchiveCandidatModal('${jsString(id)}')">🗄 Archiver</button>
      <button type="button" class="btn btn-danger justify-start" onclick="closeModal();deleteCandidat('${jsString(id)}')">🗑 Supprimer</button>
    </div>
    <div class="flex justify-end mt-4"><button type="button" class="btn btn-ghost" onclick="closeModal()">Fermer</button></div>`);
}

/* ---- CANDIDAT FORM ---- */
const CANDIDAT_SECTIONS=[
  {key:"identification",label:"Identification du candidat"},
  {key:"mensurations",label:"Mensurations"},
  {key:"militaire",label:"Service militaire"},
  {key:"poste",label:"Poste & CV"},
  {key:"avis",label:"Avis du recruteur"},
  {key:"contact",label:"Coordonnées & contact d'urgence"},
  {key:"habilitations",label:"Habilitations"},
  {key:"experience",label:"Expérience professionnelle"}
];
const CANDIDAT_ARCHIVE_MOTIFS=[
  "Dossier incomplet",
  "Profil non conforme",
  "Âge non conforme",
  "Poste non disponible",
  "Candidat non joignable",
  "Désistement du candidat",
  "Avis défavorable",
  "Doublon",
  "Autre"
];
const CANDIDAT_ETAPE1_KEYS=["identification","mensurations","militaire","poste","avis"];
const candidatValidationLocks=new Set();
const candidatTempRealIds={};
function candidatAliasStorageKey(){return "candidatIdAliases"}
function loadCandidatAliases(){try{return JSON.parse(sessionStorage.getItem(candidatAliasStorageKey())||"{}")}catch(e){return {}}}
function saveCandidatAliases(aliases){try{sessionStorage.setItem(candidatAliasStorageKey(),JSON.stringify(aliases||{}))}catch(e){}}
function rememberCandidatAlias(from,to){
  from=String(from||"").trim();to=String(to||"").trim();
  if(!from||!to||from===to)return;
  const aliases=loadCandidatAliases();aliases[from]=to;saveCandidatAliases(aliases);
}
function resolveCandidatAlias(id){
  let cur=String(id||"").trim();if(!cur)return "";
  const aliases=loadCandidatAliases();const seen=new Set();
  while(aliases[cur]&&!seen.has(cur)){seen.add(cur);cur=String(aliases[cur]);}
  return cur;
}
function candidatValidationLockKey(id,key){return String(id||"")+":"+String(key||"")}
function setCandidatSectionButtonsDisabled(id,key,disabled){
  document.querySelectorAll('[data-section-action="1"]').forEach(b=>{
    const call=String(b.getAttribute("onclick")||"");
    if(call.includes("validateCandidatSectionAction")&&call.includes("'"+String(id)+"'")&&call.includes("'"+String(key)+"'")){
      b.disabled=!!disabled;
    }
  });
}
function candidateDedupeKey(c){
  if(!candidateHasMinimumData(c))return"";
  const norm=v=>String(v||"").trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g," ");
  const society=norm(c.societe||c.society);
  const nin=norm(c.nin);
  const birth=norm(c.dateNaissance||c.birth_date);
  const phone=norm(c.telephone||c.phone);
  const name=norm(c.nom||c.last_name)+"|"+norm(c.prenom||c.first_name);
  if(nin&&nin.length>=6)return "nin|"+society+"|"+nin;
  if(birth&&phone)return "birth-phone|"+society+"|"+name+"|"+birth+"|"+phone;
  if(birth&&norm(c.lieuNaissance)&&norm(c.nomPere))return "identity|"+society+"|"+name+"|"+birth+"|"+norm(c.lieuNaissance)+"|"+norm(c.nomPere);
  return "";
}
function candidateCompletenessScore(c){return ["nin","telephone","phone","dateNaissance","posteSouhaite","desired_position","avisDecision","avisCommentaire","source"].reduce((n,k)=>n+(String(c&&c[k]||"").trim()?1:0),0)+(c&&c.backendId?2:0)}
function stashCandidatForRoute(c,aliases){
  if(!c)return;
  const keys=new Set();
  if(c.id)keys.add(String(c.id));
  if(c.backendId)keys.add(String(c.backendId));
  (aliases||[]).forEach(k=>{if(k)keys.add(String(k))});
  keys.forEach(k=>{try{sessionStorage.setItem("pendingCandidat:"+k,JSON.stringify(c))}catch(e){}});
}
function restorePendingCandidat(id){
  const raw=String(id||"");
  if(!raw)return null;
  let item=null;
  const alias=resolveCandidatAlias(raw);
  try{item=JSON.parse(sessionStorage.getItem("pendingCandidat:"+raw)||"null")}catch(e){item=null}
  if(!item&&alias&&alias!==raw){try{item=JSON.parse(sessionStorage.getItem("pendingCandidat:"+alias)||"null")}catch(e){item=null}}
  if(!item&&isTempCandidateId(raw)&&candidatTempRealIds[raw]){
    try{item=JSON.parse(sessionStorage.getItem("pendingCandidat:"+String(candidatTempRealIds[raw]))||"null")}catch(e){item=null}
  }
  if(!item||!candidateHasMinimumData(item))return null;
  if(!db.candidats)db.candidats=[];
  const existing=db.candidats.find(c=>String(c.id)===String(item.id)||String(c.backendId||"")===String(item.backendId||""));
  if(existing){Object.assign(existing,item);return existing}
  db.candidats.push(item);
  return item;
}
function findCandidatById(id){
  const raw=String(id||"").trim();
  if(!raw)return null;
  if(!db)db={};
  if(!Array.isArray(db.candidats))db.candidats=[];
  const alias=resolveCandidatAlias(raw);
  const mapped=isTempCandidateId(raw)?candidatTempRealIds[raw]:"";
  const keys=[raw,alias,mapped].filter(Boolean).map(String);
  return db.candidats.find(c=>keys.includes(String(c.id)))
    ||db.candidats.find(c=>keys.includes(String(c.backendId||"")))
    ||restorePendingCandidat(raw)
    ||(alias&&alias!==raw?restorePendingCandidat(alias):null)
    ||null;
}
function candidatDeleteKeys(c,extra){
  const keys=new Set();
  [extra,c?.id,c?.backendId,resolveCandidatAlias(extra),resolveCandidatAlias(c?.id),resolveCandidatAlias(c?.backendId)].forEach(v=>{if(v!==null&&v!==undefined&&String(v).trim())keys.add(String(v).trim())});
  return keys;
}
function forgetPendingCandidat(c,extra){
  const keys=candidatDeleteKeys(c,extra);
  try{
    keys.forEach(k=>sessionStorage.removeItem("pendingCandidat:"+k));
    const aliases=loadCandidatAliases();
    Object.keys(aliases).forEach(k=>{if(keys.has(k)||keys.has(String(aliases[k]))){keys.add(k);keys.add(String(aliases[k]));delete aliases[k]}});
    saveCandidatAliases(aliases);
    for(let i=sessionStorage.length-1;i>=0;i--){
      const k=sessionStorage.key(i);
      if(!k||!k.startsWith("pendingCandidat:"))continue;
      let item=null;try{item=JSON.parse(sessionStorage.getItem(k)||"null")}catch(e){}
      if(item&&(keys.has(String(item.id||""))||keys.has(String(item.backendId||""))))sessionStorage.removeItem(k);
    }
  }catch(e){}
}
function removeCandidatLocal(c,extra){
  if(!db||!Array.isArray(db.candidats))return 0;
  const keys=candidatDeleteKeys(c,extra);
  const before=db.candidats.length;
  db.candidats=db.candidats.filter(x=>x!==c&&!keys.has(String(x.id||""))&&!keys.has(String(x.backendId||"")));
  forgetPendingCandidat(c,extra);
  return before-db.candidats.length;
}
function cleanupDuplicateCandidates(deleteRemote){
  if(!db||!Array.isArray(db.candidats))return 0;
  const before=db.candidats.length;
  const byKey=new Map();
  const dropped=[];
  (db.candidats||[]).forEach(c=>{
    if(!candidateHasMinimumData(c)){dropped.push(c);return}
    const backendId=sqlBackendId(c.backendId);
    const localId=String(c.id||"").trim();
    if(isTempCandidateId(localId)||(!localId&&!backendId)){dropped.push(c);return}
    const key=candidateDedupeKey(c)||(backendId?"pg:"+backendId:"id:"+localId);
    const prev=byKey.get(key);
    if(!prev||candidateCompletenessScore(c)>candidateCompletenessScore(prev)){
      if(prev)dropped.push(prev);
      byKey.set(key,c);
    }else{
      dropped.push(c);
    }
  });
  const kept=[...byKey.values()];
  dropped.forEach(d=>{
    const dk=candidateDedupeKey(d);
    const keep=dk?byKey.get(dk):null;
    if(keep){rememberCandidatAlias(d.id,keep.id||keep.backendId);rememberCandidatAlias(d.backendId,keep.id||keep.backendId);}
  });
  db.candidats=kept.map(c=>{delete c.isNew;return c});
  if(deleteRemote&&dropped.length&&sgdiAuthToken()){
    dropped.filter(c=>sqlBackendId(c&&c.backendId)).forEach(c=>deleteCandidateFromPostgres(c).catch(e=>console.warn("Doublon candidat non supprimé",e)));
  }
  return before-db.candidats.length;
}
function candidatSectionValidations(c){if(!c.sectionValidations||typeof c.sectionValidations!=="object")c.sectionValidations={};return c.sectionValidations}
function candidatSectionIsValidated(c,key){return !!(c&&candidatSectionValidations(c)[key])}
function candidatSectionIndex(key){return CANDIDAT_SECTIONS.findIndex(s=>s.key===key)}
function candidatCurrentSectionKey(c){const s=CANDIDAT_SECTIONS.find(x=>!candidatSectionIsValidated(c,x.key));return s?s.key:null}
function candidatAllSectionsValid(c){return CANDIDAT_SECTIONS.every(s=>candidatSectionIsValidated(c,s.key))}
function candidatEtape1Valid(c){return CANDIDAT_ETAPE1_KEYS.every(k=>candidatSectionIsValidated(c,k))}
function candidatIsReserve(c){return !!(c&&c.statut==="reserve"&&c.fichePositionValidee===true)}
function candidatPreviousSectionsValid(c,key){
  const idx=candidatSectionIndex(key);
  if(idx<=0)return true;
  return CANDIDAT_SECTIONS.slice(0,idx).every(s=>candidatSectionIsValidated(c,s.key));
}
function candidatSectionAvailable(c,key){
  const cur=candidatCurrentSectionKey(c);
  if(!cur)return true;
  return candidatSectionIndex(key)<=candidatSectionIndex(cur);
}
function candidatSectionUnlockRoles(){return ["ADM1"]}
function candidatCanUnlockSections(){return !!(session&&isAdm1())}
function candidatSectionLocked(c,key){return candidatSectionIsValidated(c,key)&&!candidatCanUnlockSections()}
function candidatSectionOpen(c,key,bannerClass,title){
  if(!candidatSectionAvailable(c,key))return "";
  const locked=candidatSectionLocked(c,key);
  const current=candidatCurrentSectionKey(c)===key;
  const v=candidatSectionValidations(c)[key];
  return `<div class="card candidate-section-card ${current?"current":""} ${locked?"opacity-80":""}" id="section-${key}" data-candidat-section="${key}" data-locked="${locked?"1":"0"}">
    <div class="candidate-section-head ${bannerClass}">
      <div>
        <div class="candidate-section-kicker">Section ${candidatSectionIndex(key)+1}</div>
        <h2>${title}</h2>
      </div>
      <div class="candidate-section-state">
        ${v?`<span class="pill pill-green">Validée ${v.by?`par ${escapeHTML(v.by)}`:""}</span>`:(current?`<span class="pill pill-amber">À valider</span>`:`<span class="pill pill-gray">En attente</span>`)}
      </div>
    </div>`;
}
function candidatSectionClose(c,key){
  if(!candidatSectionAvailable(c,key))return "";
  const valid=candidatSectionIsValidated(c,key);
  const canUnlock=candidatCanUnlockSections();
  const meta=candidatSectionValidations(c)[key];
  return `<div class="candidate-section-footer">
      <div class="candidate-section-actions">
        ${valid&&canUnlock?`<button type="button" class="btn btn-ghost text-xs" data-section-action="1" onclick="unlockCandidatSection('${escapeHTML(c.id)}','${key}')">Déverrouiller</button>`:""}
      </div>
      <div class="candidate-section-note">${valid?`Section validée ${meta?.at?`le ${new Date(meta.at).toLocaleString("fr-FR")}`:""}`:"La validation se fait depuis la barre d'action en bas de page."}</div>
    </div>
  </div>`;
}
function applyCandidatSectionLocks(){
  if(document.getElementById("candidat-form")?.dataset.editMode==="1")return;
  document.querySelectorAll("[data-candidat-section][data-locked='1']").forEach(sec=>{
    sec.querySelectorAll("input,select,textarea,button").forEach(el=>{
      if(el.dataset.sectionAction==="1")return;
      el.disabled=true;
    });
    if(!sec.querySelector(".section-lock-note")){
      const note=document.createElement("div");
      note.className="section-lock-note text-xs text-emerald-700 mt-2";
      note.textContent="Section verrouillée après validation. Cliquez sur Modifier pour corriger les informations du formulaire.";
      sec.appendChild(note);
    }
  });
  const focus=sessionStorage.getItem("candidatFocusSection");
  if(focus){
    sessionStorage.removeItem("candidatFocusSection");
    setTimeout(()=>document.getElementById("section-"+focus)?.scrollIntoView({behavior:"smooth",block:"start"}),50);
  }
}
function modifierCandidatForm(id){
  const form=document.getElementById("candidat-form");
  if(!form)return;
  const c=findCandidatById(id);
  if(!c){toast("Candidat introuvable","error");return}
  form.dataset.editMode="1";
  form.querySelectorAll("input,select,textarea").forEach(el=>{el.disabled=false;el.classList.remove("bg-slate-100","text-slate-400")});
  form.querySelectorAll(".section-lock-note").forEach(el=>el.remove());
  form.querySelectorAll("[data-candidat-section]").forEach(sec=>{sec.dataset.locked="0";sec.classList.remove("opacity-80")});
  bindCandidatDraftAutosave(c.id);
  toast("Modification activée. Corrigez les informations puis cliquez sur Enregistrer.","info");
}

function renderCandidatForm(view,id,options){
  const formOptions=options||{};
  let c;
  if(id){c=findCandidatById(id);if(!c){toast("Candidat introuvable","error");return navigate((location.hash||"").includes("#/candidats_archives")?"candidats_archives":"reserve")}}
  else{c={id:newTempCandidateId(),statut:formOptions.reserveDirect?"reserve":"nouvelle",reserveDirect:!!formOptions.reserveDirect,fichePositionValidee:!!formOptions.reserveDirect,photo:null,nom:"",prenom:"",dateNaissance:"",lieuNaissance:"",nomPere:"",nomMere:"",nin:"",sexe:"M",situation:"Célibataire",taille:"",pointure:"",tailleChemise:"M",exServices:"Non",exServicesPrecision:"",sport:"Non",sportPrecision:"",telephone:"",email:"",adresse:"",commune:"",wilaya:"",contactUrgenceNom:"",contactUrgenceTel:"",contactUrgenceLien:"",posteSouhaite:"",societe:"",salairePrevu:"",avisDecision:"",avisDate:"",avisRecruteur:"",avisCommentaire:"",source:"",cvFile:null,notes:"",habilitations:{enqueteHabilitation:"non",serviceNational:"non",diplomeSecourisme:"non",diplomeAntiIncendie:"non"},langues:[],langueAutre:"",experience:[],verifActeNaissance:false,verifCertifResidence:false,verifCasierJudiciaire:false,verifAptitudeMedicale:false,verifBulletinANEM:false,verifChequeBarre:false,verifPieceIdentite:false,verifFicheFamiliale:false,verifFicheIndividuelle:false,documents:{},createdAt:today(),isNew:true}}
  const step=candidatEtape1Valid(c)?2:1;
  const allValid=candidatAllSectionsValid(c);
  const validatedCount=CANDIDAT_SECTIONS.filter(s=>candidatSectionIsValidated(c,s.key)).length;
  const progressPct=Math.round((validatedCount/(CANDIDAT_SECTIONS.length||1))*100);
  const displayName=String(`${c.nom||""} ${c.prenom||""}`).trim();
  const pageTitle=c.isNew?(c.reserveDirect?"Ajouter candidat en réserve":"Fiche candidat"):(displayName||"Fiche candidat");
  const initials=(displayName?displayName.split(/\s+/).slice(0,2).map(x=>x.charAt(0)).join(""):"CR").toUpperCase();
  const returnRoute=candidatIsArchived(c)?"candidats_archives":c.statut==="reserve"?"reserve":"recrutement";
  const currentKey=candidatCurrentSectionKey(c);
  const currentSection=CANDIDAT_SECTIONS.find(s=>s.key===currentKey);
  const sectionList=CANDIDAT_SECTIONS.map((s,i)=>{
    const done=candidatSectionIsValidated(c,s.key);
    const active=currentKey===s.key;
    const available=candidatSectionAvailable(c,s.key);
    return `<button type="button" class="candidate-section-link ${done?"done":active?"active":""}" ${available?`onclick="document.getElementById('section-${s.key}')?.scrollIntoView({behavior:'smooth',block:'start'})"`:"disabled"}>
      <span>${i+1}</span><strong>${escapeHTML(s.label)}</strong>
    </button>`;
  }).join("");
  view.innerHTML=`<div class="candidate-dossier">
    <div class="candidate-hero">
      <div class="candidate-hero-main">
        <div class="candidate-eyebrow">Recrutement / réserve</div>
        <h1 class="candidate-title">${escapeHTML(pageTitle)}</h1>
        <div class="candidate-meta">
          <span class="candidate-chip">${escapeHTML(c.posteSouhaite||"Poste à définir")}</span>
          <span class="candidate-chip">${escapeHTML(c.societe||"Société non renseignée")}</span>
          <span class="candidate-chip">${escapeHTML(c.statut||"nouvelle")}</span>
          <span class="candidate-chip">Étape ${step}/2</span>
        </div>
      </div>
      <button type="button" class="btn btn-ghost" onclick="navigate('${returnRoute}')">Retour</button>
	    </div>
	    <form id="candidat-form" class="candidate-dossier-grid" onsubmit="event.preventDefault();saveCandidat('${c.id}')">
	      <input type="hidden" name="id" value="${c.id}"/><input type="hidden" name="isNew" value="${c.isNew?"1":""}"/><input type="hidden" name="reserveDirect" value="${c.reserveDirect?"1":""}"/>
	      <div class="candidate-progress-strip">
	        <div class="candidate-progress-top">
	          <div>
	            <div class="candidate-panel-label">Avancement du dossier</div>
	            <p>${allValid?"Toutes les sections sont validées.":"Validez chaque section dans l'ordre pour continuer."}</p>
	          </div>
	          <div class="candidate-progress-score"><strong>${validatedCount}/${CANDIDAT_SECTIONS.length}</strong><span>${progressPct}%</span></div>
	        </div>
	        <div class="candidate-progress-track"><div class="candidate-progress-bar" style="width:${progressPct}%"></div></div>
	        <div class="candidate-section-list candidate-section-list-horizontal">${sectionList}</div>
	      </div>
	      <div class="candidate-actions-panel candidate-actions-row">
	        <button type="button" class="btn btn-secondary" onclick="modifierCandidatForm('${c.id}')">Modifier</button>
	        <button type="button" class="btn btn-secondary" onclick="saveCandidat('${c.id}',true)">Enregistrer</button>
	        ${candidatIsArchived(c)?`<button type="button" class="btn btn-success" onclick="activerCandidat('${c.id}')">Activer</button>`:`<button type="button" class="btn btn-ghost text-red-600" onclick="openArchiveCandidatModal('${c.id}')">Archiver candidat</button>`}
	        ${!candidatIsArchived(c)?(allValid?`<button type="button" class="btn btn-primary" onclick="validerFichePosition('${c.id}')">Valider la fiche de position</button>`:`<button type="button" class="btn btn-ghost" disabled>Fiche de position non complète</button>`):""}
	        <button type="button" class="btn btn-ghost text-red-600" onclick="deleteCandidat('${c.id}')">Supprimer</button>
	      </div>
	      <div class="candidate-main">
	        <div class="stepper candidate-stepper"><div class="step ${step>=1?"done":"active"}">1. Candidature</div><div class="step ${step===2?"active":""}">2. Fiche de renseignement</div></div>
	        ${renderCandidatEtape1(c)}
	        <div id="etape2-block" class="${candidatEtape1Valid(c)?"":"hidden"}">${candidatEtape1Valid(c)?renderCandidatEtape2(c):""}</div>
	      </div>
	      <div class="candidate-global-section-footer">
	        <div>
	          <div class="candidate-global-footer-label">${allValid?"Dossier complet":currentSection?`Section en cours : ${escapeHTML(currentSection.label)}`:"Validation du dossier"}</div>
	          <div class="candidate-global-footer-note">${allValid?"Toutes les sections sont validées. Vous pouvez valider la fiche de position.":"Après validation, la section suivante s'ouvre automatiquement."}</div>
	        </div>
	        <div class="candidate-global-footer-actions">
	          ${!allValid&&currentKey?`<button type="button" class="btn btn-primary" data-section-action="1" onclick="validateCandidatSectionAction('${escapeHTML(c.id)}','${currentKey}')">Valider la section</button>`:""}
	          ${allValid&&!candidatIsArchived(c)?`<button type="button" class="btn btn-primary" onclick="validerFichePosition('${c.id}')">Valider la fiche de position</button>`:""}
	        </div>
	      </div>
	    </form>
	  </div>`;
  setTimeout(()=>{applyCandidatSectionLocks();bindRequiredFieldCleanup(document.getElementById("candidat-form"));if(!c.isNew)bindCandidatDraftAutosave(c.id);validateCandidatBirthField(document.querySelector('[name="dateNaissance"]'));if(sessionStorage.getItem("candidatAutoEdit:"+c.id)==="1"){sessionStorage.removeItem("candidatAutoEdit:"+c.id);modifierCandidatForm(c.id)}},0);
}

