function experienceRow(e,idx){return`<div class="grid grid-6 mb-2 exp-row" data-idx="${idx}"><div class="col-span-2"><label class="label">Employeur</label><input class="input" name="exp_employeur" value="${escapeHTML(e.employeur||"")}"/></div><div class="col-span-2"><label class="label">Poste</label><input class="input" name="exp_poste" value="${escapeHTML(e.poste||"")}"/></div><div><label class="label">Du</label><input class="input" type="date" name="exp_du" value="${e.du||""}"/></div><div><label class="label">Au</label><input class="input" type="date" name="exp_au" value="${e.au||""}"/></div><div class="col-span-2"><label class="label">Salaire</label><input class="input" inputmode="decimal" name="exp_salaire" value="${formatMoneyInputValue(e.salaire||"")}" placeholder="45 000,00" onblur="formatMoneyField(this)"/></div><div class="col-span-3"><label class="label">Motif de départ</label><select class="select" name="exp_motif"><option value="">—</option>${MOTIFS_DEPART.map(m=>`<option ${e.motifDepart===m?"selected":""}>${m}</option>`).join("")}</select></div><div class="col-span-1 flex items-end"><button type="button" class="btn btn-ghost text-red-600 text-xs" onclick="this.closest('.exp-row').remove()">✕</button></div></div>`}
function addExpRow(){const h=document.getElementById("exp-rows");const d=document.createElement("div");d.innerHTML=experienceRow({},h.children.length);h.appendChild(d.firstElementChild)}
function toggleServiceMilitaireFields(value){
  const enabled=value==="Oui";
  document.querySelectorAll("[data-service-militaire-field]").forEach(el=>{
    el.disabled=!enabled;
    if(!enabled)el.value="";
    el.classList.toggle("bg-slate-100",!enabled);
    el.classList.toggle("text-slate-400",!enabled);
  });
}

function collectCandidatFormData(){
  const f=document.getElementById("candidat-form");if(!f)return null;
  const existingId=f.querySelector('[name="id"]')?.value||"";
  const existing=findCandidatById(existingId)||{};
  const fd=new FormData(f);const data={...existing};
  fd.forEach((v,k)=>{if(k==="photo"){data.photo=v||null}else if(k.startsWith("hab_")||k.startsWith("lang_")||k.startsWith("doc_")||k.startsWith("exp_")||k.startsWith("verif")||k.startsWith("cv_")){}else{data[k]=typeof v==="string"?v.trim():v}});
  data.nom=String(fd.get("nom")||data.nom||"").trim();
  data.prenom=String(fd.get("prenom")||data.prenom||"").trim();
  normalizeCandidateIdentity(data);
  data.societe=data.societe||currentStructureSocieteFilter()||mySoc()||sessionStorage.getItem("dashSociete")||"";
  if(data.serviceMilitaire!=="Oui"){
    data.serviceMilitaire="Non";
    data.armeService="";
    data.dateIncorporation="";
    data.dateRadiation="";
    data.nombreAnneesService="";
  }
  data.salairePrevu=parseMoneyInput(data.salairePrevu);
  if(f.querySelector('[name^="hab_"]:not(:disabled),[name^="lang_"]:not(:disabled),[name="langueAutre"]:not(:disabled)')){
    data.habilitations={};["enqueteHabilitation","serviceNational","diplomeSecourisme","diplomeAntiIncendie"].forEach(k=>{const r=f.querySelector(`[name="hab_${k}"]:checked`);data.habilitations[k]=r?r.value:"non"});
    const langues=[];["Arabe","Français","Anglais","Kabyle","Espagnol","Allemand"].forEach(l=>{if(f.querySelector(`[name="lang_${l}"]`)?.checked)langues.push(l)});
    const autre=f.querySelector('[name="langueAutre"]')?.value?.trim();if(autre)langues.push(autre);
    data.langues=langues;data.langueAutre=autre||"";
  }
  const rows=[...f.querySelectorAll(".exp-row")].filter(r=>!r.querySelector("input,select,textarea")?.disabled);
  if(rows.length)data.experience=rows.map(r=>({employeur:r.querySelector('[name="exp_employeur"]').value,poste:r.querySelector('[name="exp_poste"]').value,du:r.querySelector('[name="exp_du"]').value,au:r.querySelector('[name="exp_au"]').value,salaire:parseMoneyInput(r.querySelector('[name="exp_salaire"]').value),motifDepart:r.querySelector('[name="exp_motif"]').value})).filter(e=>e.employeur||e.poste);
  const cvUrl=f.querySelector('[name="cv_url"]')?.value;const cvName=f.querySelector('[name="cv_name"]')?.value;
  if(f.querySelector('[name="cv_url"]:not(:disabled)'))data.cvFile=cvUrl?{url:cvUrl,name:cvName||"cv"}:null;
  if(f.querySelector('[name^="doc_"]:not(:disabled)')){
    data.documents={};
    [...f.querySelectorAll('[name^="doc_"][name$="_url"]')].forEach(inp=>{if(inp.value){const k=inp.name.replace("doc_","").replace("_url","");const nm=f.querySelector(`[name="doc_${k}_name"]`)?.value||"fichier";data.documents[k]={url:inp.value,name:nm}}});
  }
  ["ActeNaissance","CertifResidence","CasierJudiciaire","AptitudeMedicale","BulletinANEM","ChequeBarre","PieceIdentite","FicheFamiliale","FicheIndividuelle"].forEach(k=>{data["verif"+k]=!!f.querySelector(`[name="verif${k}"]`)?.checked});
  return data;
}
function validateCandidatIdentification(data){
  markRequiredFields(document.getElementById("candidat-form"));
  if(data.nin&&!/^\d{10}$/.test(String(data.nin||""))){toast("Le NIN doit contenir exactement 10 chiffres","error");return false}
  return true;
}
function candidatRequiredFieldsForSection(key){
  return {
    identification:[["nom","Nom"],["prenom","Prénom"],["dateNaissance","Date de naissance"],["lieuNaissance","Lieu de naissance"],["sexe","Sexe"],["nomPere","Nom du père"],["nomMere","Nom de la mère"],["nin","NIN"],["situation","Situation familiale"],["source","Source"]],
    poste:[["posteSouhaite","Poste souhaité"],["telephone","Téléphone"]],
    avis:[["avisDecision","Décision"],["avisDate","Date de l'avis"],["avisRecruteur","Recruteur"],["avisCommentaire","Commentaire"]],
    contact:[["adresse","Adresse"],["commune","Commune"],["wilaya","Wilaya"],["contactUrgenceLien","Lien contact urgence"],["contactUrgenceNom","Nom contact urgence"],["contactUrgenceTel","Téléphone urgence"]]
  }[key]||[];
}
function markCandidatSectionMissingFields(key,data){
  const form=document.getElementById("candidat-form");
  if(!form)return [];
  const missing=[];
  candidatRequiredFieldsForSection(key).forEach(([field,label])=>{
    const value=String(data?.[field]??"").trim();
    const controls=[...form.querySelectorAll("[name=\""+CSS.escape(field)+"\"]")];
    controls.forEach(el=>{
      if(el.disabled)return;
      el.classList.toggle("input-error",!value);
      if(!value)el.setAttribute("aria-invalid","true");else el.removeAttribute("aria-invalid");
    });
    if(!value)missing.push(label);
  });
  return missing;
}
function candidatSectionRequiredValid(key,data){
  const missing=markCandidatSectionMissingFields(key,data);
  if(missing.length){toast("Champs obligatoires manquants : "+missing.slice(0,6).join(", ")+(missing.length>6?"...":""),"error");return false}
  return true;
}
async function saveCandidat(id,showToast,options){
  const opt=options||{};
  if(opt.requireIdentification)markRequiredFields(document.getElementById("candidat-form"));
  const data=collectCandidatFormData();if(!data){toast("Formulaire introuvable","error");return}
  if(!candidateHasMinimumData(data)){toast(candidateMinimumDataMessage(data),"error");return}
  if(opt.requireIdentification&& !candidatSectionRequiredValid("identification",data))return;
  if(!validateCandidatIdentification(data))return;
  if(data.dateNaissance&&candidatAgeAtSave(data.dateNaissance)<20){toast("Le candidat doit avoir au moins 20 ans à la date d'enregistrement","error");return}
  const realId=isTempCandidateId(id)?(candidatTempRealIds[id]||(candidatTempRealIds[id]=uid("cd"))):id;
  const creating=!findCandidatById(realId)&&!findCandidatById(id);
  let c=findCandidatById(realId)||findCandidatById(id);
  const draft={...(c||{id:realId,statut:"nouvelle",createdAt:today()}),...data,id:realId};
  delete draft.isNew;
  if((data.reserveDirect==="1"||draft.reserveDirect)&&candidatAllSectionsValid(draft)){
    draft.reserveDirect=true;
    draft.statut="reserve";
    draft.fichePositionValidee=true;
    draft.fichePositionValideeAt=draft.fichePositionValideeAt||new Date().toISOString();
    draft.fichePositionValideeBy=draft.fichePositionValideeBy||session?.username||"system";
  }
  else if(!candidatIsArchived(draft)){
    draft.statut="nouvelle";
    draft.fichePositionValidee=false;
    delete draft.fichePositionValideeAt;
    delete draft.fichePositionValideeBy;
  }
  try{
    await persistCandidateToPostgres(draft,{allowCreate:creating});
    if(c)Object.assign(c,draft);else{c=draft;if(!db.candidats.some(x=>x===c||String(x.id)===String(c.id)||String(x.backendId||"")===String(c.backendId||"")))db.candidats.push(c)}
    stashCandidatForRoute(c,[id,realId,data.id]);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
  }catch(e){
    toast("Candidat non enregistré dans PostgreSQL : "+(e.message||e),"error");
    return null;
  }
  if(showToast)toast("Candidat enregistré dans PostgreSQL","success");
  if((location.hash||"").endsWith("/nouveau")){
    location.hash="#/"+(c.reserveDirect?"reserve/":"recrutement/")+c.id;
  }
  return c;
}
async function saveCandidatDraft(id){
  const data=collectCandidatFormData();if(!data||!candidateHasMinimumData(data))return false;
  let c=findCandidatById(id);
  if(!c)return false;
  Object.assign(c,data);
  delete c.isNew;
  if(!c.fichePositionValidee&&!candidatIsArchived(c))c.statut="nouvelle";
  try{
    await persistCandidateToPostgres(c);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
    if((location.hash||"").endsWith("/nouveau")){
      history.replaceState(null,"","#/"+(c.reserveDirect?"reserve/":"recrutement/")+id);
    }
    return true;
  }catch(e){
    console.error("Brouillon candidat non enregistré dans PostgreSQL",e);
    return false;
  }
}
function openArchiveCandidatModal(id){
  const c=findCandidatById(id)||{};
  openModal(`<h3 class="font-bold text-lg mb-4">Archiver candidat</h3>
    <form onsubmit="event.preventDefault();confirmArchiveCandidat('${id}')">
      <div class="mb-4 text-sm text-slate-600">Choisissez le motif d'archivage${c.nom||c.prenom?` pour <b>${escapeHTML((c.nom||"")+" "+(c.prenom||""))}</b>`:""}.</div>
      <div class="mb-4">
        <label class="label">Motif *</label>
        <select class="select" name="motifArchive" >
          <option value="">— Choisir un motif —</option>
          ${CANDIDAT_ARCHIVE_MOTIFS.map(m=>`<option>${escapeHTML(m)}</option>`).join("")}
        </select>
      </div>
      <div class="mb-4">
        <label class="label">Commentaire</label>
        <textarea class="textarea" name="commentaireArchive" rows="3" placeholder="Précision facultative"></textarea>
      </div>
      <div class="flex justify-end gap-2">
        <button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button>
        <button class="btn btn-danger">Archiver candidat</button>
      </div>
    </form>`);
}
async function confirmArchiveCandidat(id){
  const f=document.querySelector(".modal-bg form");if(!f)return;
  const motif=String(new FormData(f).get("motifArchive")||"").trim();
  const commentaire=String(new FormData(f).get("commentaireArchive")||"").trim();
  const data=collectCandidatFormData()||{};
  let c=findCandidatById(id);
  if(!c){toast("Enregistrez d'abord le candidat avant de l'archiver","error");return}
  if(!motif){toast("Choisissez un motif d'archivage","error");return}
  const source=candidatIsReserve(c)||data.statut==="reserve"||data.fichePositionValidee===true?"reserve":"nouvelle";
  const draft={...c,...data};
  draft.statut="archive";
  draft.archiveSource=source;
  draft.motifArchive=motif;
  draft.commentaireArchive=commentaire;
  draft.archivedAt=new Date().toISOString();
  draft.archivedBy=session?.username||session?.nom||"";
  delete draft.isNew;
  try{
    await persistCandidateToPostgres(draft);
    Object.assign(c,draft);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
    closeModal();
    toast("Candidat archivé dans PostgreSQL","success");
    navigate("candidats_archives");
  }catch(e){toast("Archivage PostgreSQL refusé : "+(e.message||e),"error")}
}
async function deleteCandidat(id){
  if(isTempCandidateId(id)){forgetPendingCandidat(null,id);navigate("reserve");setTimeout(renderView,0);return}
  const c=findCandidatById(id);
  if(!c){forgetPendingCandidat(null,id);toast("Candidat déjà supprimé","info");navigate("reserve");setTimeout(renderView,0);return}
  const label=String((c.nom||"")+" "+(c.prenom||"")).trim();
  const targetRoute=candidatIsArchived(c)?"candidats_archives":candidatIsReserve(c)?"reserve":"recrutement";
  if(!confirm("Supprimer définitivement "+(label||"ce candidat")+" ?"))return;
  try{await deleteCandidateFromPostgres(c)}catch(e){
    const msg=String(e&&e.message||e||"");
    if(!/not found|introuvable|404/i.test(msg)){toast("Suppression PostgreSQL refusée : "+msg,"error");return}
  }
  const removed=removeCandidatLocal(c,id);
  if(typeof sgdiBackendSave==="function")sgdiBackendSave();
  toast(removed?"Candidat supprimé de PostgreSQL":"Candidat déjà supprimé","success");
  if((location.hash||"").slice(2)===targetRoute)renderView();else navigate(targetRoute);
}
async function activerCandidat(id){
  const c=findCandidatById(id);
  if(!c){toast("Candidat introuvable","error");return}
  if(!confirm("Activer ce candidat et l'envoyer vers Candidats en réserve ?"))return;
  const draft={...c};
  draft.statut="reserve";
  draft.fichePositionValidee=true;
  draft.fichePositionValideeAt=draft.fichePositionValideeAt||new Date().toISOString();
  draft.fichePositionValideeBy=draft.fichePositionValideeBy||session?.username||"system";
  draft.reactivatedAt=new Date().toISOString();
  draft.reactivatedBy=session?.username||session?.nom||"";
  delete draft.motifArchive;
  delete draft.commentaireArchive;
  delete draft.archivedAt;
  delete draft.archivedBy;
  delete draft.archiveSource;
  delete draft.isNew;
  try{
    await persistCandidateToPostgres(draft);
    Object.assign(c,draft);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
    toast("Candidat activé et envoyé en réserve","success");
    navigate("reserve");
  }catch(e){toast("Activation PostgreSQL refusée : "+(e.message||e),"error")}
}
function scheduleCandidatDraftSave(id){
  if(!findCandidatById(id))return;
  sgdiDirty=true;
  clearTimeout(candidatDraftTimer);
  candidatDraftTimer=setTimeout(()=>saveCandidatDraft(id),700);
}
function bindCandidatDraftAutosave(id){
  const f=document.getElementById("candidat-form");if(!f)return;
  f.querySelectorAll("input,select,textarea").forEach(el=>{
    if(el.dataset.candidatDraftBound==="1")return;
    const fn=()=>scheduleCandidatDraftSave(id);
    el.addEventListener("change",fn);
    if(["INPUT","TEXTAREA"].includes(el.tagName))el.addEventListener("input",fn);
    el.dataset.candidatDraftBound="1";
  });
}
function validateCandidatSection(key,data){
  if(!candidatSectionRequiredValid(key,data))return false;
  if(key==="identification"&&!validateCandidatIdentification(data))return false;
  if(data.dateNaissance&&candidatAgeAtSave(data.dateNaissance)<20){toast("Le candidat doit avoir au moins 20 ans à la date d'enregistrement","error");return false}
  return true;
}
async function validateCandidatSectionAction(id,key){
  const lockKey=candidatValidationLockKey(id,key);
  if(candidatValidationLocks.has(lockKey)){toast("Validation déjà en cours, veuillez patienter","warning");return}
  candidatValidationLocks.add(lockKey);
  setCandidatSectionButtonsDisabled(id,key,true);
  const realId=isTempCandidateId(id)?(candidatTempRealIds[id]||(candidatTempRealIds[id]=uid("cd"))):id;
  let c=findCandidatById(realId)||findCandidatById(id);
  markRequiredFields(document.getElementById("candidat-form"));
  const data=collectCandidatFormData();if(!data){candidatValidationLocks.delete(lockKey);setCandidatSectionButtonsDisabled(id,key,false);return}
  const creating=!c;
  const validationTarget=c||findCandidatById(data.id)||{id:realId,statut:"nouvelle",createdAt:today(),sectionValidations:{}};
  if(data.sectionValidations&&!validationTarget.sectionValidations)validationTarget.sectionValidations=data.sectionValidations;
  if(!candidatPreviousSectionsValid(validationTarget,key)){
    const missing=CANDIDAT_SECTIONS.slice(0,candidatSectionIndex(key)).filter(s=>!candidatSectionIsValidated(validationTarget,s.key)).map(s=>s.label).join(", ");
    toast("Validez d'abord la section précédente"+(missing?" : "+missing:""),"error");
    candidatValidationLocks.delete(lockKey);setCandidatSectionButtonsDisabled(id,key,false);return
  }
  if(!candidatSectionAvailable(validationTarget,key)){toast("Cette section n'est pas encore ouverte","error");candidatValidationLocks.delete(lockKey);setCandidatSectionButtonsDisabled(id,key,false);return}
  if(!validateCandidatSection(key,data)){candidatValidationLocks.delete(lockKey);setCandidatSectionButtonsDisabled(id,key,false);return}
  if(!candidateHasMinimumData(data)){toast(candidateMinimumDataMessage(data),"error");candidatValidationLocks.delete(lockKey);setCandidatSectionButtonsDisabled(id,key,false);return}
  const draft={...validationTarget,...data,id:realId};
  delete draft.isNew;
  let validation;
  try{
    validation=await SGDI.rh.validateCandidateSection(candidateApiPayload(draft),key,sqlBackendId(draft.backendId));
  }catch(e){
    toast("Validation backend refusée : "+(e.message||e),"error");
    candidatValidationLocks.delete(lockKey);setCandidatSectionButtonsDisabled(id,key,false);return
  }
  draft.sectionValidations=validation.data?.sectionValidations||draft.sectionValidations||{};
  if((data.reserveDirect==="1"||draft.reserveDirect)&&candidatAllSectionsValid(draft)){
    draft.reserveDirect=true;
    draft.statut="reserve";
    draft.fichePositionValidee=true;
    draft.fichePositionValideeAt=draft.fichePositionValideeAt||new Date().toISOString();
    draft.fichePositionValideeBy=draft.fichePositionValideeBy||session?.username||"system";
  }else{
    draft.statut="nouvelle";
    draft.fichePositionValidee=false;
    delete draft.fichePositionValideeAt;
    delete draft.fichePositionValideeBy;
  }
  const next=CANDIDAT_SECTIONS[candidatSectionIndex(key)+1];
  if(next)sessionStorage.setItem("candidatFocusSection",next.key);
  try{
    await persistCandidateToPostgres(draft,{allowCreate:creating});
    if(c)Object.assign(c,draft);else{c=draft;if(!db.candidats.some(x=>x===c||String(x.id)===String(c.id)||String(x.backendId||"")===String(c.backendId||"")))db.candidats.push(c)}
    stashCandidatForRoute(c,[id,realId,data.id]);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
    toast(next?"Section validée. Passage à la section suivante.":"Toutes les sections sont validées.","success");
    if((location.hash||"").endsWith("/nouveau"))navigate((c.reserveDirect?"reserve/":"recrutement/")+c.id);else renderView();
  }catch(e){toast("Validation PostgreSQL refusée : "+(e.message||e),"error");setCandidatSectionButtonsDisabled(id,key,false)}
  finally{candidatValidationLocks.delete(lockKey)}
}
function unlockCandidatSection(id,key){
  if(!candidatCanUnlockSections()){toast("Déverrouillage réservé à l'administrateur habilité","error");return}
  const c=findCandidatById(id);if(!c)return;
  const idx=candidatSectionIndex(key);
  const locks=candidatSectionValidations(c);
  CANDIDAT_SECTIONS.slice(idx).forEach(s=>delete locks[s.key]);
  sessionStorage.setItem("candidatFocusSection",key);
  saveDB();toast("Section déverrouillée. Les sections suivantes devront être revalidées.","success");renderView();
}
async function validerFichePosition(id){
  const c=await saveCandidat(id,false,{requireIdentification:true});if(!c)return;
  if(!candidatAllSectionsValid(c)){toast("Impossible de valider la fiche : toutes les sections doivent être validées","error");renderView();return}
  const draft={...c};
  draft.societe=draft.societe||currentStructureSocieteFilter()||mySoc()||sessionStorage.getItem("dashSociete")||"";
  draft.statut="reserve";draft.fichePositionValidee=true;draft.fichePositionValideeAt=new Date().toISOString();draft.fichePositionValideeBy=session?session.username:"system";
  try{
    await persistCandidateToPostgres(draft);
    Object.assign(c,draft);
    if(typeof sgdiBackendSave==="function")sgdiBackendSave();
    toast("✓ Fiche de position validée — candidat en réserve","success");navigate("reserve");
  }catch(e){toast("Validation fiche PostgreSQL refusée : "+(e.message||e),"error")}
}
function presselectionner(id){validateCandidatSectionAction(id,candidatCurrentSectionKey(findCandidatById(id)||{sectionValidations:{}})||"identification")}
function validerVersContrat(id){validerFichePosition(id)}
function mettreEnReserve(id){validerFichePosition(id)}

/* ---- CONTRATS / CONTRACTUALISATION ---- */
function renderAvenants(view){
  const socFilter=currentStructureSocieteFilter();
  const list=(db.avenants||[]).filter(av=>{
    if(!socFilter)return true;
    const a=(db.agents||[]).find(x=>x.id===av.agentId);
    return a&&a.societe===socFilter;
  }).sort((a,b)=>String(b.dateAvenant||b.createdAt||"").localeCompare(String(a.dateAvenant||a.createdAt||"")));
  const enCours=list.filter(a=>a.statut==="brouillon").length;
  const signes=list.filter(a=>a.statut==="signe").length;
  view.innerHTML=`<div class="flex justify-between items-start gap-3 mb-4">
    <div><h1 class="text-2xl font-bold">Avenants au contrat</h1><p class="text-sm text-slate-500">Gestion des modifications contractuelles du personnel${socFilter?` · <span class="font-semibold text-amber-700">${escapeHTML(socFilter)}</span>`:""}.</p></div>
    <button class="btn avenant-create-btn" onclick="openAvenantModal('general')">Nouvel avenant</button>
  </div>
  <div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Total avenants</div><div class="text-3xl font-black text-sky-700">${list.length}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Brouillons</div><div class="text-3xl font-black text-amber-700">${enCours}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Signés</div><div class="text-3xl font-black text-emerald-700">${signes}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Ce mois</div><div class="text-3xl font-black text-indigo-700">${list.filter(x=>(x.dateAvenant||"").slice(0,7)===today().slice(0,7)).length}</div></div>
  </div>
  <div class="card overflow-hidden"><table>
    <thead><tr><th>N°</th><th>Employé</th><th>Type</th><th>Date</th><th>Effet</th><th>Objet</th><th>Statut</th><th></th></tr></thead>
    <tbody>${list.length===0?`<tr><td colspan="10" class="text-center text-slate-500 p-6">Aucun avenant enregistré.</td></tr>`:list.map(av=>{const a=db.agents.find(x=>x.id===av.agentId);const st=av.statut==="signe"?"pill-green":av.statut==="annule"?"pill-red":"pill-amber";return`<tr data-searchable onclick="previewAvenant('${av.id}')" class="cursor-pointer hover:bg-slate-50"><td class="font-mono font-bold">${escapeHTML(av.numero||"—")}</td><td>${a?`<a class="font-semibold hover:underline" href="#/effectif/agent/${a.id}" onclick="event.stopPropagation()">${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</a><div class="text-[10px] text-slate-500">${escapeHTML(a.matricule||"")} · ${escapeHTML(a.societe||"")}</div>`:"—"}</td><td><span class="pill pill-blue">${escapeHTML(av.type||"—")}</span></td><td class="text-xs">${formatDate(av.dateAvenant)}</td><td class="text-xs">${formatDate(av.dateEffet)}</td><td class="text-xs">${escapeHTML((av.objet||"").slice(0,60))}</td><td><span class="pill ${st}">${escapeHTML(av.statut||"brouillon")}</span></td><td class="text-right"><button class="btn btn-ghost text-xs" onclick="event.stopPropagation();previewAvenant('${av.id}')">Aperçu</button>${av.statut!=="signe"?`<button class="btn btn-success text-xs" onclick="event.stopPropagation();signerAvenant('${av.id}')">Signer</button>`:""}${av.statut!=="annule"?`<button class="btn btn-danger text-xs" onclick="event.stopPropagation();annulerAvenant('${av.id}')">Annuler</button>`:""}</td></tr>`}).join("")}</tbody>
  </table></div>`;
}
function nextAvenantNumero(){const y=new Date().getFullYear();const n=(db.avenants||[]).filter(a=>String(a.numero||"").includes(String(y))).length+1;return`AV-${y}-${String(n).padStart(4,"0")}`}
function openAvenantModal(mode){
  mode=mode||"general";
  const agents=db.agents.filter(a=>a.statut!=="archive").sort((a,b)=>(a.nom||"").localeCompare(b.nom||""));
  const title=mode==="salaire"?"Nouveau salaire":mode==="affectation"?"Nouvelle affectation":"Nouvel avenant";
  const typeDefault=mode==="salaire"?"Modification salaire":mode==="affectation"?"Changement de site":"Changement de poste";
  openModal(`<h3 class="font-bold text-lg mb-4">${title}</h3>
  <form onsubmit="event.preventDefault();saveAvenant()">
    <input type="hidden" name="mode" value="${mode}"/>
    <div class="grid grid-6">
      <div class="col-span-3"><label class="label">Employé</label><select class="select" name="agentId" ><option value="">— Choisir —</option>${agents.map(a=>`<option value="${a.id}">${escapeHTML((a.nom||"")+" "+(a.prenom||""))} — ${escapeHTML(a.matricule||"")} — ${escapeHTML(a.societe||"")}</option>`).join("")}</select></div>
      <div class="col-span-3"><label class="label">Type d'avenant</label><select class="select" name="type" onchange="toggleAvenantFields(this.value)">${["Changement de poste","Changement de site","Nouveau salaire","Nouvelle affectation","Changement date de contrat","Modification horaire","Prolongation CDD","Changement de structure","Autre"].map(t=>`<option ${t===typeDefault?"selected":""}>${t}</option>`).join("")}</select></div>
      <div class="col-span-2"><label class="label">N° avenant</label><input class="input bg-slate-50" name="numero" value="${nextAvenantNumero()}" readonly/></div>
      <div class="col-span-2"><label class="label">Date avenant</label><input class="input" type="date" name="dateAvenant" value="${today()}" /></div>
      <div class="col-span-2"><label class="label">Date d'effet</label><input class="input" type="date" name="dateEffet" value="${today()}" /></div>
      ${mode==="salaire"?`<div class="col-span-3"><label class="label">Ancien salaire</label><input class="input" name="ancienneValeur" placeholder="Ex : 45 000,00" onblur="formatMoneyField(this)"/></div><div class="col-span-3"><label class="label">Nouveau salaire</label><input class="input" name="nouvelleValeur"  placeholder="Ex : 55 000,00" onblur="formatMoneyField(this)"/></div>`:mode==="affectation"?`<div class="col-span-3"><label class="label">Ancienne affectation</label><input class="input" name="ancienneValeur" placeholder="Ex : Site A - Agent APS"/></div><div class="col-span-3"><label class="label">Nouvelle affectation</label><input class="input" name="nouvelleValeur"  placeholder="Ex : Site B - Chef de poste"/></div>`:`
      <div class="col-span-3"><label class="label">Ancienne situation / valeur</label><input class="input" name="ancienneValeur" placeholder="Ex : Agent APS - Site A"/></div>
      <div class="col-span-3"><label class="label">Nouvelle situation / valeur</label><input class="input" name="nouvelleValeur" placeholder="Ex : Chef de poste - Site B"/></div>`}
      <div id="avenant-date-fields" class="col-span-6 hidden"><div class="grid grid-2"><div><label class="label">Ancienne date fin contrat</label><input class="input" type="date" name="ancienneDateContrat"/></div><div><label class="label">Nouvelle date fin contrat</label><input class="input" type="date" name="nouvelleDateContrat"/></div></div><div class="text-xs text-slate-500 mt-1">Après signature, la nouvelle date sera portée automatiquement sur la fiche employé et la situation contrat.</div></div>
      <div class="col-span-6"><label class="label">Objet</label><input class="input" name="objet"  value="${mode==="salaire"?"Modification du salaire":mode==="affectation"?"Nouvelle affectation":"Objet de l'avenant"}" placeholder="Objet de l'avenant"/></div>
      <div class="col-span-6"><label class="label">Détails / clauses</label><textarea class="textarea" name="details" rows="5" placeholder="Décrire les clauses modifiées et les conditions d'application...">${mode==="salaire"?"Le salaire mensuel net de l'employé est modifié à compter de la date d'effet indiquée. Les autres clauses du contrat initial demeurent inchangées.":mode==="affectation"?"L'employé est affecté à une nouvelle structure/site à compter de la date d'effet indiquée. Les autres clauses du contrat initial demeurent inchangées.":""}</textarea></div>
    </div>
    <div class="flex justify-end gap-2 mt-4"><button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button><button class="btn btn-primary">Enregistrer</button></div>
  </form>`);
}
function saveAvenant(){
  const f=document.querySelector(".modal-bg form");const fd=new FormData(f);
  const av={id:uid("av"),numero:fd.get("numero")||nextAvenantNumero(),agentId:fd.get("agentId"),mode:fd.get("mode")||"general",type:fd.get("type"),dateAvenant:fd.get("dateAvenant"),dateEffet:fd.get("dateEffet"),ancienneValeur:fd.get("ancienneValeur")||"",nouvelleValeur:fd.get("nouvelleValeur")||"",ancienneDateContrat:fd.get("ancienneDateContrat")||"",nouvelleDateContrat:fd.get("nouvelleDateContrat")||"",objet:fd.get("objet")||"",details:fd.get("details")||"",statut:"brouillon",createdAt:new Date().toISOString(),createdBy:session?.username||""};
  db.avenants=db.avenants||[];db.avenants.push(av);saveDB();closeModal();toast("Avenant enregistré","success");renderView();
}
function toggleAvenantFields(type){
  const box=document.getElementById("avenant-date-fields");if(box)box.classList.toggle("hidden",!(type==="Changement date de contrat"||type==="Prolongation CDD"));
  const old=document.querySelector('[name="ancienneValeur"]');const neu=document.querySelector('[name="nouvelleValeur"]');const obj=document.querySelector('[name="objet"]');const det=document.querySelector('[name="details"]');
  if(type==="Nouveau salaire"){if(old){old.placeholder="Ex : 45 000,00";old.type="text"}if(neu){neu.placeholder="Ex : 55 000,00";neu.required=false}if(obj)obj.value="Modification du salaire";if(det)det.value="Le salaire mensuel net de l'employé est modifié à compter de la date d'effet indiquée. Les autres clauses du contrat initial demeurent inchangées."}
  else if(type==="Nouvelle affectation"){if(old)old.placeholder="Ex : Site A - Agent APS";if(neu){neu.placeholder="Ex : Site B - Chef de poste";neu.required=false}if(obj)obj.value="Nouvelle affectation";if(det)det.value="L'employé est affecté à une nouvelle structure/site à compter de la date d'effet indiquée. Les autres clauses du contrat initial demeurent inchangées."}
}
function appliquerAvenantAgent(av){
  const a=db.agents.find(x=>x.id===av.agentId);if(!a)return;
  if((av.type==="Changement date de contrat"||av.type==="Prolongation CDD")&&av.nouvelleDateContrat){
    av.ancienneDateContrat=av.ancienneDateContrat||a.dateFinContrat||"";
    a.dateFinContrat=av.nouvelleDateContrat;
    a.updatedAt=today();
  }
  if((av.type==="Modification salaire"||av.type==="Nouveau salaire")&&av.nouvelleValeur){
    a.salaireNet=parseMoneyInput(av.nouvelleValeur)||a.salaireNet;
    a.updatedAt=today();
  }
}
async function signerAvenant(id){
  const av=(db.avenants||[]).find(x=>x.id===id);if(!av)return;
  try{
    await sgdiRunLegacyAction("set-status",{collection:"avenants",item_id:id,data:{statut:"signe"}});
    appliquerAvenantAgent(av);
    await sgdiPullState({silent:true});
    toast("Avenant signé par le backend","success");
    renderView();
  }catch(e){toast("Signature refusée par PostgreSQL : "+(e.message||e),"error")}
}
async function annulerAvenant(id){
  const av=(db.avenants||[]).find(x=>x.id===id);if(!av)return;
  if(!confirm("Annuler cet avenant ?"))return;
  try{
    await sgdiRunLegacyAction("set-status",{collection:"avenants",item_id:id,data:{statut:"annule"}});
    await sgdiPullState({silent:true});
    toast("Avenant annulé par le backend","success");
    renderView();
  }catch(e){toast("Annulation refusée par PostgreSQL : "+(e.message||e),"error")}
}
function avenantHTML(av){
  const a=db.agents.find(x=>x.id===av.agentId)||{};
  return`<div style="font-family:Arial,sans-serif;color:#111;background:#fff;padding:28px;max-width:850px;margin:auto">
    <div style="display:flex;justify-content:space-between;border-bottom:3px solid #111;padding-bottom:12px;margin-bottom:18px"><div><div style="font-size:24px;font-weight:900;text-transform:uppercase">Avenant au contrat de travail</div><div style="font-size:12px;color:#555">N° ${escapeHTML(av.numero||"")}</div></div><div style="text-align:right;font-weight:700">${escapeHTML(a.societe||"SGDI")}<div style="font-size:12px;font-weight:400;color:#555">Date : ${formatDate(av.dateAvenant)}</div></div></div>
    <p>Entre la société <b>${escapeHTML(a.societe||"")}</b> et l'employé(e) <b>${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</b>, matricule <b>${escapeHTML(a.matricule||"")}</b>, il est convenu le présent avenant.</p>
    <table style="width:100%;border-collapse:collapse;font-size:13px;margin:16px 0"><tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Type</td><td style="border:1px solid #333;padding:8px">${escapeHTML(av.type||"")}</td></tr><tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Date d'effet</td><td style="border:1px solid #333;padding:8px">${formatDate(av.dateEffet)}</td></tr><tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Objet</td><td style="border:1px solid #333;padding:8px">${escapeHTML(av.objet||"")}</td></tr><tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Ancienne situation</td><td style="border:1px solid #333;padding:8px">${escapeHTML(av.ancienneValeur||"—")}</td></tr><tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Nouvelle situation</td><td style="border:1px solid #333;padding:8px">${escapeHTML(av.nouvelleValeur||"—")}</td></tr>${av.ancienneDateContrat||av.nouvelleDateContrat?`<tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Ancienne date fin contrat</td><td style="border:1px solid #333;padding:8px">${formatDate(av.ancienneDateContrat)}</td></tr><tr><td style="border:1px solid #333;padding:8px;background:#f1f5f9;font-weight:bold">Nouvelle date fin contrat</td><td style="border:1px solid #333;padding:8px">${formatDate(av.nouvelleDateContrat)}</td></tr>`:""}</table>
    <h3 style="font-size:14px;text-transform:uppercase;border-bottom:1px solid #333;padding-bottom:5px">Clauses particulières</h3><div style="white-space:pre-wrap;font-size:13px;line-height:1.6">${escapeHTML(av.details||"Les autres clauses du contrat initial demeurent inchangées.")}</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:60px;margin-top:50px;font-size:12px"><div>Signature employeur<br><br><br>________________________</div><div>Signature employé(e)<br><br><br>________________________</div></div>
  </div>`;
}
function previewAvenant(id){const av=(db.avenants||[]).find(x=>x.id===id);if(!av)return;openModal(`<div style="max-height:82vh;overflow:auto;background:#fff">${avenantHTML(av)}</div><div class="flex justify-end gap-2 mt-3"><button class="btn btn-ghost" onclick="closeModal()">Fermer</button><button class="btn btn-primary" onclick="printAvenant('${id}')">Imprimer</button></div>`)}
function printAvenant(id){const av=(db.avenants||[]).find(x=>x.id===id);if(!av)return;const w=window.open("","_blank","width=900,height=700");w.document.write(`<html><head><title>${escapeHTML(av.numero||"Avenant")}</title></head><body>${avenantHTML(av)}<script>window.onload=()=>setTimeout(()=>window.print(),300)<\/script></body></html>`);w.document.close()}

function renderContratsDashboard(view){
  const socFilter=currentStructureSocieteFilter();
  const agents=(db.agents||[]).filter(a=>a.statut!=="archive"&&(!socFilter||a.societe===socFilter));
  const candidates=(db.candidats||[]).filter(c=>!socFilter||c.societe===socFilter);
  const toContract=candidates.filter(c=>c.statut==="a_contractualiser");
  const avenants=(db.avenants||[]).filter(av=>{const a=(db.agents||[]).find(x=>x.id===av.agentId);return !socFilter||a?.societe===socFilter});
  const signedAvenants=avenants.filter(a=>a.statut==="signe");
  const today_=today();
  const cddSoon=agents.filter(a=>a.typeContrat==="CDD"&&a.dateFinContrat&&daysBetween(today_,a.dateFinContrat)>=0&&daysBetween(today_,a.dateFinContrat)<=60);
  const trialSoon=agents.filter(a=>a.dateFinEssai&&daysBetween(today_,a.dateFinEssai)>=0&&daysBetween(today_,a.dateFinEssai)<=30);
  const mass=agents.reduce((sum,a)=>sum+(parseFloat(a.salaireNet)||0),0);
  const card=(label,value,sub,route,color,icon)=>`<button type="button" class="card p-5 text-left kpi-clickable" onclick="navigate('${route}')" style="border-left:5px solid ${color};min-height:132px;background:#fff"><div class="flex items-start justify-between gap-3"><div><div class="text-xs uppercase font-black text-slate-500">${escapeHTML(label)}</div><div class="text-4xl font-black mt-2" style="color:${color}">${value}</div><div class="text-xs text-slate-400 mt-2">${escapeHTML(sub||"Cliquer pour ouvrir")}</div></div></div></button>`;
  const quick=(label,route,icon)=>`<button type="button" class="btn btn-secondary justify-start" onclick="navigate('${route}')">${icon} ${escapeHTML(label)}</button>`;
  view.innerHTML=`<div class="mb-5 flex items-start justify-between gap-3 flex-wrap"><div><h1 class="text-2xl font-black uppercase">CONTRATS</h1><p class="text-sm text-slate-500">Statistiques et accès rapides${socFilter?` · ${escapeHTML(socFilter)}`:""}</p></div><button class="btn contract-create-btn" onclick="openCreateContratDirectModal()">➕ Créer contrat</button></div>
    <div class="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4 mb-5">
      ${card("Nouveau contrat",toContract.length,"Candidats à contractualiser","contrats/a_contractualiser","#043970","➕")}
      ${card("Avenants",avenants.length,`${signedAvenants.length} signé(s)`,"contrats/avenants","#7c3aed","✎")}
      ${card("Situation contrat",agents.length,"Agents avec contrat","contrats/situation","#0369a1","📑")}
      ${card("Alertes",cddSoon.length+trialSoon.length,`${cddSoon.length} CDD · ${trialSoon.length} essai`,"contrats/situation","#dc2626","🔔")}
    </div>
    <div class="grid grid-cols-1 xl:grid-cols-2 gap-4">
      <div class="card p-4"><h3 class="font-black mb-3">Accès rapides</h3><div class="grid gap-2">${quick("Nouveau contrat","contrats/a_contractualiser","➕")}${quick("Avenant","contrats/avenants","✎")}${quick("Situation contrat","contrats/situation","📑")}</div></div>
      <div class="card p-4"><h3 class="font-black mb-3">Synthèse financière</h3><div class="grid grid-cols-2 gap-3"><div class="p-3 rounded bg-slate-50"><div class="text-xs text-slate-500 uppercase">Masse salariale nette</div><div class="text-2xl font-black text-slate-800">${money(mass)}</div></div><div class="p-3 rounded bg-slate-50"><div class="text-xs text-slate-500 uppercase">Salaire moyen</div><div class="text-2xl font-black text-slate-800">${agents.length?money(mass/agents.length):money(0)}</div></div></div></div>
    </div>`;
}

function renderContrats(view,mode){
  const socFilter=currentStructureSocieteFilter();
  if(mode==="a_contractualiser"){
    const list=db.candidats.filter(c=>c.statut==="a_contractualiser"&&(!socFilter||c.societe===socFilter));
    view.innerHTML=`<div class="flex items-start justify-between gap-3 mb-6 flex-wrap">
      <div><h1 class="text-2xl font-bold mb-2">📋 À contractualiser</h1><p class="text-slate-500 text-sm">Candidats retenus.</p></div>
      <button type="button" class="btn contract-create-btn" onclick="openCreateContratDirectModal()">Créer contrat</button>
    </div>
    ${list.length===0?`<div class="card p-10 text-center text-slate-500">Aucun.</div>`:`<div class="card overflow-hidden"><table>
      <thead><tr><th>Candidat</th><th>Poste</th><th>Société</th><th>Vérifs.</th><th></th></tr></thead>
      <tbody>${list.map(c=>{const v=["ActeNaissance","CertifResidence","CasierJudiciaire","AptitudeMedicale","BulletinANEM","ChequeBarre","PieceIdentite","FicheFamiliale","FicheIndividuelle"].filter(k=>c["verif"+k]).length;return`<tr data-searchable><td><div class="flex items-center gap-2"><div class="avatar">${c.photo?`<img src="${c.photo}"/>`:escapeHTML(c.prenom.slice(0,1))}</div>${escapeHTML(c.nom+" "+c.prenom)}</div></td><td>${safe(c.posteSouhaite)}</td><td><span class="pill pill-indigo">${safe(c.societe)}</span></td><td><span class="pill ${v===9?"pill-green":"pill-amber"}">${v}/9</span></td><td class="text-right">${candidateBlackListMatch(c)?`<span class="pill" style="background:#111827;color:#fff">⛔ BLACKLIST</span>`:`<a class="btn btn-primary text-xs" href="#/contrats/nouveau/${c.id}">Contractualiser →</a>`}</td></tr>`}).join("")}</tbody></table></div>`}`;
    return;
  }
  const agents=db.agents.filter(a=>a.statut!=="archive"&&(!socFilter||a.societe===socFilter));
  const today_=today();
  const byType={};agents.forEach(a=>{const t=a.typeContrat||"—";byType[t]=(byType[t]||0)+1});
  const essaiEnCours=agents.filter(a=>{if(!a.dateFinEssai)return false;const d=daysBetween(today_,a.dateFinEssai);return d>=0}).length;
  const essaiBientot=agents.filter(a=>{if(!a.dateFinEssai)return false;const d=daysBetween(today_,a.dateFinEssai);return d>=0&&d<=30}).length;
  const essaiAlertes=agents.filter(a=>{if(!a.dateFinEssai)return false;const d=daysBetween(today_,a.dateFinEssai);return d>=0&&d<=30}).sort((a,b)=>String(a.dateFinEssai||"").localeCompare(String(b.dateFinEssai||"")));
  const cddBientot=agents.filter(a=>{if(a.typeContrat!=="CDD"||!a.dateFinContrat)return false;const d=daysBetween(today_,a.dateFinContrat);return d>=0&&d<=60}).length;
  const masseSal=agents.reduce((s,a)=>s+(parseFloat(a.salaireNet)||0),0);
  view.innerHTML=`<h1 class="text-2xl font-bold mb-2">📑 Situation contrat (personnel)</h1><p class="text-slate-500 text-sm mb-6">Analyse des contrats de travail des agents${socFilter?` · <span class="font-semibold text-amber-700">${escapeHTML(socFilter)}</span>`:""} — <span id="ct-total">${agents.length}</span> agent(s).</p>
    <div class="grid grid-4 mb-6">
      <button type="button" class="card p-4 text-left kpi-clickable" onclick="setContratQuickFilter('total')"><div class="text-xs text-slate-500 uppercase">Effectif total</div><div class="text-2xl font-bold mt-1">${agents.length}</div><div class="text-xs text-slate-400 mt-1">${Object.entries(byType).map(([t,n])=>`${t}: ${n}`).join(" • ")||"—"}</div></button>
      <button type="button" class="card p-4 text-left kpi-clickable" onclick="setContratQuickFilter('essai')"><div class="text-xs text-slate-500 uppercase">Période d'essai</div><div class="text-2xl font-bold mt-1">${essaiEnCours}</div><div class="text-xs ${essaiBientot>0?"text-red-600":"text-slate-400"} mt-1">${essaiBientot} se termine(nt) sous 30 j</div></button>
      <button type="button" class="card p-4 text-left kpi-clickable" onclick="setContratQuickFilter('cdd')"><div class="text-xs text-slate-500 uppercase">CDD bientôt expirés</div><div class="text-2xl font-bold mt-1">${cddBientot}</div><div class="text-xs text-slate-400 mt-1">≤ 60 jours</div></button>
      <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Masse salariale (net)</div><div class="text-2xl font-bold mt-1">${money(masseSal)}</div><div class="text-xs text-slate-400 mt-1">par mois</div></div>
    </div>
    ${essaiAlertes.length?`<div class="card p-4 mb-4" style="background:#fef2f2;border:2px solid #dc2626">
      <div class="flex items-center justify-between gap-3">
        <div class="flex items-center gap-3">
          <span class="red-blink-dot"></span>
          <div><div class="font-black text-red-700 uppercase">Alerte fin de période d'essai</div><div class="text-xs text-red-700">${essaiAlertes.length} employé(s) concerné(s) dans les 30 jours</div></div>
        </div>
        <button class="btn btn-danger text-xs" onclick="setContratQuickFilter('essai30')">Voir la liste</button>
      </div>
      <div class="grid grid-cols-1 md:grid-cols-2 gap-2 mt-3">${essaiAlertes.slice(0,4).map(a=>{const d=daysBetween(today_,a.dateFinEssai);return`<a href="#/effectif/agent/${a.id}" class="p-3 rounded-lg text-sm block" style="background:#fff;border:1px solid #fecaca;text-decoration:none;color:#0f172a"><div class="flex justify-between gap-2"><b>${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</b><span class="pill pill-red">J-${d}</span></div><div class="text-xs text-slate-500 mt-1">${escapeHTML(a.matricule||"—")} · Fin essai : ${formatDate(a.dateFinEssai)}</div></a>`}).join("")}</div>
    </div>`:""}
    <div class="card p-4 mb-4">
      <div class="flex items-center justify-between mb-3"><h3 class="font-semibold text-sm">🔎 Filtres</h3><div class="text-xs text-slate-500"><span id="ct-shown">${agents.length}</span> / ${agents.length} agents affichés</div></div>
      <div class="grid grid-4 gap-3 mb-3">
        <div><label class="label">Fin d'essai — préréglage</label><select id="flt-essai" class="select" onchange="applyContratFilters()"><option value="">Tous</option><option value="passed">Terminée</option><option value="upcoming">À venir (toutes)</option><option value="30">≤ 30 jours</option><option value="60">≤ 60 jours</option><option value="90">≤ 90 jours</option><option value="none">Sans date</option></select></div>
        <div><label class="label">Fin d'essai — du</label><input id="flt-essai-du" type="date" class="input" oninput="applyContratFilters()"/></div>
        <div><label class="label">Fin d'essai — au</label><input id="flt-essai-au" type="date" class="input" oninput="applyContratFilters()"/></div>
        <div></div>
        <div><label class="label">Fin de contrat — préréglage</label><select id="flt-contrat" class="select" onchange="applyContratFilters()"><option value="">Tous</option><option value="passed">Expiré</option><option value="upcoming">À venir (tous)</option><option value="30">≤ 30 jours</option><option value="60">≤ 60 jours</option><option value="90">≤ 90 jours</option><option value="none">Sans date</option></select></div>
        <div><label class="label">Fin de contrat — du</label><input id="flt-contrat-du" type="date" class="input" oninput="applyContratFilters()"/></div>
        <div><label class="label">Fin de contrat — au</label><input id="flt-contrat-au" type="date" class="input" oninput="applyContratFilters()"/></div>
        <div class="flex items-end"><button type="button" class="btn btn-ghost w-full" onclick="resetContratFilters()">↺ Réinitialiser</button></div>
      </div>
    </div>
    <div class="card overflow-hidden"><table>
    <thead><tr><th>Agent</th><th>Matricule</th><th>Société</th><th>Type</th><th>Recrutement</th><th>Fin d'essai</th><th>Fin contrat</th><th>Salaire net</th><th>Statut</th></tr></thead>
    <tbody id="ct-tbody">${agents.length===0?`<tr><td colspan="9" class="text-center text-slate-500 p-6">Aucun agent.</td></tr>`:agents.map(a=>{
      let essaiCell="—";
      if(a.dateFinEssai){const d=daysBetween(today_,a.dateFinEssai);
        if(d<0)essaiCell=`<span class="pill pill-gray">terminée</span>`;
        else if(d<=30)essaiCell=`<span class="pill pill-red">${formatDate(a.dateFinEssai)} (${d} j)</span>`;
        else essaiCell=`<span class="pill pill-green">${formatDate(a.dateFinEssai)}</span>`;
      }
      let contratCell="—";
      if(a.dateFinContrat){const d=daysBetween(today_,a.dateFinContrat);
        if(d<0)contratCell=`<span class="pill pill-gray">expiré</span>`;
        else if(d<=60)contratCell=`<span class="pill pill-red">${formatDate(a.dateFinContrat)} (${d} j)</span>`;
        else contratCell=`<span class="pill pill-green">${formatDate(a.dateFinContrat)}</span>`;
      } else if(a.typeContrat==="CDI"){contratCell=`<span class="pill pill-blue">CDI</span>`}
      const tCl=a.typeContrat==="CDI"?"pill-green":a.typeContrat==="CDD"?"pill-amber":"pill-blue";
      const stCl=a.statut==="actif"?"pill-green":a.statut==="absent"||a.statut==="suspendu"?"pill-red":"pill-gray";
      return`<tr data-row data-finessai="${a.dateFinEssai||""}" data-fincontrat="${a.dateFinContrat||""}" data-typecontrat="${escapeHTML(a.typeContrat||"")}" data-searchable><td><a class="font-semibold hover:underline" href="#/effectif/agent/${a.id}">${escapeHTML(a.nom+" "+a.prenom)}</a></td><td class="font-mono text-xs">${safe(a.matricule)}</td><td><span class="pill pill-indigo">${safe(a.societe)}</span></td><td><span class="pill ${tCl}">${safe(a.typeContrat)}</span></td><td class="text-xs">${formatDate(a.dateRecrutement)}</td><td class="text-xs">${essaiCell}</td><td class="text-xs">${contratCell}</td><td>${a.salaireNet?money(a.salaireNet):"—"}</td><td><span class="pill ${stCl}">${safe(a.statut)}</span></td></tr>`}).join("")}</tbody></table></div>`;
}
function openCreateContratDirectModal(){
  const soc=currentStructureSocieteFilter()||mySoc()||sessionStorage.getItem("dashSociete")||"";
  const reserves=(db.candidats||[]).filter(c=>candidatIsReserve(c)&&(!soc||c.societe===soc));
  openModal(`<h3 class="font-bold text-lg mb-4">Créer contrat</h3>
    <form onsubmit="event.preventDefault();startContractFromReserve(this.candidatId.value)">
      <label class="label">Choisir société</label>
      <select class="select mb-3" name="societe" onchange="setCurrentStructureSocieteFilter(this.value)">
        <option value="">Toutes les sociétés</option>
        ${SOCIETES.map(s=>`<option value="${escapeHTML(s)}" ${soc===s?"selected":""}>${escapeHTML(s)}</option>`).join("")}
      </select>
      <label class="label">Candidat en réserve</label>
      <select class="select" name="candidatId" autofocus>
        <option value="">— Choisir un candidat —</option>
        ${reserves.map(c=>`<option value="${c.id}">${escapeHTML((c.nom||"")+" "+(c.prenom||""))} · ${escapeHTML(c.nin||"NIN non renseigné")} · ${escapeHTML(c.societe||"")}</option>`).join("")}
      </select>
      ${reserves.length?`<div class="text-xs text-slate-500 mt-2">${reserves.length} candidat(s) en réserve${soc?` · ${escapeHTML(soc)}`:""}.</div>`:`<div class="text-sm text-red-700 mt-3">Aucun candidat en réserve${soc?` pour ${escapeHTML(soc)}`:""}.</div>`}
      <div class="flex justify-end gap-2 mt-4">
        <button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button>
        <button class="btn btn-primary" ${reserves.length?"":"disabled"}>Continuer contrat</button>
      </div>
    </form>`);
}
function startContractFromReserve(id){
  if(!id){toast("Choisissez un candidat en réserve","error");return}
  const c=findCandidatById(id);
  if(!c){toast("Candidat introuvable","error");return}
  c.statut="a_contractualiser";
  c.updatedAt=new Date().toISOString();
  saveDB();closeModal();navigate(`contrats/nouveau/${c.id}`);
}
function applyContratFilters(){
  const fe=document.getElementById("flt-essai")?.value||"";
  const fc=document.getElementById("flt-contrat")?.value||"";
  const feDu=document.getElementById("flt-essai-du")?.value||"";
  const feAu=document.getElementById("flt-essai-au")?.value||"";
  const fcDu=document.getElementById("flt-contrat-du")?.value||"";
  const fcAu=document.getElementById("flt-contrat-au")?.value||"";
  const t=today();
  const rows=document.querySelectorAll("#ct-tbody tr[data-row]");
  let shown=0;
  rows.forEach(r=>{
    const e=r.dataset.finessai||"";
    const c=r.dataset.fincontrat||"";
    let ok=true;
    if(fe){
      if(fe==="none"){if(e)ok=false}
      else if(!e)ok=false;
      else{const d=daysBetween(t,e);
        if(fe==="passed"&&d>=0)ok=false;
        else if(fe==="upcoming"&&d<0)ok=false;
        else if(fe==="30"&&!(d>=0&&d<=30))ok=false;
        else if(fe==="60"&&!(d>=0&&d<=60))ok=false;
        else if(fe==="90"&&!(d>=0&&d<=90))ok=false;
      }
    }
    if(ok&&fc){
      if(fc==="none"){if(c)ok=false}
      else if(!c)ok=false;
      else{const d=daysBetween(t,c);
        if(fc==="passed"&&d>=0)ok=false;
        else if(fc==="upcoming"&&d<0)ok=false;
        else if(fc==="30"&&!(d>=0&&d<=30))ok=false;
        else if(fc==="60"&&!(d>=0&&d<=60))ok=false;
        else if(fc==="90"&&!(d>=0&&d<=90))ok=false;
      }
    }
    if(ok&&feDu&&(!e||e<feDu))ok=false;
    if(ok&&feAu&&(!e||e>feAu))ok=false;
    if(ok&&fcDu&&(!c||c<fcDu))ok=false;
    if(ok&&fcAu&&(!c||c>fcAu))ok=false;
    r.classList.toggle("hidden",!ok);
    if(ok)shown++;
  });
  const sh=document.getElementById("ct-shown");if(sh)sh.textContent=shown;
}
function resetContratFilters(){["flt-essai","flt-contrat","flt-essai-du","flt-essai-au","flt-contrat-du","flt-contrat-au"].forEach(id=>{const el=document.getElementById(id);if(el)el.value=""});applyContratFilters()}
function setContratQuickFilter(type){
  resetContratFilters();
  if(type==="essai"){
    const e=document.getElementById("flt-essai");if(e)e.value="upcoming";
  }else if(type==="essai30"){
    const e=document.getElementById("flt-essai");if(e)e.value="30";
  }else if(type==="cdd"){
    const c=document.getElementById("flt-contrat");if(c)c.value="60";
  }
  applyContratFilters();
  const table=document.getElementById("ct-tbody");if(table)table.scrollIntoView({behavior:"smooth",block:"start"});
}

function contratPersonnelByPoste(poste){ensureContratsPersonnel();return (db.contratsPersonnel||[]).find(c=>c.actif!==false&&c.poste===poste)||null}
function contratPersonnelOptions(selectedId,poste){
  ensureContratsPersonnel();
  const list=(db.contratsPersonnel||[]).filter(c=>c.actif!==false);
  return `<option value="">— Aucun modèle —</option>`+list.map(c=>`<option value="${c.id}" ${(selectedId===c.id||(!selectedId&&poste&&c.poste===poste))?"selected":""}>${escapeHTML(c.titre||c.poste)} — ${escapeHTML(c.poste||"")}</option>`).join("");
}
function updateContratPersonnelPreview(){
  const f=document.getElementById("contract-form");if(!f)return;
  const poste=f.querySelector('[name="posteContrat"]')?.value||"";
  const sel=f.querySelector('[name="contratPersonnelId"]');
  if(!sel)return;
  if(poste){
    const auto=contratPersonnelByPoste(poste);
    if(auto&&!sel.value)sel.value=auto.id;
  }
  const c=(db.contratsPersonnel||[]).find(x=>x.id===sel.value);
  const title=document.getElementById("contrat-personnel-title");
  const prev=document.getElementById("contrat-personnel-preview");
  if(title)title.textContent=c?c.titre:"Aucun contrat spécifique sélectionné";
  if(prev)prev.textContent=c?c.texte:"Sélectionnez un poste ou un modèle dans Administration Système.";
}
function contratDureeOptions(selected){
  return `<option value="">— Choisir —</option>`+DUREES_CONTRAT.map(d=>`<option value="${d.value}" ${selected===d.value?"selected":""}>${d.label}</option>`).join("");
}
function contractEndDate(start,duration){
  if(!start||!duration)return "";
  if(duration==="15d")return addDays(start,15);
  const months=parseInt(duration,10);
  if(!months)return "";
  const d=new Date(start+"T00:00:00");
  d.setMonth(d.getMonth()+months);
  return d.toISOString().slice(0,10);
}
function updateContractEndDate(){
  const f=document.getElementById("contract-form");if(!f)return;
  const start=f.querySelector('[name="dateRecrutement"]')?.value||today();
  const duration=f.querySelector('[name="dureeContrat"]')?.value||"";
  const trialDays=parseInt(f.querySelector('[name="dureeEssai"]')?.value||"90",10)||0;
  const out=f.querySelector('[name="dateFinContrat"]');
  const trialOut=f.querySelector('[name="dateFinEssai"]');
  if(out)out.value=contractEndDate(start,duration);
  if(trialOut)trialOut.value=start&&trialDays?addDays(start,trialDays):"";
}
function fillContratPersonnelText(tpl,agent){
  return String(tpl||"")
    .replaceAll("{{nom}}",agent.nom||"")
    .replaceAll("{{prenom}}",agent.prenom||"")
    .replaceAll("{{matricule}}",agent.matricule||"")
    .replaceAll("{{societe}}",agent.societe||"")
    .replaceAll("{{dateRecrutement}}",formatDate(agent.dateRecrutement))
    .replaceAll("{{salaireNet}}",money(agent.salaireNet))
    .replaceAll("{{date}}",formatDate(today()));
}

