/* ---- MATÉRIEL & ÉQUIPEMENT ---- */
function renderAgentMateriel(a,locked){
  if(!db.materiel)db.materiel=[];
  const items=db.materiel.filter(m=>m.agentId===a.id&&m.statut==="attribue");
  const stockAttribs=(db.stockMouvements||[]).filter(m=>stockMvtIsOut(m.type)&&m.beneficiaireAgentId===a.id).slice().sort((x,y)=>(y.date||"").localeCompare(x.date||"")||(y.createdAt||"").localeCompare(x.createdAt||""));
  const allCats=[...new Set(items.map(m=>m.categorie).concat(stockAttribs.map(m=>{const art=(db.stockArticles||[]).find(a=>a.id===m.articleId);return art?art.categorie:"Stock"})).filter(Boolean))];
  const stockMvtValue=m=>{const art=(db.stockArticles||[]).find(x=>x.id===m.articleId);const pu=parseFloat(m.prixUnitaire||art?.prixUnitaire)||0;return (parseFloat(m.quantite)||0)*pu};
  const legacyValue=items.reduce((s,m)=>s+(parseFloat(m.prix)||0),0);
  const stockValue=stockAttribs.reduce((s,m)=>s+stockMvtValue(m),0);
  const totalValue=legacyValue+stockValue;
  const canEdit=!locked||isAdmin();
  const rows=agentDotationRows(a.id,{onlyActive:false});
  return`<div class="grid grid-3 mb-3">
    <div class="bg-slate-50 p-3 rounded border border-slate-200"><div class="text-xs text-slate-500 uppercase">Articles attribués</div><div class="text-2xl font-bold mt-1">${items.length+stockAttribs.length}</div><div class="text-[11px] text-slate-500 mt-1">${items.length} ancien stock · ${stockAttribs.length} dotation(s)</div></div>
    <div class="bg-slate-50 p-3 rounded border border-slate-200"><div class="text-xs text-slate-500 uppercase">Catégories</div><div class="text-sm mt-1 flex flex-wrap gap-1">${allCats.map(c=>`<span class="pill pill-indigo">${escapeHTML(c)}</span>`).join("")||"—"}</div></div>
    <div class="bg-slate-50 p-3 rounded border border-slate-200"><div class="text-xs text-slate-500 uppercase">Valeur exacte dotation</div><div class="text-2xl font-black mt-1">${money(totalValue)}</div><div class="text-[11px] text-slate-500 mt-1">Ancien stock ${money(legacyValue)} · Stock ${money(stockValue)}</div></div>
  </div>
  <div class="card p-3 mb-3">
    <div class="flex justify-between items-center mb-2 flex-wrap gap-2"><h4 class="font-bold text-sm">Détail de la dotation</h4><div class="flex gap-2 flex-wrap"><button type="button" class="btn btn-primary text-xs" onclick="printFicheDotation('${a.id}')">Imprimer fiche de dotation</button><a href="#/materiel/mouvements" class="text-xs text-amber-600 hover:underline">Voir mouvements →</a></div></div>
    <div class="overflow-x-auto"><table><thead><tr><th>Date dotation</th><th>Code</th><th>Article</th><th>Qté</th><th>Prix unitaire</th><th>Valeur exacte</th><th>Motif</th><th>N° bon</th><th>Date reversement</th><th>Motif reversement</th></tr></thead><tbody>${rows.length===0?`<tr><td colspan="10" class="text-center text-slate-500 p-3">Aucune dotation enregistrée.</td></tr>`:rows.map(r=>`<tr><td class="text-xs">${formatDate(r.date)}</td><td class="font-mono text-xs">${escapeHTML(r.code||"—")}</td><td>${r.articleId?`<a class="font-semibold hover:underline" href="#/materiel/article/${r.articleId}">${escapeHTML(r.article)}</a>`:`<span class="font-semibold">${escapeHTML(r.article||"—")}</span>`}<div class="text-[10px] text-slate-500">${escapeHTML(r.categorie||"—")}</div></td><td class="font-bold text-center">${qty(r.qte)} <span class="text-[10px] text-slate-400">${escapeHTML(r.unite||"")}</span></td><td class="text-right text-xs">${money(r.pu)}</td><td class="text-right font-bold">${money(r.valeur)}</td><td class="text-xs">${escapeHTML(r.motif||"—")}</td><td class="font-mono text-xs">${escapeHTML(r.bon||"—")}</td><td class="text-xs">${r.dateReversement||"—"}</td><td class="text-xs">${escapeHTML(r.motifReversement||"—")}</td></tr>`).join("")}</tbody></table></div>
  </div>`;
}
function agentDotationRows(agentId,opts){
  opts=opts||{};
  const ag=(db.agents||[]).find(x=>x.id===agentId);
  const legacy=(db.materiel||[]).filter(m=>m.agentId===agentId&&(opts.onlyActive?m.statut==="attribue":true)).map(m=>({date:m.dateAttribution,code:m.code,article:m.designation,categorie:m.categorie,qte:1,unite:"Pièce",pu:parseFloat(m.prix)||0,valeur:parseFloat(m.prix)||0,motif:m.notes||"Dotation matériel",bon:"—",dateReversement:m.dateRetour||"",motifReversement:m.dateRetour?(m.notes||"Retour matériel"):"",detail:"",articleId:""}));
  const stockOut=(db.stockMouvements||[]).filter(m=>stockMvtIsOut(m.type)&&m.beneficiaireAgentId===agentId);
  const rows=stockOut.map(m=>{
    const art=(db.stockArticles||[]).find(x=>x.id===m.articleId);
    const pu=parseFloat(m.prixUnitaire||art?.prixUnitaire)||0;
    const returned=(db.stockMouvements||[]).filter(r=>stockMvtIsIn(r.type)&&stockMvtIsRetourAgent(r.motif)&&r.retourAgentId===agentId&&r.articleId===m.articleId&&(!m.date||!r.date||r.date>=m.date));
    const returnedQty=returned.reduce((s,r)=>s+(parseFloat(r.quantite)||0),0);
    const initialQty=parseFloat(m.quantite)||0;
    const remaining=Math.max(0,initialQty-returnedQty);
    if(opts.onlyActive&&remaining<=0)return null;
    const q=opts.onlyActive?remaining:initialQty;
    const rep=m.repartitionTailles||{};
    const detail=Object.keys(rep).length?Object.entries(rep).map(([k,v])=>`${k}: ${qty(v)}`).join(" / "):"";
    return{date:m.date,code:art?.code||"—",article:art?.designation||"Article supprimé",categorie:art?.categorie||"Stock",articleId:m.articleId,qte:q,unite:art?.unite||"",pu,valeur:q*pu,motif:[stockMvtTypeLabel(m.type),m.motif,m.motifRenouvellement,m.motifRenouvellementPrecision].filter(Boolean).join(" · "),bon:m.numeroBon||"—",dateReversement:returned.map(r=>formatDate(r.date)).join(", "),motifReversement:returned.map(r=>[r.motif,qty(r.quantite)+(art?.unite?` ${art.unite}`:"")].filter(Boolean).join(" · ")).join(" / "),detail};
  }).filter(Boolean);
  return legacy.concat(rows).sort((x,y)=>(y.date||"").localeCompare(x.date||""));
}
function ficheDotationHTML(agentId){
  const a=(db.agents||[]).find(x=>x.id===agentId);if(!a)return"<div>Employé introuvable</div>";
  const rows=agentDotationRows(agentId,{onlyActive:true});
  const total=rows.reduce((s,r)=>s+(parseFloat(r.valeur)||0),0);
  const bon=rows.find(r=>r.bon&&r.bon!=="—")?.bon||nextStockBonNum("sortie");
  const aff=a.affectationCourante||{};
  return`<div class="dotation-print">
    <div class="doc-head">
      <div><h1>FICHE DE DOTATION PERSONNEL</h1><div class="muted">${escapeHTML(a.societe||"")} · Matériel & Équipement</div></div>
      <div class="doc-ref"><div>${escapeHTML(bon)}</div><small>${formatDate(today())}</small></div>
    </div>
    <table class="info-table">
      <tr><td>Nom et prénom</td><td><b>${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</b></td><td>Matricule</td><td><b>${safe(a.matricule)}</b></td></tr>
      <tr><td>Fonction / Poste</td><td>${safe(a.fonction||aff.poste)}</td><td>Site</td><td>${safe(aff.siteName)}</td></tr>
      <tr><td>Société</td><td>${safe(a.societe)}</td><td>Date recrutement</td><td>${formatDate(a.dateRecrutement)}</td></tr>
    </table>
    <h2>Équipements dotés au personnel</h2>
    <table class="items-table">
      <thead><tr><th>N°</th><th>Date</th><th>Code</th><th>Désignation</th><th>Catégorie</th><th>Détail taille/pointure</th><th>Qté</th><th>P.U.</th><th>Valeur</th><th>N° bon</th></tr></thead>
      <tbody>${rows.length?rows.map((r,i)=>`<tr><td>${i+1}</td><td>${formatDate(r.date)}</td><td>${escapeHTML(r.code||"—")}</td><td><b>${escapeHTML(r.article||"—")}</b></td><td>${escapeHTML(r.categorie||"—")}</td><td>${escapeHTML(r.detail||"—")}</td><td class="num">${qty(r.qte)} ${escapeHTML(r.unite||"")}</td><td class="num">${money(r.pu)}</td><td class="num">${money(r.valeur)}</td><td>${escapeHTML(r.bon||"—")}</td></tr>`).join(""):`<tr><td colspan="10" style="text-align:center;color:#64748b;padding:18px">Aucune dotation active enregistrée.</td></tr>`}</tbody>
      <tfoot><tr><td colspan="8" class="num">Valeur totale de la dotation</td><td class="num"><b>${money(total)}</b></td><td></td></tr></tfoot>
    </table>
    <div class="engagement">
      <h2>Engagement du bénéficiaire</h2>
      <p>Je soussigné(e), <b>${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</b>, reconnais avoir reçu les équipements listés ci-dessus en bon état apparent et m'engage à les utiliser exclusivement dans le cadre professionnel.</p>
      <p>Je m'engage à préserver ce matériel, à le restituer sur demande de l'entreprise ou lors de mon départ, et à signaler immédiatement toute perte, vol, casse, détérioration ou anomalie. En cas de perte, vol, dégradation volontaire, négligence ou non-restitution, j'accepte que ma responsabilité soit engagée conformément au règlement intérieur et aux procédures applicables de l'entreprise.</p>
      <div class="checks"><label><span></span> Matériel reçu en bon état</label><label><span></span> Engagement lu et accepté</label><label><span></span> Restitution obligatoire en fin de mission/contrat</label></div>
    </div>
    <div class="signatures">
      <div><b>Signature du bénéficiaire</b><br/><small>Nom, date et signature précédés de la mention "Lu et approuvé"</small><div class="sig-box"></div></div>
      <div><b>Responsable matériel</b><br/><small>Nom, date, cachet et signature</small><div class="sig-box"></div></div>
      <div><b>Administration / RH</b><br/><small>Contrôle et validation</small><div class="sig-box"></div></div>
    </div>
  </div>`;
}
