function openAttribuerToAgentModal(agentId){
  const a=db.agents.find(x=>x.id===agentId);if(!a)return;
  const stock=db.materiel.filter(m=>m.statut==="en_stock");
  if(stock.length===0){toast("Aucun article disponible en stock","error");return}
  openModal(`<h3 class="font-bold text-lg mb-4">➕ Attribuer un matériel à ${escapeHTML(a.nom+" "+a.prenom)}</h3>
    <form onsubmit="event.preventDefault();confirmAttribuerToAgent('${agentId}')">
      <div class="grid grid-2">
        <div class="col-span-2"><label class="label">Article disponible *</label><select class="select" name="materielId" ><option value="">— Choisir —</option>${stock.map(m=>`<option value="${m.id}">${safe(m.code)} — ${escapeHTML(m.categorie)} — ${escapeHTML(m.designation)} ${m.numeroSerie?"["+escapeHTML(m.numeroSerie)+"]":""}</option>`).join("")}</select></div>
        <div><label class="label">Date d'attribution</label><input class="input" type="date" name="dateAttribution" value="${today()}" /></div>
        <div><label class="label">État au moment</label><select class="select" name="etat">${ETATS_MATERIEL.map(e=>`<option>${e}</option>`).join("")}</select></div>
        <div class="col-span-2"><label class="label">Notes</label><input class="input" name="notes" placeholder="Accessoires inclus, remarques..."/></div>
      </div>
      <div class="flex justify-end gap-2 mt-4"><button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button><button class="btn btn-primary">Confirmer attribution</button></div>
    </form>`)
}
function confirmAttribuerToAgent(agentId){
  const f=document.querySelector(".modal-bg form");const fd=new FormData(f);
  const matId=fd.get("materielId");const m=db.materiel.find(x=>x.id===matId);if(!m)return;
  const a=db.agents.find(x=>x.id===agentId);if(!a)return;
  m.agentId=agentId;m.statut="attribue";m.dateAttribution=fd.get("dateAttribution")||today();m.dateRetour=null;m.etat=fd.get("etat")||m.etat;
  if(!m.societe)m.societe=a.societe;
  if(fd.get("notes"))m.notes=(m.notes?m.notes+" | ":"")+"Attribution: "+fd.get("notes");
  saveDB();closeModal();toast("Matériel attribué","success");renderView();
}
function statutMatPill(s){return{"en_stock":"pill-green","attribue":"pill-blue","en_reparation":"pill-amber","perdu":"pill-red","reforme":"pill-gray"}[s]||"pill-gray"}
function statutMatLabel(s){return{"en_stock":"En stock","attribue":"Attribué","en_reparation":"En réparation","perdu":"Perdu","reforme":"Réformé"}[s]||s}
function etatMatPill(e){return{"Neuf":"pill-green","Bon état":"pill-blue","Usé":"pill-amber","Hors service":"pill-red"}[e]||"pill-gray"}
function nextMatCode(cat){const prefix={"Uniforme":"UN","Chaussures":"CH","Casquette":"CP","Insigne":"IN","Badge":"BD","Talkie-walkie":"TW","Téléphone":"TP","Bâton télescopique":"BT","Menottes":"MN","Lampe torche":"LM","Sifflet":"SF","Détecteur de métaux":"DM","Veste pare-balles":"VP","Imperméable":"IM","Brassard":"BR","Véhicule":"VH","Vélo":"VL","Ordinateur":"OR","Tablette":"TB","Caméra-piéton":"CM","Trousse 1ers secours":"TS","Autre":"AU"}[cat]||"AU";const n=db.materiel.filter(m=>m.code&&m.code.startsWith(prefix+"-")).length+1;return prefix+"-"+String(n).padStart(3,"0")}
function renderMaterielStats(view){
  const all=db.materiel||[];
  const socColors={};
  const total=all.length;
  const enStock=all.filter(m=>m.statut==="en_stock").length;
  const attribues=all.filter(m=>m.statut==="attribue").length;
  const enRep=all.filter(m=>m.statut==="en_reparation").length;
  const reformes=all.filter(m=>m.statut==="reforme").length;
  const perdus=all.filter(m=>m.statut==="perdu").length;
  const valeur=all.reduce((s,m)=>s+(parseFloat(m.prix)||0),0);
  const parSoc=SOCIETES.map(s=>({s,n:all.filter(m=>m.societe===s).length,v:all.filter(m=>m.societe===s).reduce((sum,m)=>sum+(parseFloat(m.prix)||0),0)}));
  const parType={};all.forEach(m=>{const k=m.type||m.categorie||"Non précisé";if(!parType[k])parType[k]={n:0,v:0};parType[k].n++;parType[k].v+=parseFloat(m.prix)||0});
  const parEtat={};all.forEach(m=>{const k=m.etat||"Non précisé";parEtat[k]=(parEtat[k]||0)+1});
  const bars=(entries,color)=>{const max=Math.max(1,...entries.map(e=>e[1]));if(!entries.length)return`<div class="text-sm text-slate-400">Aucune donnée.</div>`;return entries.sort((a,b)=>b[1]-a[1]).map(([k,n])=>{const pct=Math.round(n/max*100);return`<div class="text-sm mb-2"><div class="flex justify-between mb-1"><span class="font-medium">${escapeHTML(String(k||"—"))}</span><span class="text-slate-500">${n}</span></div><div class="h-2 bg-slate-100 rounded-full"><div class="h-full rounded-full" style="width:${pct}%;background:${color}"></div></div></div>`}).join("")};
  view.innerHTML=`<h1 class="text-2xl font-bold mb-2">📈 Matériel — Statistiques</h1>
    <div class="flex gap-2 mb-4 flex-wrap">
      <a href="#/materiel/inventaire" class="btn btn-ghost text-sm">📦 Situation</a>
      <a href="#/materiel/attributions" class="btn btn-ghost text-sm">🎽 Attributions</a>
      <a href="#/materiel/retours" class="btn btn-ghost text-sm">↩ Retours</a>
      <a href="#/materiel/stats" class="btn btn-primary text-sm">📈 Statistiques</a>
    </div>
    <div class="grid grid-cols-2 md:grid-cols-6 gap-3 mb-4">
      <div class="card p-4"><div class="text-xs text-slate-500">Articles total</div><div class="text-2xl font-bold">${total}</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500">En stock</div><div class="text-2xl font-bold text-emerald-700">${enStock}</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500">Attribués</div><div class="text-2xl font-bold text-blue-700">${attribues}</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500">En réparation</div><div class="text-2xl font-bold text-amber-700">${enRep}</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500">Réformés</div><div class="text-2xl font-bold text-slate-700">${reformes}</div></div>
      <div class="card p-4"><div class="text-xs text-slate-500">Perdus</div><div class="text-2xl font-bold text-red-700">${perdus}</div></div>
    </div>
    <div class="grid grid-cols-2 gap-4 mb-4">
      <div class="card p-5"><h3 class="font-bold mb-3">Articles par société</h3>${bars(parSoc.map(r=>[r.s,r.n]),"#043970")}</div>
      <div class="card p-5"><h3 class="font-bold mb-3">Articles par type</h3>${bars(Object.entries(parType).map(([k,v])=>[k,v.n]),"#8b5cf6")}</div>
      <div class="card p-5"><h3 class="font-bold mb-3">Articles par état</h3>${bars(Object.entries(parEtat),"#043970")}</div>
      <div class="card p-5"><h3 class="font-bold mb-3">Articles par statut</h3>${bars([["En stock",enStock],["Attribué",attribues],["En réparation",enRep],["Réformé",reformes],["Perdu",perdus]],"#043970")}</div>
    </div>
    <div class="card p-0 overflow-x-auto">
      <table class="w-full text-sm">
        <thead class="bg-slate-50"><tr><th class="text-left p-3">Société</th><th class="p-3">Nb articles</th></tr></thead>
        <tbody>${parSoc.map(r=>`<tr class="border-t"><td class="p-3 font-semibold">${escapeHTML(r.s)}</td><td class="p-3 text-center">${r.n}</td></tr>`).join("")}
        <tr class="border-t bg-slate-50 font-bold"><td class="p-3">TOTAL</td><td class="p-3 text-center">${total}</td></tr></tbody>
      </table>
    </div>`;
}
function renderMateriel(view,sub,arg){
  if(!db.materiel)db.materiel=[];
  if(!db.magasins)db.magasins=[];
  if(!db.magasinArticles)db.magasinArticles=[];
  if(!db.stockArticles)db.stockArticles=[];
  if(!db.stockMouvements)db.stockMouvements=[];
  if(!db.fournisseurs)db.fournisseurs=[];
  matNormalizeRelations();
  // Simple module routes (new architecture)
  if(!sub||sub==="dashboard"){return renderMatSimpleDashboard(view)}
  if(sub==="fiches"){try{sessionStorage.setItem("ficheContext","materiel")}catch(e){}return renderFiches(view,"toutes")}
  if(sub==="fiche"&&arg){try{sessionStorage.setItem("ficheContext","materiel")}catch(e){}return renderAgentForm(view,arg)}
  if(sub==="inventaire"){return renderMatSimpleInventaire(view)}
  if(sub==="articles"||sub==="catalogue"){return renderMatSimpleArticles(view)}
  if(sub==="magasins"){return renderMatSimpleMagasins(view)}
  if(sub==="magasin"&&arg){return renderMatSimpleMagasinDetail(view,arg)}
  if(sub==="magasin-nouveau"){return renderMatSimpleMagasinForm(view,null)}
  if(sub==="magasin-edit"&&arg){return renderMatSimpleMagasinForm(view,arg)}
  if(sub==="entree-stock"){renderMatSimpleMouvements(view);setTimeout(()=>stockOpenMvt("entree"),0);return}
  if(sub==="sortie-stock"){renderMatSimpleMouvements(view);setTimeout(()=>stockOpenMvt("sortie"),0);return}
  if(sub==="fournisseurs"){return renderMatSimpleFournisseurs(view)}
  if(sub==="fournisseur"&&arg){return renderMatSimpleFournisseurDetail(view,arg)}
  if(sub==="fournisseur-nouveau"){return renderMatSimpleFournisseurForm(view,null)}
  if(sub==="fournisseur-edit"&&arg){return renderMatSimpleFournisseurForm(view,arg)}
  if(sub==="dotation"){return renderMatSimpleDotation(view)}
  if(sub==="reversement"){return renderMatSimpleReversement(view)}
  // Stock pro routes (still available for article detail & forms)
  if(sub==="article"&&arg){return renderStockArticleDetail(view,arg)}
  if(sub==="article-nouveau"){return renderStockArticleForm(view,null)}
  if(sub==="article-edit"&&arg){return renderStockArticleForm(view,arg)}
  if(sub==="mouvements"){return renderMatSimpleMouvements(view)}
  // Legacy unitaire routes (kept)
  if(sub==="nouveau"){return renderMaterielForm(view,null)}
  if(sub==="edit"&&arg){return renderMaterielForm(view,arg)}
  if(sub==="stats"||sub==="statistiques"||sub==="alertes"||sub==="entrees"||sub==="sorties"||sub==="attributions"||sub==="retours"){return renderMatSimpleArticles(view)}
  // Default
  return renderMatSimpleDashboard(view);
}

// =====================================================================
// MATERIEL & EQUIPEMENT — MODULE SIMPLE
// Architecture : Dashboard + Articles + Magasins + Fournisseurs
// =====================================================================

const MAT_SIMPLE_HEADER_COLOR="#043970";
function matNormalizeRelations(){
  try{
    const fournisseursById=new Map((db.fournisseurs||[]).map(f=>[f.id,f]));
    const magasinsById=new Map((db.magasins||[]).map(m=>[m.id,m]));
    const articlesById=new Map((db.stockArticles||[]).map(a=>[a.id,a]));
    (db.stockArticles||[]).forEach(a=>{
      if(a.fournisseurId&&fournisseursById.has(a.fournisseurId))a.fournisseur=fournisseursById.get(a.fournisseurId).raisonSociale||a.fournisseur||"";
      if(a.magasinId&&magasinsById.has(a.magasinId))a.magasin=magasinsById.get(a.magasinId).nom||a.magasin||"";
      if(Array.isArray(a.stockReceptionsGlobales)&&a.stockReceptionsGlobales.length){
        a.quantiteGlobaleRecue=stockGlobalStockTotal(a.stockReceptionsGlobales);
        const flatDetails=a.stockReceptionsGlobales.flatMap(r=>Array.isArray(r.details)?r.details:[]);
        if(flatDetails.length)a.stockVariantes=flatDetails;
        if(!parseFloat(a.stockInitial))a.stockInitial=a.quantiteGlobaleRecue;
      }
      if(!a.designation)a.designation=a.sousCategorie||stockGetCategorie(a.societe,a.categorie).label||a.code||"Article";
    });
    (db.stockMouvements||[]).forEach(m=>{
      const a=articlesById.get(m.articleId);
      if(a){
        m.societe=m.societe||a.societe||"";
        m.articleCode=m.articleCode||a.code||"";
        m.articleDesignation=m.articleDesignation||a.designation||"";
        if(!m.prixUnitaire&&a.prixUnitaire)m.prixUnitaire=a.prixUnitaire;
      }
      if(m.fournisseurId&&fournisseursById.has(m.fournisseurId))m.fournisseur=fournisseursById.get(m.fournisseurId).raisonSociale||m.fournisseur||"";
    });
  }catch(err){console.warn("matNormalizeRelations",err)}
}
function matSimpleSocFilter(){return mySoc()||(session?.transverse?currentStructureSocieteFilter():sessionStorage.getItem("mtSociete"))||""}
function matSimpleSetSoc(v){if(mySoc()){toast("Vous êtes sur "+mySoc()+". Utilisez Changer de société.","error");return}sessionStorage.setItem("mtSociete",v||"");render()}
function matSimpleBySoc(arr){const s=matSimpleSocFilter();return s?arr.filter(x=>x.societe===s||!x.societe):arr.slice()}
function agentDotationCount(agentId){
  const legacy=(db.materiel||[]).filter(m=>m.agentId===agentId&&m.statut==="attribue").length;
  const stock=(db.stockMouvements||[]).filter(m=>typeof stockMvtIsOut==="function"&&stockMvtIsOut(m.type)&&m.beneficiaireAgentId===agentId).length;
  return legacy+stock;
}
function agentsEnInstanceDotation(){
  const soc=matSimpleSocFilter();
  return (db.agents||[]).filter(a=>a.statut==="actif"&&(!soc||a.societe===soc)&&agentDotationCount(a.id)===0);
}
function isAgentSortant(a){return a&&["sortant","demissionne","licencie","archive"].includes(a.statut)}
function agentReversementSituation(agentId){
  const legacy=(db.materiel||[]).filter(m=>m.agentId===agentId&&m.statut==="attribue");
  const mvts=db.stockMouvements||[];
  const rows={};
  mvts.filter(m=>stockMvtIsOut(m.type)&&m.beneficiaireAgentId===agentId).forEach(m=>{
    const art=(db.stockArticles||[]).find(a=>a.id===m.articleId);
    const k=m.articleId||"unknown";
    if(!rows[k])rows[k]={articleId:m.articleId,code:art?.code||"—",designation:art?.designation||"Article supprimé",unite:art?.unite||"",prixUnitaire:parseFloat(m.prixUnitaire||art?.prixUnitaire)||0,qteSortie:0,qteRetour:0,date:m.date||""};
    rows[k].qteSortie+=parseFloat(m.quantite)||0;
    if((m.date||"")>(rows[k].date||""))rows[k].date=m.date||"";
  });
  mvts.filter(m=>stockMvtIsIn(m.type)&&stockMvtIsRetourAgent(m.motif)&&m.retourAgentId===agentId).forEach(m=>{
    const k=m.articleId||"unknown";
    if(!rows[k]){
      const art=(db.stockArticles||[]).find(a=>a.id===m.articleId);
      rows[k]={articleId:m.articleId,code:art?.code||"—",designation:art?.designation||"Article supprimé",unite:art?.unite||"",prixUnitaire:parseFloat(m.prixUnitaire||art?.prixUnitaire)||0,qteSortie:0,qteRetour:0,date:""};
    }
    rows[k].qteRetour+=parseFloat(m.quantite)||0;
  });
  const stock=Object.values(rows).map(r=>({...r,qteRestante:Math.max(0,(r.qteSortie||0)-(r.qteRetour||0)),valeur:Math.max(0,(r.qteSortie||0)-(r.qteRetour||0))*(parseFloat(r.prixUnitaire)||0)})).filter(r=>r.qteRestante>0);
  const legacyValue=legacy.reduce((s,m)=>s+(parseFloat(m.prix)||0),0);
  const stockValue=stock.reduce((s,r)=>s+r.valeur,0);
  return{legacy,stock,count:legacy.length+stock.length,qty:legacy.length+stock.reduce((s,r)=>s+r.qteRestante,0),value:legacyValue+stockValue};
}
function agentsEnInstanceReversement(){
  const soc=matSimpleSocFilter();
  return (db.agents||[]).filter(a=>isAgentSortant(a)&&(!soc||a.societe===soc)&&agentReversementSituation(a.id).count>0);
}

function matSimpleHeader(active){
  // Navigation centralisée dans la barre latérale gauche.
  return "";
}

// ---- Helpers stock par magasin
function matSimpleStockMagasin(magasinId){
  // Articles dans ce magasin + valeur stock
  const arts=(db.stockArticles||[]).filter(a=>a.magasinId===magasinId||(a.emplacement&&!a.magasinId&&a.magasinIdAlias===magasinId));
  let totalQty=0,totalVal=0,nbAlertes=0;
  arts.forEach(a=>{
    const q=stockGetActuel?stockGetActuel(a.id):(parseFloat(a.stockInitial)||0);
    totalQty+=q;
    totalVal+=q*(parseFloat(a.prixUnitaire)||0);
    const seuil=parseFloat(a.seuilAlerte)||0;
    if(seuil&&q<=seuil)nbAlertes++;
  });
  return{nb:arts.length,qty:totalQty,val:totalVal,alertes:nbAlertes};
}
function matSimpleFournisseurStats(fid){
  const mvts=(db.stockMouvements||[]).filter(m=>m.type==="entree"&&m.fournisseurId===fid);
  const totalAchats=mvts.reduce((s,m)=>s+(parseFloat(m.quantite)||0)*(parseFloat(m.prixUnitaire)||0),0);
  const lastDate=mvts.length?mvts.map(m=>m.date).sort().slice(-1)[0]:"";
  return{nb:mvts.length,total:totalAchats,lastDate};
}

