function renderMagasinsList(view){
  const mags=db.magasins||[];
  const articles=db.magasinArticles||[];
  view.innerHTML=`<div class="flex items-center justify-between mb-4 flex-wrap gap-3">
      <div><h1 class="text-2xl font-bold">🏬 Magasins par thème</h1><p class="text-slate-500 text-sm">Stocks d'articles regroupés par thématique (habillement, etc.)</p></div>
      <div class="flex gap-2">
        <button class="btn btn-secondary text-xs" onclick="navigate('materiel/inventaire')">← Situation</button>
        <button class="btn btn-primary" onclick="openMagasinFormModal('')">➕ Nouveau magasin</button>
      </div>
    </div>
    ${mags.length===0?`<div class="card p-10 text-center"><div class="text-5xl mb-3">🏬</div><div class="font-bold text-slate-700 mb-2">Aucun magasin</div><div class="text-sm text-slate-500 mb-4">Créez votre premier magasin pour organiser vos stocks par thème.</div><button class="btn btn-primary" onclick="openMagasinFormModal('')">➕ Créer un magasin</button></div>`:`<div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">${mags.map(m=>{
      const t=getTheme(m.theme);
      const arts=articles.filter(a=>a.magasinId===m.id);
      const totalQty=arts.reduce((s,a)=>s+(parseInt(a.quantite)||0),0);
      const valeur=arts.reduce((s,a)=>s+((parseFloat(a.prix)||0)*(parseInt(a.quantite)||0)),0);
      return`<div class="card p-5 hover:shadow-lg transition cursor-pointer" style="border:2px solid ${t.color}33;background:linear-gradient(135deg,${t.color}08,${t.color}15)" onclick="navigate('materiel/magasin/${m.id}')">
        <div class="flex items-start justify-between mb-3">
          <div class="flex items-center gap-3"><div style="font-size:42px">${m.icon||t.icon}</div><div><div class="font-black text-lg" style="color:${t.color}">${escapeHTML(m.nom)}</div><div class="text-[10px] uppercase tracking-wider text-slate-500 font-bold">${t.label}</div></div></div>
          <div class="flex gap-1">
            <button type="button" class="btn btn-ghost text-xs" onclick="event.stopPropagation();openMagasinFormModal('${m.id}')" title="Modifier le magasin">✏</button>
            <button type="button" class="btn btn-ghost text-xs text-red-600" onclick="event.stopPropagation();deleteMagasin('${m.id}')" title="Supprimer le magasin">🗑</button>
          </div>
        </div>
        <div class="text-xs text-slate-600 mb-3">${escapeHTML(m.description||t.description||"")}</div>
        <div class="grid grid-cols-3 gap-2 mb-3">
          <div class="card p-2 text-center" style="background:#fff"><div class="text-[9px] uppercase font-bold text-slate-500">Articles</div><div class="text-xl font-black" style="color:${t.color}">${arts.length}</div></div>
          <div class="card p-2 text-center" style="background:#fff"><div class="text-[9px] uppercase font-bold text-slate-500">Unités</div><div class="text-xl font-black text-emerald-700">${totalQty}</div></div>
          <div class="card p-2 text-center" style="background:#fff"><div class="text-[9px] uppercase font-bold text-slate-500">Valeur DA</div><div class="text-base font-black text-amber-700">${money(valeur)}</div></div>
        </div>
        <div class="flex justify-between items-center text-xs text-slate-500"><span>${m.societe?"🏢 "+escapeHTML(m.societe):"🏢 Toutes sociétés"}</span><span class="font-bold" style="color:${t.color}">→ Ouvrir</span></div>
      </div>`}).join("")}</div>`}`;
}
function openMagasinFormModal(id){
  const m=id?(db.magasins||[]).find(x=>x.id===id):null;
  const isNew=!m;
  const data=m||{nom:"",theme:"habillement",description:"",societe:"",icon:"🧥",color:"#8b5cf6"};
  const themesOpts=Object.entries(MAGASIN_THEMES).map(([k,t])=>`<option value="${k}" ${data.theme===k?"selected":""}>${t.icon} ${t.label}</option>`).join("");
  openModal(`<h3 class="font-bold text-lg mb-4">${isNew?"➕ Nouveau magasin":"✏ Modifier le magasin"}</h3>
    <form id="magasin-form">
      <div class="grid grid-cols-2 gap-3">
        <div class="col-span-2"><label class="label">Nom du magasin *</label><input class="input" name="nom" value="${escapeHTML(data.nom)}"  placeholder="ex: Magasin d'habillement"/></div>
        <div><label class="label">Thème *</label><select class="select" name="theme" >${themesOpts}</select></div>
        <div><label class="label">Icône</label><input class="input text-center" name="icon" value="${escapeHTML(data.icon||"🧥")}" maxlength="3"/></div>
        <div class="col-span-2"><label class="label">Description</label><textarea class="input" name="description" rows="2" placeholder="Description du magasin">${escapeHTML(data.description||"")}</textarea></div>
        <div class="col-span-2"><label class="label">Société (facultatif)</label><select class="select" name="societe"><option value="" ${!data.societe?"selected":""}>— Toutes sociétés —</option>${SOCIETES.map(s=>`<option ${data.societe===s?"selected":""}>${s}</option>`).join("")}</select></div>
      </div>
      <div class="flex justify-between gap-2 mt-4">
        ${!isNew?`<button type="button" class="btn btn-ghost text-xs text-red-600" onclick="deleteMagasin('${id}')">🗑 Supprimer</button>`:"<span></span>"}
        <div class="flex gap-2"><button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button><button type="submit" id="magasin-save-btn" class="btn btn-primary" onclick="event.preventDefault();saveMagasin('${id||""}')">💾 Enregistrer</button></div>
      </div>
    </form>`);
  setTimeout(()=>{
    const f=document.getElementById("magasin-form");
    if(f&&!f._wired){f._wired=true;f.addEventListener("submit",e=>{e.preventDefault();saveMagasin(id||"")});}
  },0);
}
function saveMagasin(id){
  try{
    const f=document.getElementById("magasin-form")||document.querySelector(".modal-bg form");
    if(!f){toast("Formulaire introuvable","error");return}
    const fd=new FormData(f);
    const nom=(fd.get("nom")||"").trim();
    if(!nom){toast("Saisissez le nom du magasin","error");f.querySelector('[name="nom"]')?.focus();return}
    const theme=fd.get("theme")||"habillement";
    if(!theme){toast("Choisissez un thème","error");return}
    const t=getTheme(theme);
    if(id){
      const m=(db.magasins||[]).find(x=>x.id===id);if(!m){toast("Magasin introuvable","error");return}
      m.nom=nom;
      m.theme=theme;
      m.description=fd.get("description")||"";
      m.societe=fd.get("societe")||"";
      m.icon=fd.get("icon")||t.icon;
      m.color=t.color;
      m.updatedAt=new Date().toISOString();
    }else{
      if(!db.magasins)db.magasins=[];
      db.magasins.push({id:uid("mag"),nom:nom,theme:theme,description:fd.get("description")||"",societe:fd.get("societe")||"",icon:fd.get("icon")||t.icon,color:t.color,createdAt:new Date().toISOString()});
    }
    saveDB();closeModal();toast(id?"✓ Magasin modifié":"✓ Magasin créé","success");
    if(typeof logActivity==="function")logActivity(id?"Magasin modifié":"Magasin créé",nom);
    renderView();
  }catch(err){
    console.error("saveMagasin error:",err);
    toast("Erreur d'enregistrement: "+err.message,"error");
  }
}
function deleteMagasin(id){
  const m=(db.magasins||[]).find(x=>x.id===id);if(!m)return;
  const arts=(db.magasinArticles||[]).filter(a=>a.magasinId===id);
  if(arts.length){if(!confirm("⚠ Ce magasin contient "+arts.length+" article(s). Tout supprimer ?"))return;db.magasinArticles=(db.magasinArticles||[]).filter(a=>a.magasinId!==id)}
  else if(!confirm("Supprimer le magasin « "+m.nom+" » ?"))return;
  db.magasins=(db.magasins||[]).filter(x=>x.id!==id);
  saveDB();closeModal();toast("Magasin supprimé","success");navigate("materiel/magasins");
}
