  const numeroBonAuto=nextStockBonNum(type);
  const types=isEntry?[["entree","Entrée standard"],["retour","Retour (agent/site)"]]:[["nouvelle_dotation","Nouvelle dotation"],["renouvellement_dotation","Renouvellement de dotation"],["dotation_pret","Dotation à titre de prêt (mission)"],["reforme","Réformer"]];
  const sizeBlock=isEntry?stockMvtSizeBreakdownHTML(a):"";
