function stockExportCSV(){
  const arts=stockArticlesFiltered();
  if(arts.length===0){toast("Aucun article à exporter","error");return}
  const rows=[["Code","Désignation","Société","Catégorie","Sous-catégorie","Marque","Modèle","Référence","Code-barre","Unité","Prix unitaire","Stock initial","Stock actuel","Stock min","Stock max","Seuil alerte","Emplacement","Fournisseur","État"]];
  arts.forEach(a=>{
    const cat=stockGetCategorie(a.societe,a.categorie);
    const q=stockGetActuel(a.id);
    const etat=stockGetEtat(a);
    rows.push([a.code,a.designation,a.societe,cat.label,a.sousCategorie,a.marque,a.modele,a.reference,a.codeBarre,a.unite,a.prixUnitaire,a.stockInitial,q,a.stockMin,a.stockMax,a.seuilAlerte,a.emplacement,a.fournisseur,etat.label]);
  });
  const csv=rows.map(r=>r.map(c=>{const s=String(c==null?"":c);return /[",;\n]/.test(s)?'"'+s.replace(/"/g,'""')+'"':s}).join(";")).join("\n");
  const blob=new Blob(["\ufeff"+csv],{type:"text/csv;charset=utf-8"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url;a.download="catalogue-stock-"+today()+".csv";a.click();
  URL.revokeObjectURL(url);
  toast("Export CSV téléchargé","success");
}

/* ---- PAIE ---- */
function defaultPaieConfig(){return{snmg:24000,heuresMois:173.33,tauxCnasSalarie:9,tauxCnasPatronal:26,abattementIRG:40,abattementMinMensuel:1000,abattementMaxMensuel:120000,primeNuit:3000,primePanier:0,primeTransport:0,retenueAbsenceJour:0}}
function paieConfig(){if(!db.paieConfig)db.paieConfig=defaultPaieConfig();db.paieConfig={...defaultPaieConfig(),...db.paieConfig};return db.paieConfig}
function irgBaremeMensuel(base){
  const b=Math.max(0,Number(base)||0);
  let irg=0;
  if(b>30000)irg+=Math.min(b,120000)-30000>0?(Math.min(b,120000)-30000)*0.23:0;
  if(b>120000)irg+=(Math.min(b,360000)-120000)*0.27;
  if(b>360000)irg+=(b-360000)*0.30;
  return Math.max(0,Math.round(irg));
}
function calcPaieAgent(a){
  const cfg=paieConfig();
  const brutBase=Number(a.salaireNet||a.salaireBase||0)||0;
  const primeNuit=a.affectationCourante?.horaire==="Nuit"?Number(cfg.primeNuit||0):0;
  const primes=primeNuit+Number(cfg.primePanier||0)+Number(cfg.primeTransport||0);
  const absences=0;
  const brutCotisable=Math.max(0,brutBase+primes-absences);
  const cnasSalarie=Math.round(brutCotisable*(Number(cfg.tauxCnasSalarie||0)/100));
  const netSocial=Math.max(0,brutCotisable-cnasSalarie);
  const abatRaw=netSocial*(Number(cfg.abattementIRG||0)/100);
  const abat=Math.min(Math.max(abatRaw,Number(cfg.abattementMinMensuel||0)),Number(cfg.abattementMaxMensuel||0));
  const baseIRG=Math.max(0,netSocial-abat);
  const irg=irgBaremeMensuel(baseIRG);
  const netAPayer=Math.max(0,netSocial-irg);
  const cnasPatronal=Math.round(brutCotisable*(Number(cfg.tauxCnasPatronal||0)/100));
  const coutEmployeur=brutCotisable+cnasPatronal;
  return{brutBase,primeNuit,primes,absences,brutCotisable,cnasSalarie,netSocial,abat,baseIRG,irg,netAPayer,cnasPatronal,coutEmployeur};
}
function paieMonthLabel(ym){const [y,m]=String(ym||"").split("-").map(Number);if(!y||!m)return new Date().toLocaleDateString("fr-FR",{month:"long",year:"numeric"});return new Date(y,m-1,1).toLocaleDateString("fr-FR",{month:"long",year:"numeric"})}
function setPaieFilter(k,v){sessionStorage.setItem("paie"+k,v||"");renderView()}
function savePaieConfig(){
  const f=document.getElementById("paie-config-form");if(!f)return;
  const fd=new FormData(f);const cfg=paieConfig();
  ["snmg","heuresMois","tauxCnasSalarie","tauxCnasPatronal","abattementIRG","abattementMinMensuel","abattementMaxMensuel","primeNuit","primePanier","primeTransport","retenueAbsenceJour"].forEach(k=>cfg[k]=parseMoneyInput(fd.get(k))||0);
  db.paieConfig=cfg;saveDB();toast("Paramètres paie enregistrés","success");renderView();
}
function paieExportCSV(){
  const rows=[["Matricule","Nom","Société","Contrat","Brut cotisable","CNAS salarié","Base IRG","IRG","Net à payer","CNAS patronal","Coût employeur"]];
  document.querySelectorAll("#paie-tbody tr[data-paierow]").forEach(r=>rows.push(JSON.parse(r.dataset.csv)));
  const csv=rows.map(r=>r.map(c=>`"${String(c??"").replace(/"/g,'""')}"`).join(";")).join("\n");
  const blob=new Blob(["\ufeff"+csv],{type:"text/csv;charset=utf-8"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download="paie-"+(sessionStorage.getItem("paieMois")||today().slice(0,7))+".csv";a.click();URL.revokeObjectURL(url);
}
function paieFicheHTML(agentId,ym){
  const a=db.agents.find(x=>x.id===agentId);if(!a)return"";
  const cfg=paieConfig();const c=calcPaieAgent(a);const mois=paieMonthLabel(ym||sessionStorage.getItem("paieMois")||today().slice(0,7));
  const totalRetenues=c.cnasSalarie+c.irg;
  const ligne=(lib,base,taux,gain,retenue)=>`<tr><td>${escapeHTML(lib)}</td><td class="r">${base}</td><td class="r">${taux}</td><td class="r">${gain}</td><td class="r">${retenue}</td></tr>`;
  return`<div class="bulletin-paie">
    
    <div class="bp-head">
      <div><div class="bp-title">Fiche de paie</div><div class="bp-sub">Période : ${escapeHTML(mois)} · SGDI</div></div>
      <div style="text-align:right"><div style="font-size:18px;font-weight:900">${escapeHTML(a.societe||"")}</div><div class="bp-sub">Établie le ${formatDate(today())}</div></div>
    </div>
    <div class="bp-grid">
      <div class="bp-box"><h3>Employeur</h3>
        <div class="bp-line"><span>Société</span><b>${escapeHTML(a.societe||"—")}</b></div>
        <div class="bp-line"><span>Site</span><b>${escapeHTML(a.affectationCourante?.siteName||"—")}</b></div>
        <div class="bp-line"><span>Poste</span><b>${escapeHTML(a.fonction||a.affectationCourante?.poste||"—")}</b></div>
      </div>
      <div class="bp-box"><h3>Salarié</h3>
        <div class="bp-line"><span>Nom et prénom</span><b>${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</b></div>
        <div class="bp-line"><span>Matricule</span><b>${escapeHTML(a.matricule||"—")}</b></div>
        <div class="bp-line"><span>Contrat</span><b>${escapeHTML(a.typeContrat||"—")}</b></div>
        <div class="bp-line"><span>Date recrutement</span><b>${formatDate(a.dateRecrutement)}</b></div>
      </div>
    </div>
    <table>
      <thead><tr><th>Rubrique</th><th class="r">Base</th><th class="r">Taux</th><th class="r">Gains</th><th class="r">Retenues</th></tr></thead>
      <tbody>
        ${ligne("Salaire de base",money(c.brutBase),"",money(c.brutBase),"")}
        ${c.primeNuit?ligne("Prime de nuit",money(c.primeNuit),"",money(c.primeNuit),""):""}
        ${cfg.primePanier?ligne("Prime panier",money(cfg.primePanier),"",money(cfg.primePanier),""):""}
        ${cfg.primeTransport?ligne("Prime transport",money(cfg.primeTransport),"",money(cfg.primeTransport),""):""}
        ${ligne("Brut cotisable",money(c.brutCotisable),"","<b>"+money(c.brutCotisable)+"</b>","")}
        ${ligne("CNAS salarié",money(c.brutCotisable),qty(cfg.tauxCnasSalarie)+" %","",money(c.cnasSalarie))}
        ${ligne("Net social",money(c.netSocial),"","<b>"+money(c.netSocial)+"</b>","")}
        ${ligne("Abattement IRG",money(c.netSocial),qty(cfg.abattementIRG)+" %","",money(c.abat))}
        ${ligne("Base IRG",money(c.baseIRG),"","",money(c.baseIRG))}
        ${ligne("IRG retenu",money(c.baseIRG),"Barème","",money(c.irg))}
      </tbody>
      <tfoot>
        <tr><th colspan="3" class="r">Totaux</th><th class="r">${money(c.brutCotisable)}</th><th class="r">${money(totalRetenues)}</th></tr>
      </tfoot>
    </table>
    <div class="bp-grid" style="margin-top:12px">
      <div class="bp-box"><h3>Charges patronales</h3>
        <div class="bp-line"><span>CNAS patronal</span><b>${money(c.cnasPatronal)}</b></div>
        <div class="bp-line"><span>Coût employeur</span><b>${money(c.coutEmployeur)}</b></div>
      </div>
      <div class="bp-net"><div class="label">Net à payer</div><div class="value">${money(c.netAPayer)}</div></div>
    </div>
    <div class="bp-sign"><div>Signature employeur<br><br>________________________</div><div>Signature salarié<br><br>________________________</div></div>
  </div>`;
}
function previewPaieFiche(agentId){
  const ym=sessionStorage.getItem("paieMois")||today().slice(0,7);
  const html=paieFicheHTML(agentId,ym);
  openModal(`<div style="max-height:82vh;overflow:auto;background:#fff">${html}</div><div class="no-print flex justify-end gap-2 mt-3"><button class="btn btn-ghost" onclick="closeModal()">Fermer</button><button class="btn btn-primary" onclick="printPaieFiche('${agentId}')">Imprimer</button></div>`);
}
function printPaieFiche(agentId){
  const ym=sessionStorage.getItem("paieMois")||today().slice(0,7);
  const a=db.agents.find(x=>x.id===agentId);
  const w=window.open("","_blank","width=900,height=700");
  w.document.write(`<html><head><title>Fiche paie ${a?escapeHTML(a.matricule):""}</title></head><body>${paieFicheHTML(agentId,ym)}<script>window.onload=()=>setTimeout(()=>window.print(),300)<\/script></body></html>`);
  w.document.close();
}
function renderPaie(view){
  const cfg=paieConfig();
  const ym=sessionStorage.getItem("paieMois")||today().slice(0,7);
  const soc=sessionStorage.getItem("paieSociete")||"";
  let agents=db.agents.filter(a=>a.statut==="actif");
  if(soc)agents=agents.filter(a=>a.societe===soc);
  const lines=agents.map(a=>({a,c:calcPaieAgent(a)}));
  const sum=k=>lines.reduce((s,x)=>s+(Number(x.c[k])||0),0);
  const anomalies=lines.filter(x=>x.c.brutCotisable<cfg.snmg);
  view.innerHTML=`<div class="flex justify-between items-start gap-3 mb-4">
    <div><h1 class="text-2xl font-bold">Paie — ${paieMonthLabel(ym)}</h1><p class="text-sm text-slate-500">Calcul paie Algérie : CNAS, IRG, net à payer, coût employeur.</p></div>
    <div class="flex gap-2 flex-wrap justify-end"><button class="btn paie-export-btn" onclick="paieExportCSV()">Exporter CSV</button><button class="btn paie-print-btn" onclick="window.print()">Imprimer</button></div>
  </div>
  <div class="card p-4 mb-4">
    <div class="grid grid-4">
      <div><label class="label">Mois de paie</label><input class="input" type="month" value="${ym}" onchange="setPaieFilter('Mois',this.value)"/></div>
      <div><label class="label">Société</label><select class="select" onchange="setPaieFilter('Societe',this.value)"><option value="">Toutes</option>${SOCIETES.map(s=>`<option ${soc===s?"selected":""}>${s}</option>`).join("")}</select></div>
      <div><label class="label">SNMG applicable</label><div class="input bg-slate-50">${money(cfg.snmg)}</div></div>
      <div><label class="label">Heures légales / mois</label><div class="input bg-slate-50">${qty(cfg.heuresMois)} h</div></div>
    </div>
  </div>
  <div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Effectif paie</div><div class="text-3xl font-black text-sky-700">${agents.length}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Brut cotisable</div><div class="text-2xl font-black">${money(sum("brutCotisable"))}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Net à payer</div><div class="text-2xl font-black text-emerald-700">${money(sum("netAPayer"))}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Coût employeur</div><div class="text-2xl font-black text-amber-700">${money(sum("coutEmployeur"))}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">CNAS salarié 9%</div><div class="text-2xl font-black text-red-700">${money(sum("cnasSalarie"))}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">CNAS patronal 26%</div><div class="text-2xl font-black text-orange-700">${money(sum("cnasPatronal"))}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">IRG retenu</div><div class="text-2xl font-black text-purple-700">${money(sum("irg"))}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Alertes SNMG</div><div class="text-2xl font-black ${anomalies.length?"text-red-700":"text-emerald-700"}">${anomalies.length}</div></div>
  </div>
  ${anomalies.length?`<div class="card p-4 mb-4" style="background:#fef2f2;border:2px solid #dc2626"><div class="font-black text-red-700 mb-2">Alerte SNMG</div><div class="text-sm text-red-700">${anomalies.length} agent(s) ont un brut cotisable inférieur au SNMG ${money(cfg.snmg)}.</div></div>`:""}
  <details class="card p-4 mb-4"><summary class="font-bold cursor-pointer">Paramètres réglementaires et primes</summary>
    <form id="paie-config-form" class="grid grid-6 mt-4">
      <div class="col-span-2"><label class="label">SNMG</label><input class="input" name="snmg" value="${formatMoneyInputValue(cfg.snmg)}" onblur="formatMoneyField(this)"/></div>
      <div class="col-span-2"><label class="label">Heures / mois</label><input class="input" name="heuresMois" value="${cfg.heuresMois}"/></div>
      <div><label class="label">CNAS salarié %</label><input class="input" name="tauxCnasSalarie" value="${cfg.tauxCnasSalarie}"/></div>
      <div><label class="label">CNAS patronal %</label><input class="input" name="tauxCnasPatronal" value="${cfg.tauxCnasPatronal}"/></div>
      <div><label class="label">Abattement IRG %</label><input class="input" name="abattementIRG" value="${cfg.abattementIRG}"/></div>
      <div><label class="label">Abatt. min/mois</label><input class="input" name="abattementMinMensuel" value="${formatMoneyInputValue(cfg.abattementMinMensuel)}" onblur="formatMoneyField(this)"/></div>
      <div><label class="label">Abatt. max/mois</label><input class="input" name="abattementMaxMensuel" value="${formatMoneyInputValue(cfg.abattementMaxMensuel)}" onblur="formatMoneyField(this)"/></div>
      <div><label class="label">Prime nuit</label><input class="input" name="primeNuit" value="${formatMoneyInputValue(cfg.primeNuit)}" onblur="formatMoneyField(this)"/></div>
      <div><label class="label">Prime panier</label><input class="input" name="primePanier" value="${formatMoneyInputValue(cfg.primePanier)}" onblur="formatMoneyField(this)"/></div>
      <div><label class="label">Prime transport</label><input class="input" name="primeTransport" value="${formatMoneyInputValue(cfg.primeTransport)}" onblur="formatMoneyField(this)"/></div>
      <div class="col-span-6 text-xs text-slate-500">Barème IRG mensuel intégré : 0% jusqu'à 30 000 DA, 23% de 30 001 à 120 000 DA, 27% de 120 001 à 360 000 DA, 30% au-delà. Les paramètres restent modifiables selon instruction comptable.</div>
      <div class="col-span-6"><button type="button" class="btn btn-primary" onclick="savePaieConfig()">Enregistrer paramètres</button></div>
    </form>
  </details>
  <div class="card overflow-hidden"><div class="overflow-x-auto"><table>
    <thead><tr><th>Matricule</th><th>Agent</th><th>Société</th><th>Contrat</th><th class="text-right">Base</th><th class="text-right">Primes</th><th class="text-right">Brut cotisable</th><th class="text-right">CNAS sal.</th><th class="text-right">Base IRG</th><th class="text-right">IRG</th><th class="text-right">Net à payer</th><th class="text-right">Coût employeur</th><th>Alerte</th><th></th></tr></thead>
    <tbody id="paie-tbody">${lines.length===0?`<tr><td colspan="14" class="text-center text-slate-500 p-6">Aucun agent actif.</td></tr>`:lines.map(({a,c})=>{const csv=[a.matricule,(a.nom||"")+" "+(a.prenom||""),a.societe,a.typeContrat,c.brutCotisable,c.cnasSalarie,c.baseIRG,c.irg,c.netAPayer,c.cnasPatronal,c.coutEmployeur];return`<tr data-searchable data-paierow data-csv='${JSON.stringify(csv).replace(/'/g,"&#39;")}'><td class="font-mono font-bold">${safe(a.matricule)}</td><td><a href="#/effectif/agent/${a.id}" class="font-semibold hover:underline">${escapeHTML((a.nom||"")+" "+(a.prenom||""))}</a><div class="text-[10px] text-slate-500">${escapeHTML(a.fonction||a.affectationCourante?.poste||"")}</div></td><td class="text-xs">${safe(a.societe)}</td><td><span class="pill pill-gray">${safe(a.typeContrat)}</span></td><td class="text-right">${money(c.brutBase)}</td><td class="text-right">${money(c.primes)}</td><td class="text-right font-bold">${money(c.brutCotisable)}</td><td class="text-right text-red-700">${money(c.cnasSalarie)}</td><td class="text-right">${money(c.baseIRG)}</td><td class="text-right text-purple-700">${money(c.irg)}</td><td class="text-right font-black text-emerald-700">${money(c.netAPayer)}</td><td class="text-right font-bold text-amber-700">${money(c.coutEmployeur)}</td><td>${c.brutCotisable<cfg.snmg?`<span class="pill pill-red">SNMG</span>`:`<span class="pill pill-green">OK</span>`}</td><td><button class="btn btn-primary text-xs" onclick="previewPaieFiche('${a.id}')">Fiche de paie</button></td></tr>`}).join("")}</tbody>
  </table></div></div>
  <div class="text-xs text-slate-500 mt-3">Note : ce module automatise les calculs standards. Les cas particuliers (avantages en nature, indemnités imposables/non imposables, temps partiel, dispositifs aidés, rappels) doivent être validés par votre comptable ou gestionnaire paie.</div>`;
}

/* ---- RAPPORTS ---- */
function renderRapports(view){view.innerHTML=`<h1 class="text-2xl font-bold mb-6">📈 Rapports</h1><div class="grid grid-3 mb-6">${kpiCard("Agents actifs",db.agents.filter(a=>a.statut==="actif").length,"👮","amber")}${kpiCard("Sites actifs",db.sites.filter(s=>s.actif).length,"📍","blue")}${kpiCard("Évèn. en cours",db.incidents.filter(i=>i.statut==="en_cours").length,"🚨","red")}</div><div class="grid grid-2 gap-4"><div class="card p-5"><h3 class="mb-4">Par société</h3>${SOCIETES.map(s=>{const n=db.agents.filter(a=>a.societe===s&&a.statut==="actif").length;return`<div class="flex justify-between text-sm py-1 border-b border-slate-200"><span>${s}</span><b>${n}</b></div>`}).join("")}</div><div class="card p-5"><h3 class="mb-4">Types de contrat</h3>${TYPES_CONTRAT.map(t=>{const n=db.agents.filter(a=>a.typeContrat===t&&a.statut==="actif").length;if(!n)return"";return`<div class="flex justify-between text-sm py-1 border-b border-slate-200"><span>${t}</span><b>${n}</b></div>`}).join("")}</div></div>`}

