async function fpqCloturerJournee(date){if(!date)date=fpqCurrentDate();if(fpqIsCloture(date)){toast("Déjà clôturée","info");return}const lignes=(db.feuillePresence||[]).filter(f=>f.date===date);if(!lignes.length){if(!confirm("Aucune ligne saisie pour le "+formatDate(date)+".\nClôturer la feuille à zéro quand même ?"))return}else{const incomplets=lignes.filter(f=>!f.heureArrivee).length;const msg="Clôturer définitivement la feuille du "+formatDate(date)+" ?\n\n• "+lignes.length+" ligne(s) au total\n"+(incomplets?"• ⚠ "+incomplets+" ligne(s) incomplète(s) (situation manquante)\n":"")+"\nLes lignes ne pourront plus être modifiées sans déclôture.";if(!confirm(msg))return}try{await sgdiRunLegacyAction("close-presence-day",{data:{date}});await sgdiPullState({silent:true});if(typeof logActivity==="function")logActivity("Clôture feuille de présence","Date: "+formatDate(date)+" · "+lignes.length+" ligne(s)");toast("Feuille clôturée par le backend","success");renderView()}catch(e){toast("Clôture refusée : "+(e.message||e),"error")}}
function fpqDeclôturerJournee(date){return fpqDecloturerJournee(date)}
async function fpqDecloturerJournee(date){if(!date)date=fpqCurrentDate();if(!fpqIsCloture(date)){toast("Feuille non clôturée","info");return}const motif=prompt("Motif de la déclôture du "+formatDate(date)+" :","");if(motif===null)return;if(!motif.trim()){toast("Motif obligatoire","error");return}try{await sgdiRunLegacyAction("reopen-presence-day",{data:{date,motif:motif.trim()}});await sgdiPullState({silent:true});if(typeof logActivity==="function")logActivity("Déclôture feuille de présence","Date: "+formatDate(date)+" · Motif: "+motif.trim());toast("Feuille déclôturée par le backend","success");renderView()}catch(e){toast("Déclôture refusée : "+(e.message||e),"error")}}
function fpqClotureBannerHTML(){if(!db||!session)return"";if(session.transverse!=="ops")return"";if(typeof canAccess==="function"&&!canAccess("ops"))return"";const today=new Date().toISOString().slice(0,10);const allDates=new Set();(db.feuillePresence||[]).forEach(f=>allDates.add(f.date));allDates.add(today);const c=db.feuillePresenceCloture||{};const pending=[...allDates].filter(d=>!c[d]).sort((a,b)=>b.localeCompare(a));if(!pending.length)return"";const todayPending=pending.includes(today);const oldPending=pending.filter(d=>d!==today).sort((a,b)=>b.localeCompare(a));const todayCount=(db.feuillePresence||[]).filter(f=>f.date===today).length;const oldList=oldPending.slice(0,5).map(d=>{const cnt=(db.feuillePresence||[]).filter(f=>f.date===d).length;return`<button class="text-[11px] px-2 py-0.5 rounded-full font-bold" style="background:#fff;color:#b91c1c;border:1px solid #fca5a5" onclick="setFpqDate('${d}');navigate('pointage/quotidien')">📅 ${formatDate(d)} · ${cnt} ligne${cnt>1?"s":""}</button>`}).join(" ");const moreOld=oldPending.length>5?` <span class="text-[11px] text-red-700 font-semibold">+ ${oldPending.length-5} autre(s)…</span>`:"";const todayLabel=new Date(today).toLocaleDateString("fr-FR",{weekday:"long",day:"2-digit",month:"long"});const bg=todayPending&&!oldPending.length?"linear-gradient(90deg,#043970,#043970)":"linear-gradient(90deg,#fee2e2,#fecaca)";const border=todayPending&&!oldPending.length?"#043970":"#dc2626";const titleColor=todayPending&&!oldPending.length?"#043970":"#991b1b";const subColor=todayPending&&!oldPending.length?"#043970":"#7f1d1d";return`<div class="no-print mx-4 mt-3 p-4 rounded-lg shadow-lg fpq-banner-pulse" style="background:${bg};border:3px solid ${border}">
    <div class="flex items-center justify-between gap-3 flex-wrap">
      <div class="flex items-center gap-3 flex-1 min-w-0">
        <div style="font-size:38px;line-height:1">${todayPending&&!oldPending.length?"⏰":"🚨"}</div>
        <div class="min-w-0 flex-1">
          <div class="font-black text-lg leading-tight uppercase" style="color:${titleColor};letter-spacing:0.02em">FEUILLE DE PRÉSENCE QUOTIDIENNE — NON CLÔTURÉE</div>
          <div class="text-xs mt-1 font-semibold" style="color:${subColor}">
            ${todayPending?`📅 <span class="capitalize">${todayLabel}</span> · ${todayCount} ligne${todayCount>1?"s":""} saisie${todayCount>1?"s":""}`:""}
            ${todayPending&&oldPending.length?" &nbsp;·&nbsp; ":""}
            ${oldPending.length?`🚩 <strong>${oldPending.length} feuille${oldPending.length>1?"s":""} antérieure${oldPending.length>1?"s":""} non clôturée${oldPending.length>1?"s":""}</strong>`:""}
          </div>
          ${oldPending.length?`<div class="mt-2 flex flex-wrap gap-1">${oldList}${moreOld}</div>`:""}
        </div>
      </div>
      <div class="flex gap-2 shrink-0">
        <button class="btn btn-secondary text-sm font-bold" onclick="setFpqDate('${today}');navigate('pointage/quotidien')">📋 Ouvrir</button>
        ${todayPending?`<button class="btn text-sm font-black shadow" style="background:${border};color:white;border:0" onclick="fpqCloturerJournee('${today}')">🔒 Clôturer aujourd'hui</button>`:""}
      </div>
    </div>
  </div>`}
function fpqClearAll(date,soc){if(fpqGuardCloture(date))return;if(!confirm("Effacer toute la feuille du "+formatDate(date)+" ?"))return;const removed=(db.feuillePresence||[]).filter(f=>f.date===date&&(!soc||f.societe===soc));removed.forEach(f=>ptRemovePresenceLine(f));const before=(db.feuillePresence||[]).length;db.feuillePresence=(db.feuillePresence||[]).filter(f=>{if(f.date!==date)return true;if(soc&&f.societe!==soc)return true;return false});saveDB();toast((before-db.feuillePresence.length)+" ligne(s) supprimée(s)","success");renderView()}
function fpqSupprimerFeuille(date){
  if(fpqGuardCloture(date))return;
  const lignes=(db.feuillePresence||[]).filter(f=>f.date===date);
  if(!lignes.length){toast("Aucune feuille à supprimer pour cette date","info");return}
  if(!confirm("Supprimer définitivement toute la feuille de présence du "+formatDate(date)+" ?\n\n"+lignes.length+" ligne(s) seront supprimée(s)."))return;
  lignes.forEach(f=>ptRemovePresenceLine(f));
  db.feuillePresence=(db.feuillePresence||[]).filter(f=>f.date!==date);
  if(db.feuillePresenceCloture)delete db.feuillePresenceCloture[date];
  saveDB();
  if(typeof logActivity==="function")logActivity("Suppression feuille de présence","Date: "+formatDate(date)+" · "+lignes.length+" ligne(s)");
  toast("Feuille de présence supprimée","success");
  renderView();
}
function fpqDuplicateYesterday(date,soc){const d=new Date(date);d.setDate(d.getDate()-1);const prev=d.toISOString().slice(0,10);const src=(db.feuillePresence||[]).filter(f=>f.date===prev&&(!soc||f.societe===soc));if(!src.length){toast("Aucune feuille pour le "+formatDate(prev),"error");return}if(!confirm(`Copier ${src.length} ligne(s) du ${formatDate(prev)} vers le ${formatDate(date)} ?`))return;let n=0;src.forEach(s=>{const exists=fpqGet(date,s.agentId);if(exists)return;const f={...s,id:uid("fpq"),date,heureArrivee:"",heureDepart:"",heureReleve:"",observations:"",createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()};db.feuillePresence.push(f);n++});saveDB();toast(n+" ligne(s) copiée(s)","success");renderView()}
function fpqAddAllAgents(date,soc){const allAg=(db.agents||[]).filter(a=>a.statut==="actif");const ag=soc?allAg.filter(a=>a.societe===soc):allAg;if(!ag.length){toast("Aucun agent actif","error");return}if(!confirm(`Ajouter les ${ag.length} agents actifs à la feuille du ${formatDate(date)} ?`))return;let n=0;ag.forEach(a=>{if(!fpqGet(date,a.id)){fpqEnsure(date,a.id);n++}});saveDB();toast(n+" agent(s) ajouté(s)","success");renderView()}
function fpqIsWeekendAlgerie(date){const d=new Date(date+"T00:00:00").getDay();return d===5||d===6}
function fpqIsJourFerieAlgerie(date){
  const md=(date||"").slice(5);
  const fixed=["01-01","01-12","05-01","07-05","11-01"];
  const custom=db.joursFeries||[];
  return fixed.includes(md)||custom.includes(date)||custom.includes(md);
}
function fpqIsJourOuvrableAlgerie(date){return !fpqIsWeekendAlgerie(date)&&!fpqIsJourFerieAlgerie(date)}
function fpqRotationForSite(site,date,groupIndex){
  const sys=site.rotationSystem||inferSiteRotationSystem(site);
  const base=site.dateCreation||today();
  const d1=new Date(base+"T00:00:00"),d2=new Date(date+"T00:00:00");
  const diff=Math.max(0,Math.floor((d2-d1)/86400000));
  if(sys==="1/1"){
    const isA1=(groupIndex||0)===0;
    return isA1&&fpqIsJourOuvrableAlgerie(date)?{jour:"Groupe A1",on:true,periode:"jour",regle:"5 jours/semaine · 8h max"}:{jour:isA1?"Groupe A1":"Groupe "+(["A","B","C","D"][groupIndex]||""),on:false,periode:"off",regle:isA1?"Week-end / jour férié":"Non concerné par 1/1"};
  }
  if(sys==="1/3"){
    if((groupIndex||0)===0)return fpqIsJourOuvrableAlgerie(date)?{jour:"Groupe A",on:true,periode:"jour",regle:"5 jours ouvrables"}:{jour:"Groupe A",on:false,periode:"off",regle:"Week-end / jour férié"};
    const nightIndex=((groupIndex||1)-1)%3;
    return diff%3===nightIndex?{jour:"Groupe "+(["A","B","C","D"][groupIndex]||""),on:true,periode:"nuit",regle:"1 nuit sur 3"}:{jour:"Groupe "+(["A","B","C","D"][groupIndex]||""),on:false,periode:"off",regle:"Récupération"};
  }
  if(sys==="1/2"){
    const gi=groupIndex||0;
    const isWork=(diff%2)===(gi%2);
    const isDay=gi<2;
    return isWork?{jour:"Groupe "+(["A","B","C","D"][gi]||""),on:true,periode:isDay?"jour":"nuit",regle:isDay?"1 jour sur 2 · max 12h":"1 nuit sur 2 · max 12h"}:{jour:"Groupe "+(["A","B","C","D"][gi]||""),on:false,periode:"off",regle:"Récupération"};
  }
  const rot=siteRotationForGroup(sys,groupIndex||0);
  return rot[diff%rot.length]||{on:false,periode:"off"};
}
function fpqParseHoraires(site,periode){
  const jour=(site.heureReleveJour||"").trim();
  const nuit=(site.heureReleveNuit||"").trim();
  if(jour||nuit){
    const rel=periode==="nuit"?(nuit||jour||"06:00"):(jour||nuit||"18:00");
    const arr=periode==="nuit"?"18:00":"06:00";
    return {a:arr,d:rel,r:rel};
  }
  const raw=(site.horairesReleves||"").trim();
  const fallback=periode==="nuit"?{a:"18:00",d:"06:00",r:"06:00"}:{a:"06:00",d:"18:00",r:"18:00"};
  const blocks=raw.split("/").map(x=>x.trim()).filter(Boolean);
  const pick=periode==="nuit"?(blocks[1]||blocks[0]||""):(blocks[0]||"");
  const m=pick.match(/(\d{1,2}:\d{2})\s*[-à]\s*(\d{1,2}:\d{2})/i);
  if(!m)return fallback;
  const norm=t=>t.split(":").map((x,i)=>i===0?String(+x).padStart(2,"0"):x).join(":");
  return {a:norm(m[1]),d:norm(m[2]),r:norm(m[2])};
}
function fpqAgentMatchesPeriode(agent,periode){
  const h=(agent.affectationCourante?.horaire||"").toLowerCase();
  if(!h||h==="mixte")return true;
  if(periode==="jour")return h.includes("jour");
  if(periode==="nuit")return h.includes("nuit");
  return false;
}
function fpqAgentGroup(site,agent,agents){
  const groupNames=["A","B","C","D"];
  const manual=site.groupesAffectation?.[agent.id];
  if(manual&&groupNames.includes(manual))return {index:groupNames.indexOf(manual),name:manual};
  const n=Math.max(1,Math.min(4,+site.effectifs?.groupes||4));
  const sorted=(agents||[]).slice().sort((a,b)=>(a.matricule||a.nom||"").localeCompare(b.matricule||b.nom||""));
  const idx=Math.max(0,sorted.findIndex(a=>a.id===agent.id));
  const gi=idx%n;
  return {index:gi,name:groupNames[gi]||String(gi+1)};
}

function fpqRecoveryStandby(date,soc,siteId){
  const used=new Set((db.feuillePresence||[]).filter(f=>f.date===date&&f.agentId).map(f=>f.agentId));
  const rows=[];
  (db.sites||[]).filter(site=>site.actif!==false&&(!soc||site.societe===soc)&&(!siteId||site.id===siteId)).forEach(site=>{
    const agentsSite=(db.agents||[]).filter(a=>a.statut==="actif"&&a.affectationCourante?.siteId===site.id);
    agentsSite.forEach(a=>{
      if(used.has(a.id))return;
      const grp=fpqAgentGroup(site,a,agentsSite);
      const rot=fpqRotationForSite(site,date,grp.index);
      if(rot.on)return;
      rows.push({agent:a,site,group:grp.name,rot,phone:a.telephone||a.phone||"",reason:rot.regle||"Récupération"});
    });
  });
  return rows.sort((x,y)=>(x.agent.matricule||x.agent.nom||"").localeCompare(y.agent.matricule||y.agent.nom||""));
}
function fpqStandbyPanelHTML(date,soc,siteId){
  const rows=fpqRecoveryStandby(date,soc,siteId);
  const preview=rows.slice(0,8).map(r=>`<tr><td class="font-mono font-bold text-xs">${escapeHTML(r.agent.matricule||"—")}</td><td class="text-xs font-semibold">${escapeHTML((r.agent.nom||"")+" "+(r.agent.prenom||""))}</td><td class="text-xs">${escapeHTML(r.site.nom||r.site.intitule||"Site")}</td><td class="text-xs font-bold">Groupe ${escapeHTML(r.group)}</td><td class="text-xs">${escapeHTML(r.phone||"—")}</td><td><button class="btn btn-secondary text-xs" onclick="fpqQuickCallInfo('${r.agent.id}','${date}')">Contacter</button></td></tr>`).join("");
  return `<div class="card p-4 mb-4" style="background:#f8fafc;border:1px solid #cbd5e1"><div class="flex items-center justify-between gap-3 flex-wrap"><div><div class="text-xs uppercase tracking-wider font-black text-slate-500">Astreinte / récupération disponible</div><div class="font-black text-lg">${rows.length} employé(s) récupérable(s) pour remplacement</div></div><span class="pill" style="background:#01112f;color:#facc15">Rotation calculée</span></div>${rows.length?`<div class="overflow-x-auto mt-3"><table class="w-full text-sm"><thead><tr><th>Code</th><th>Employé</th><th>Site</th><th>Groupe</th><th>Téléphone</th><th>Action</th></tr></thead><tbody>${preview}</tbody></table>${rows.length>8?`<div class="text-xs text-slate-500 mt-2">+ ${rows.length-8} autre(s) disponible(s)</div>`:""}</div>`:`<div class="text-sm text-slate-500 mt-2">Aucun personnel en récupération disponible avec ce filtre.</div>`}</div>`;
}
function fpqQuickCallInfo(agentId,date){const a=(db.agents||[]).find(x=>x.id===agentId);if(!a)return;toast("Astreinte : "+((a.nom||"")+" "+(a.prenom||"")).trim()+" · Tél: "+(a.telephone||a.phone||"non renseigné"),"info");}

function fpqSiteProgrammedSlots(site,date,agentsSite){
  const eff=siteEffectifsNorm(site);
  const grouped={jour:[],nuit:[]};
  agentsSite.forEach(a=>{
    const grp=fpqAgentGroup(site,a,agentsSite);
    const rot=fpqRotationForSite(site,date,grp.index);
    if(!rot.on||!["jour","nuit"].includes(rot.periode)||!fpqAgentMatchesPeriode(a,rot.periode))return;
    grouped[rot.periode].push({agent:a,rot,group:grp.name});
  });
  const period=grouped.jour.length?"jour":(grouped.nuit.length?"nuit":((+eff.jour||0)>0?"jour":"nuit"));
  const slots=[];
  const required=Math.max(+eff[period]||0,grouped[period].length||0,1);
  const programmed=grouped[period].slice(0,required);
  const horaires=fpqParseHoraires(site,period);
  programmed.forEach(x=>slots.push({agent:x.agent,site,rot:x.rot,horaires,group:x.group,vacant:false,periode:period}));
  for(let i=programmed.length;i<required;i++)slots.push({agent:null,site,rot:{jour:`${period==="nuit"?"Nuit":"Jour"} · poste ${i+1}`,periode:period,regle:"Effectif à couvrir"},horaires,group:"—",vacant:true,slotIndex:i+1,periode:period});
  return slots;
}
function fpqLineOrder(f){
  if(Number.isFinite(+f?.presenceOrder))return +f.presenceOrder;
  const m=String(f?.vacantKey||"").match(/:(\d+)$/);
  if(m)return +m[1];
  const created=Date.parse(f?.createdAt||"");
  return Number.isFinite(created)?created:999999;
}
function fpqGenerateAuto(date,soc,siteId){
  if(fpqGuardCloture(date))return;
  const sites=(db.sites||[]).filter(s=>s.actif!==false&&(!soc||s.societe===soc)&&(!siteId||s.id===siteId));
  if(!sites.length){toast("Aucun site actif pour ce filtre","error");return}
  let candidates=[],sitesSansAgent=0;
  sites.forEach(site=>{
    const agentsSite=(db.agents||[]).filter(a=>a.statut==="actif"&&a.affectationCourante?.siteId===site.id);
    if(!agentsSite.length)sitesSansAgent++;
    candidates.push(...fpqSiteProgrammedSlots(site,date,agentsSite));
  });
  if(!candidates.length){toast("Aucun agent actif affecté aux sites actifs","error");return}
  if(!confirm(`Générer automatiquement la feuille du ${formatDate(date)} ?\n\n${candidates.length} agent(s) sur site(s) actif(s)\n${sites.length} site(s) actif(s) vérifié(s)\n${sitesSansAgent} site(s) sans agent actif affecté\n\nLes lignes déjà saisies ne seront pas écrasées.`))return;
  const siteIds=new Set(sites.map(s=>s.id));
  let replaced=0;
  db.feuillePresence=(db.feuillePresence||[]).filter(f=>{
    const generated=!!(f.generatedAt||f.generatedBy||f.vacant);
    if(f.date===date&&siteIds.has(f.siteId)&&!f.valide&&generated){ptRemovePresenceLine(f);replaced++;return false}
    return true;
  });
  let added=0,existing=0;
  candidates.forEach(({agent:a,site,rot,horaires,group,vacant,slotIndex,periode},idx)=>{
    const vacantKey=`${site.id}:${periode}:${slotIndex||group}`;
    const ex=a?fpqGet(date,a.id):(db.feuillePresence||[]).find(f=>f.date===date&&f.siteId===site.id&&f.vacant&&f.vacantKey===vacantKey);
    if(ex){
      if(a)fpqSyncAffectation(ex,a);
      existing++;
      return;
    }
    const f=a?fpqEnsure(date,a.id):{id:uid("fpq"),date,agentId:"",heureArrivee:"",heureDepart:"",heureReleve:"",observations:"",createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),vacant:true,vacantKey};
    f.siteId=site.id;f.siteName=site.nom||site.intitule||"";f.poste=a?(a.affectationCourante?.poste||a.fonction||""):"APS";f.societe=a?(a.societe||site.societe||""):(site.societe||"");
    f.rotationPeriode=rot.periode;f.rotationGroupe=group;f.presenceOrder=Number.isFinite(+f.presenceOrder)?+f.presenceOrder:idx+1;f.heureArrivee="";f.heureDepart="";f.heureReleve=horaires.r;
    f.observations=vacant?`Poste ${periode==="nuit"?"nuit":"jour"} à couvrir · Affecter un APS à la prise`:`Généré automatiquement · Site actif · Groupe ${group}${rot.jour?" / "+rot.jour:""}${rot.regle?" / "+rot.regle:""}`.trim();
    f.generatedBy=session?.username||"system";f.generatedAt=new Date().toISOString();f.updatedAt=new Date().toISOString();
    if(!a)db.feuillePresence.push(f);
    added++;
  });
  if(window.SGDI?.pointage?.generateRotation){const backendSiteId=siteId?((db.sites||[]).find(s=>s.id===siteId)?.backendId||null):null;SGDI.pointage.generateRotation({presence_date:date,society:soc||null,site_id:backendSiteId,overwrite_generated:true}).catch(e=>console.warn("Génération SQL rotation indisponible",e))}
  saveDB();
  if(typeof logActivity==="function")logActivity("Génération feuille quotidienne",formatDate(date)+" · "+added+" ligne(s) · sites actifs: "+sites.length+" · filtre: "+(soc||"toutes")+" / "+(siteId||"tous sites"));
  toast(`Feuille générée : ${added} ligne(s) ajoutée(s)${replaced?` · ${replaced} ancienne(s) remplacée(s)`:''}${existing?` · ${existing} déjà validée(s)/conservée(s)`:''}`,"success");
  renderView();
}
function fpqAddAgentModal(date){
  const ag=(db.agents||[]).filter(a=>a.statut==="actif").sort((x,y)=>(x.nom||"").localeCompare(y.nom||""));
  openModal(`<h3 class="font-bold text-lg mb-3">➕ Ajouter un agent à la feuille du ${formatDate(date)}</h3>
    <form onsubmit="event.preventDefault();fpqConfirmAdd('${date}')">
      <label class="label">Agent *</label>
      <select class="select" name="agentId" ><option value="">— Choisir —</option>${ag.map(a=>`<option value="${a.id}">${escapeHTML((a.nom||"")+" "+(a.prenom||""))} [${escapeHTML(a.matricule||"—")}] · ${escapeHTML(a.societe||"")}</option>`).join("")}</select>
      <div class="flex gap-2 justify-end mt-4"><button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button><button class="btn btn-primary">Ajouter</button></div>
    </form>`);
}
async function fpqConfirmAdd(date){const fd=new FormData(document.querySelector(".modal-bg form"));const id=fd.get("agentId");if(!id)return;if(fpqGet(date,id)){toast("Cet agent figure déjà sur la feuille","error");return}try{await sgdiRunLegacyAction("add-presence-agent",{data:{date,agentId:id}});await sgdiPullState({silent:true});closeModal();toast("Agent ajouté par le backend","success");renderView()}catch(e){toast("Ajout refusé : "+(e.message||e),"error")}}
function fpqFonctionAbbr(label){
  const stop=new Set(["a","au","aux","d","de","des","du","et","en","l","la","le","les","un","une"]);
  const words=String(label||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").split(/[^A-Za-z0-9]+/).filter(Boolean);
  const letters=words.filter(w=>!stop.has(w.toLowerCase())).map(w=>w[0]).join("").toUpperCase();
  return letters||String(label||"—").slice(0,3).toUpperCase();
}
function fpqApsAgentsForPrise(date,currentId){
  const used=new Set((db.feuillePresence||[]).filter(f=>f.date===date&&f.agentId&&f.agentId!==currentId).map(f=>f.agentId));
  const standby=fpqRecoveryStandby(date,fpqCurrentSoc(),fpqCurrentSite()).map(r=>r.agent).filter(a=>!used.has(a.id));
  const aps=(db.agents||[]).filter(a=>a.statut==="actif"&&!used.has(a.id)&&fpqFonctionAbbr(a.affectationCourante?.poste||a.fonction||"")==="APS");
  const seen=new Set();
  return [...standby,...aps].filter(a=>{if(seen.has(a.id))return false;seen.add(a.id);return true}).sort((x,y)=>(x.matricule||x.nom||"").localeCompare(y.matricule||y.nom||""));
}
async function fpqAssignVacantAgent(rowId,agentId){
  const f=(db.feuillePresence||[]).find(x=>x.id===rowId);if(!f||!agentId)return;
  if(fpqGuardCloture(f.date))return;
  if((db.feuillePresence||[]).some(x=>x.date===f.date&&x.agentId===agentId&&x.id!==rowId)){toast("Cet employé figure déjà sur la feuille","error");renderView();return}
  const a=(db.agents||[]).find(x=>x.id===agentId);if(!a)return;
  const patch={presenceOrder:fpqLineOrder(f),agentId,vacant:false,siteManual:true,poste:a.affectationCourante?.poste||a.fonction||"APS",societe:f.societe||a.societe||""};
  try{await sgdiRunLegacyAction("assign-vacant-agent",{data:{date:f.date,agentId:f.agentId,patch}});await sgdiPullState({silent:true});toast("APS affecté par le backend","success");renderView()}catch(e){toast("Affectation refusée : "+(e.message||e),"error")}
}
function renderPointageQuotidien(){
  const date=fpqCurrentDate();const soc=fpqCurrentSoc();const sit=fpqCurrentSite();const fpqStatus=fpqCurrentStatus();const fpqFaction=fpqCurrentFaction();
  const allFpq=(db.feuillePresence||[]).filter(f=>f.date===date);
  allFpq.forEach(f=>{
    const a=(db.agents||[]).find(x=>x.id===f.agentId);
    if(!f.siteManual&&!f.valide&&a&&a.affectationCourante?.siteId&&(f.siteId!==a.affectationCourante.siteId||!f.siteName||!f.poste||!f.societe))fpqSyncAffectation(f,a);
  });
  const baseFpq=allFpq.filter(f=>(!soc||f.societe===soc)&&(!sit||f.siteId===sit)&&(!fpqFaction||f.rotationPeriode===fpqFaction||f.faction===fpqFaction));
  const filteredFpq=baseFpq.filter(f=>fpqStatusMatch(f,fpqStatus));
  const sites=db.sites||[];
  const sitesAvail=soc?sites.filter(s=>s.societe===soc):sites;
  const dateLabel=new Date(date).toLocaleDateString("fr-FR",{weekday:"long",day:"2-digit",month:"long",year:"numeric"});
  const isCloture=fpqIsCloture(date);
  const cInfo=fpqClotureInfo(date);
  const statusPill=isCloture
    ?`<span class="px-3 py-1 rounded-full text-xs font-black inline-flex items-center gap-1" style="background:#043970;color:#043970;border:1px solid #043970">🔒 CLÔTURÉE${cInfo?` · ${escapeHTML(cInfo.by||"")} · ${formatDate((cInfo.at||"").slice(0,10))}`:""}</span>`
    :`<span class="px-3 py-1 rounded-full text-xs font-black inline-flex items-center gap-1 fpq-banner-pulse" style="background:#fee2e2;color:#991b1b;border:1px solid #fca5a5">⏰ NON CLÔTURÉE</span>`;
  const clotureBtn=isCloture
    ?`<button class="btn btn-ghost text-xs" style="color:#b45309" onclick="fpqDecloturerJournee('${date}')">🔓 Déclôturer</button>`
    :`<button class="btn text-xs font-black shadow" style="background:#dc2626;color:white;border:0" onclick="fpqCloturerJournee('${date}')">🔒 Clôturer la journée</button>`;
  const lk=isCloture?"disabled":"";
  const filterBar=`<div class="card p-4 mb-4 ${isCloture?"fpq-locked-card":""}">
    <div class="flex flex-wrap items-center gap-3">
      <div><label class="label">Date</label><input type="date" class="input" value="${date}" onchange="setFpqDate(this.value)"/></div>
      <div><label class="label">Société</label><select class="select" onchange="setFpqSociete(this.value);setFpqSite('')"><option value="" ${!soc?"selected":""}>🏢 Toutes les sociétés</option>${SOCIETES.map(s=>`<option ${soc===s?"selected":""}>${s}</option>`).join("")}</select></div>
      <div><label class="label">Site</label><select class="select" onchange="setFpqSite(this.value)"><option value="" ${!sit?"selected":""}>📍 Tous les sites</option>${sitesAvail.map(s=>`<option value="${s.id}" ${sit===s.id?"selected":""}>${escapeHTML(s.nom||s.intitule||"Site "+s.id)}</option>`).join("")}</select></div>
      <div><label class="label">Faction</label><select class="select" onchange="setFpqFaction(this.value)"><option value="" ${!fpqFaction?"selected":""}>Toutes</option><option value="jour" ${fpqFaction==="jour"?"selected":""}>Jour</option><option value="nuit" ${fpqFaction==="nuit"?"selected":""}>Nuit</option></select></div>
      <div class="flex-1"></div>
      <button class="btn btn-primary text-xs ${isCloture?"fpq-locked":""}" ${lk} onclick="fpqGenerateAuto('${date}','${soc.replace(/'/g,"\\'")}','${sit.replace(/'/g,"\\'")}')">Générer feuille de présence</button>
      <button class="btn btn-secondary text-xs ${isCloture?"fpq-locked":""}" ${lk} onclick="fpqAddAgentModal('${date}')">➕ Ajouter agent</button>
      <button class="btn btn-secondary text-xs ${isCloture?"fpq-locked":""}" ${lk} onclick="fpqAddAllAgents('${date}','${soc.replace(/'/g,"\\'")}')">👥 Ajouter tous les actifs</button>
      <button class="btn btn-ghost text-xs ${isCloture?"fpq-locked":""}" ${lk} onclick="fpqDuplicateYesterday('${date}','${soc.replace(/'/g,"\\'")}')">📋 Copier la veille</button>
      <button class="btn btn-ghost text-xs ${isCloture?"fpq-locked":""}" ${lk} onclick="fpqClearAll('${date}','${soc.replace(/'/g,"\\'")}')">🗑 Vider la feuille</button>
      <button class="btn btn-ghost text-xs text-red-600 ${isCloture?"fpq-locked":""}" ${lk} onclick="fpqSupprimerFeuille('${date}')">Supprimer feuille de présence</button>
      <button class="btn btn-ghost text-xs" onclick="window.print()">🖨 Imprimer</button>
      ${clotureBtn}
    </div>
    <div class="mt-3 text-sm font-semibold text-slate-700 flex items-center gap-2 flex-wrap">📅 <span class="capitalize">${dateLabel}</span> ${soc?` · 🏢 ${escapeHTML(soc)}`:""} ${sit?` · 📍 ${escapeHTML((sites.find(x=>x.id===sit)||{}).nom||"")}`:""} ${statusPill}</div>
  </div>`;
  const standbyPanel=fpqStandbyPanelHTML(date,soc,sit);
  if(!baseFpq.length)return filterBar+standbyPanel+`<div class="card p-8 text-center"><div class="text-5xl mb-3">📋</div><div class="font-bold text-slate-700 mb-2">Aucune ligne de présence pour cette date</div><div class="text-sm text-slate-500 mb-4">Ajoutez des agents avec les boutons ci-dessus, ou copiez la feuille de la veille.</div><div class="flex gap-2 justify-center"><button class="btn btn-secondary" onclick="fpqAddAgentModal('${date}')">➕ Ajouter un agent</button><button class="btn btn-primary" onclick="fpqAddAllAgents('${date}','${soc.replace(/'/g,"\\'")}')">👥 Ajouter tous les actifs</button></div></div>`;
  filteredFpq.sort((x,y)=>{const sx=(x.siteName||"").localeCompare(y.siteName||"");if(sx)return sx;const ox=fpqLineOrder(x),oy=fpqLineOrder(y);if(ox!==oy)return ox-oy;return String(x.id||"").localeCompare(String(y.id||""))});
  const totalPresent=baseFpq.filter(f=>fpqPresenceCode(f.heureArrivee)==="P").length;
  const totalArr=baseFpq.filter(f=>fpqPresenceCode(f.heureArrivee)).length;
  const totalAbs=baseFpq.filter(f=>["A","AB"].includes(fpqPresenceCode(f.heureArrivee))).length;
  const totalRel=baseFpq.filter(f=>f.heureReleve).length;
  const totalRecup=baseFpq.filter(f=>fpqPresenceCode(f.heureArrivee)==="R").length;
  const activeCard=s=>fpqStatus===s?"outline:3px solid #0f172a;box-shadow:0 0 0 4px rgba(15,23,42,.12);":"";
  const summary=`<div class="grid grid-cols-2 md:grid-cols-5 gap-2 mb-4">
    <button class="card p-3 text-center" style="background:#dcfce7;cursor:pointer;border:0;${activeCard("present")}" onclick="setFpqStatus('${fpqStatus==="present"?"":"present"}')" title="Afficher les présents"><div class="text-[10px] uppercase tracking-wider font-semibold text-emerald-700">Présents</div><div class="text-2xl font-black text-emerald-700">🟢 ${totalPresent}</div></button>
    <button class="card p-3 text-center" style="background:#fee2e2;cursor:pointer;border:0;${activeCard("absence")}" onclick="setFpqStatus('${fpqStatus==="absence"?"":"absence"}')" title="Afficher les absences"><div class="text-[10px] uppercase tracking-wider font-semibold text-red-700">Absence</div><div class="text-2xl font-black text-red-700">🚫 ${totalAbs}</div></button>
    <button class="card p-3 text-center" style="background:#ecfdf5;cursor:pointer;border:0;${activeCard("saisie")}" onclick="setFpqStatus('${fpqStatus==="saisie"?"":"saisie"}')" title="Afficher les situations saisies"><div class="text-[10px] uppercase tracking-wider font-semibold text-emerald-700">Situations saisies</div><div class="text-2xl font-black text-emerald-700">${totalArr}</div></button>
    <button class="card p-3 text-center" style="background:#fef3c7;cursor:pointer;border:0;${activeCard("releve")}" onclick="setFpqStatus('${fpqStatus==="releve"?"":"releve"}')" title="Afficher les lignes avec heure de relève"><div class="text-[10px] uppercase tracking-wider font-semibold text-amber-700">Heures relève saisies</div><div class="text-2xl font-black text-amber-700">${totalRel}</div></button>
    <button class="card p-3 text-center" style="background:#e2e8f0;cursor:pointer;border:0;${activeCard("recup")}" onclick="setFpqStatus('${fpqStatus==="recup"?"":"recup"}')" title="Afficher les récupérations"><div class="text-[10px] uppercase tracking-wider font-semibold text-slate-700">Liste personnel en récupération disponibles</div><div class="text-2xl font-black text-slate-700">♻️ ${totalRecup}</div></button>
  </div>${fpqStatus?`<div class="mb-3 flex justify-end"><button class="btn btn-ghost text-xs" onclick="setFpqStatus('')">Afficher toutes les lignes (${baseFpq.length})</button></div>`:""}`;
  const lockCls=isCloture?"fpq-locked":"";
  const alertSites=new Set(filteredFpq.filter(fpqRelieveDueWithoutPointage).map(f=>f.siteId||f.siteName||""));
  let lastSiteKey="";
  const rows=filteredFpq.map((f,i)=>{
    const a=db.agents.find(x=>x.id===f.agentId);
    const rowLocked=isCloture||!!f.valide;
    const rowLockCls=rowLocked?"fpq-locked":"";
    const rowRo=rowLocked?"readonly":"";
    const rowDis=rowLocked?"disabled":"";
    const validInfo=f.valide?`<div class="text-[10px] font-bold mt-1" style="color:#047857">Validée ${f.valideBy?`par ${escapeHTML(f.valideBy)}`:""}</div>`:"";
    const siteKey=f.siteId||f.siteName||"";
    const showSite=siteKey!==lastSiteKey;
    lastSiteKey=siteKey;
    const mouvementLabel=showSite?(f.siteName?escapeHTML(f.siteName):"Site non défini"):"";
    const siteAlert=showSite&&alertSites.has(siteKey);
    const siteLabel=siteAlert?`<span class="fpq-alert-marker"><span class="fpq-alert-dot"></span>${mouvementLabel}</span>`:mouvementLabel;
    const fonctionAbbr=fpqFonctionAbbr(f.poste||a?.fonction||"APS");
    const apsOptions=(!a&&!rowLocked)?fpqApsAgentsForPrise(date,"").map(x=>`<option value="${x.id}">${escapeHTML((x.matricule?x.matricule+" · ":"")+(x.nom||"")+" "+(x.prenom||""))}</option>`).join(""):"";
    const agentCell=a?`<div class="font-bold">${escapeHTML((a.nom||"")+" "+(a.prenom||""))} <span class="font-mono text-[10px] px-1.5 py-0.5 rounded ml-1 align-middle" style="background:#04397015;color:#043970;font-weight:700">${escapeHTML(a.matricule||"—")}</span> <span class="font-mono text-[10px] px-1.5 py-0.5 rounded font-black align-middle" style="background:#f1f5f9;color:#334155" title="${escapeHTML(f.poste||a.fonction||"")}">${escapeHTML(fonctionAbbr)}</span></div>`:`<select class="select text-xs" style="background:#fee2e2;color:#991b1b;border-color:#ef4444;font-weight:800" ${rowDis} onchange="fpqAssignVacantAgent('${f.id}',this.value)"><option value="">— Affecter APS à la prise —</option>${apsOptions}</select>`;
    return`<tr class="border-t">
      <td class="px-2 py-1 text-xs text-center text-slate-400 font-mono">${i+1}</td>
      <td class="px-2 py-1 ${siteAlert?"fpq-site-alert":""}"><div class="text-xs font-bold ${siteAlert?"":"text-slate-700"}">${siteLabel}</div>${showSite&&f.mouvementType?`<div class="text-[10px] font-semibold ${siteAlert?"":"text-slate-600"}">${escapeHTML(f.mouvementType)}</div>`:""}</td>
      <td class="px-2 py-1 text-xs">${agentCell}</td>
      <td class="px-2 py-1"><select class="select text-xs ${rowLockCls}" style="${fpqPresenceSelectStyle(f.heureArrivee||"")}" ${rowDis||(!a?"disabled":"")} title="${!a?"Affectez d'abord un APS":""}" onchange="fpqSetRowField('${f.id}','heureArrivee',this.value);renderView()">${fpqPresenceOptions(f.heureArrivee||"")}</select></td>
      <td class="px-2 py-1"><input type="time" class="input text-xs ${rowLockCls}" style="min-width:90px;background:${f.heureReleve?"#f1f5f9":""}" ${rowRo} value="${f.heureReleve||""}" onchange="fpqSetRowField('${f.id}','heureReleve',this.value)"/></td>
      <td class="px-2 py-1 text-center"><div class="flex gap-1 justify-center items-center"><button class="btn btn-secondary text-xs ${rowLockCls}" ${rowDis||(!a?"disabled":"")} onclick="fpqOpenMouvement('${date}','${f.agentId}')">Mouvement</button><input class="input text-xs ${rowLockCls}" style="min-width:180px" ${rowRo} placeholder="Observations…" value="${escapeHTML(f.observations||"")}" onchange="fpqSetRowField('${f.id}','observations',this.value)"/>${f.valide?`<button class="btn btn-ghost text-xs" title="Déverrouiller" onclick="fpqDevaliderLigne('${date}','${f.agentId}')">🔓</button>`:`<button class="btn btn-primary text-xs ${lockCls}" ${isCloture||!a?"disabled":""} onclick="fpqValiderLigne('${date}','${f.agentId}')">Valider</button>`}<button class="btn btn-ghost text-xs text-red-600 ${rowLockCls}" ${rowDis} title="${rowLocked?"Ligne verrouillée":"Retirer"}" onclick="fpqDeleteRow('${f.id}')">✕</button></div>${validInfo}</td>
    </tr>`;
  }).join("");
  return filterBar+standbyPanel+summary+`<div class="card p-2"><div class="text-sm font-semibold mb-2 px-2">Feuille de présence — <span class="capitalize">${dateLabel}</span> · ${filteredFpq.length} ligne${filteredFpq.length>1?"s":""}</div>
    <div style="overflow-x:auto"><table class="w-full text-sm" style="border-collapse:collapse">
      <thead><tr style="background:#f1f5f9"><th class="px-2 py-2 text-[11px] font-bold text-center" style="border-bottom:2px solid #cbd5e1;width:30px">#</th><th class="px-2 py-2 text-[11px] font-bold text-left" style="border-bottom:2px solid #cbd5e1">📍 Site</th><th class="px-2 py-2 text-[11px] font-bold text-left" style="border-bottom:2px solid #cbd5e1">👤 Nom Prénom</th><th class="px-2 py-2 text-[11px] font-bold text-left" style="border-bottom:2px solid #cbd5e1;background:#043970">🟢 Heure d'arrivée</th><th class="px-2 py-2 text-[11px] font-bold text-left" style="border-bottom:2px solid #cbd5e1;background:#043970">🔄 Heure de relève</th><th class="px-2 py-2 text-[11px] font-bold text-center" style="border-bottom:2px solid #cbd5e1;width:360px">Action</th></tr></thead>
      <tbody>${rows}</tbody>
    </table></div>
  </div>`;
}
function ptCycleCell(agentId,ym,day){const s=ptEnsureSheet(agentId,ym);if(s.valide){toast("🔒 Pointage validé · déverrouillez d'abord","error");return}const k=String(day).padStart(2,"0");const cur=s.days[k]||"";const order=["","P","A","M","S","C","R"];const idx=order.indexOf(cur);const next=order[(idx+1)%order.length];ptSetCell(agentId,ym,day,next);renderView()}
function ptSetCellPrompt(agentId,ym,day){const s=ptEnsureSheet(agentId,ym);if(s.valide){toast("🔒 Pointage validé · déverrouillez d'abord","error");return}const code=prompt("Code (P=Présent, A=Absent, M=Maladie, S=Suspendu, C=Congé, R=Repos, vide=effacer)","");if(code===null)return;const c=code.toUpperCase().trim();if(c&&!POINTAGE_CODES[c]){toast("Code invalide","error");return}ptSetCell(agentId,ym,day,c);renderView()}
function ptFillRow(agentId,ym,code){const s=ptEnsureSheet(agentId,ym);if(s.valide){toast("🔒 Pointage validé","error");return}if(!confirm("Remplir toute la ligne avec « "+code+" » ?"))return;const days=ptDaysInMonth(ym);for(let d=1;d<=days;d++)ptSetCell(agentId,ym,d,code);renderView()}
function ptClearRow(agentId,ym){const s=ptGetSheet(agentId,ym);if(s&&s.valide){toast("🔒 Pointage validé","error");return}if(!confirm("Effacer toute la ligne ?"))return;if(s){s.days={};s.updatedAt=new Date().toISOString();saveDB()}renderView()}
function ptCount(sheet,code){if(!sheet)return 0;return Object.values(sheet.days||{}).filter(v=>v===code).length}
function ptCellHTML(agentId,ym,day,code){const c=POINTAGE_CODES[code];const bg=c?c.bg:"";const fg=c?c.color:"#64748b";const txt=code||"·";return`<td class="text-center align-middle" style="border:1px solid #e2e8f0;padding:0;width:28px;min-width:28px;max-width:28px;background:${bg}"><button onclick="ptCycleCell('${agentId}','${ym}',${day})" oncontextmenu="event.preventDefault();ptSetCellPrompt('${agentId}','${ym}',${day})" title="Clic = cycle · Clic droit = saisir code" style="width:100%;height:28px;border:0;background:transparent;color:${fg};font-weight:800;font-family:ui-monospace,monospace;cursor:pointer">${txt}</button></td>`}
function renderPointageDashboard(){
  const ym=ptCurrentMonth();const soc=ptCurrentSoc();const days=ptDaysInMonth(ym);const todayDate=today();
  const allAg=(db.agents||[]).filter(a=>!["sortant","demissionne","licencie","archive"].includes(a.statut));
  const ag=soc?allAg.filter(a=>a.societe===soc):allAg;
  const sheets=ag.map(a=>ptGetSheet(a.id,ym)).filter(Boolean);
  const valid=sheets.filter(s=>s.valide).length;
  const tot={P:0,A:0,M:0,S:0,C:0,R:0};
  sheets.forEach(sh=>Object.values(sh.days||{}).forEach(v=>{if(tot[v]!==undefined)tot[v]++}));
  const expected=ag.length*days;const filled=sheets.reduce((n,sh)=>n+Object.keys(sh.days||{}).length,0);
  const coverage=expected?Math.round(filled*100/expected):0;
  const fpq=(db.feuillePresence||[]).filter(f=>f.date===todayDate&&(!soc||f.societe===soc));
  const fpqDone=fpq.filter(f=>fpqPresenceCode(f.heureArrivee)).length;
  const fpqRate=fpq.length?Math.round(fpqDone*100/fpq.length):0;
  const unclosed=[...new Set((db.feuillePresence||[]).map(f=>f.date).filter(Boolean))].filter(d=>!fpqIsCloture(d));
  const kpi=(label,n,route,color,sub)=>`<button type="button" class="card p-4 text-left kpi-clickable" onclick="navigate('${route}')" style="border:1px solid ${color}55;background:#fff"><div class="text-xs uppercase font-black text-slate-500">${label}</div><div class="text-3xl font-black mt-1" style="color:${color}">${n}</div><div class="text-xs text-slate-400 mt-1">${sub||"Cliquer pour ouvrir"}</div></button>`;
  const codeCards=Object.entries(POINTAGE_CODES).map(([k,v])=>`<button type="button" onclick="navigate('pointage/stats')" class="card p-3 text-center" style="background:${v.bg};border:1px solid ${v.color}33"><div class="text-[10px] uppercase font-black" style="color:${v.color}">${v.label}</div><div class="text-2xl font-black" style="color:${v.color}">${tot[k]||0}</div></button>`).join("");
  return `<div class="flex items-start justify-between gap-3 mb-5 flex-wrap"><div><h1 class="text-2xl font-black uppercase">POINTAGE - TABLEAU DE BORD</h1><p class="text-sm text-slate-500">Synthèse mensuelle et feuille de présence quotidienne · ${soc?escapeHTML(soc):"Toutes sociétés"}</p></div><div class="flex gap-2"><button class="btn btn-primary" onclick="navigate('pointage/quotidien')">Feuille quotidienne</button><button class="btn btn-secondary" onclick="navigate('pointage/saisie')">Saisie mensuelle</button></div></div>
    <div class="grid grid-5 gap-3 mb-5">
      ${kpi("Agents suivis",ag.length,"pointage/saisie","#043970","Effectif filtré")}
      ${kpi("Couverture",coverage+"%","pointage/stats",coverage>=80?"#16a34a":"#dc2626","Mois en cours")}
      ${kpi("Pointages validés",valid,"pointage/saisie","#7c3aed","Lignes verrouillées")}
      ${kpi("Présence du jour",fpqRate+"%","pointage/quotidien",fpqRate>=80?"#16a34a":"#f59e0b",fpqDone+"/"+(fpq.length||0)+" lignes")}
      ${kpi("Feuilles non clôturées",unclosed.length,"pointage/quotidien",unclosed.length?"#dc2626":"#16a34a","À contrôler")}
    </div>
    <div class="grid grid-2 gap-4 mb-5"><div class="card p-4"><h3 class="font-black mb-3">Répartition des codes</h3><div class="grid grid-cols-3 gap-2">${codeCards}</div></div><div class="card p-4"><h3 class="font-black mb-3">Accès rapides</h3><div class="grid gap-2"><button class="btn btn-secondary justify-start" onclick="navigate('pointage/quotidien')">📅 Feuille de présence quotidienne</button><button class="btn btn-secondary justify-start" onclick="navigate('pointage/saisie')">📝 Saisie pointage mensuel</button><button class="btn btn-secondary justify-start" onclick="navigate('pointage/recap')">👤 Récap par agent</button><button class="btn btn-secondary justify-start" onclick="navigate('pointage/societe')">🏢 Récap par société</button><button class="btn btn-secondary justify-start" onclick="navigate('pointage/legende')">🎨 Légende & codes</button></div></div></div>`;
}

function renderPointage(view,sub,arg){
  if(!canAccess("pointage")){view.innerHTML=`<div class="card p-6">🔐 Accès refusé</div>`;return}
  const tabsHTML=POINTAGE_TABS.map(([k,l])=>`<button onclick="navigate('pointage/${k}')" class="px-3 py-2 text-sm font-semibold border-b-2 ${sub===k?"border-cyan-600 text-cyan-700":"border-transparent text-slate-500 hover:text-slate-800"}">${l}</button>`).join("");
  const head=sub==="dashboard"?"":`<div class="flex items-center justify-between mb-4 flex-wrap gap-3"><h1 class="text-2xl font-bold">🕒 Pointage du personnel</h1></div><div class="flex gap-1 mb-5 border-b border-slate-200 overflow-x-auto">${tabsHTML}</div>`;
  let body="";
  if(sub==="dashboard")body=renderPointageDashboard();
  else if(sub==="quotidien")body=renderPointageQuotidien();
  else if(sub==="saisie")body=renderPointageSaisie();
  else if(sub==="recap")body=renderPointageRecap(arg);
  else if(sub==="societe")body=renderPointageSociete();
  else if(sub==="stats")body=renderPointageStats();
  else if(sub==="legende")body=renderPointageLegende();
  else body=renderPointageSaisie();
  view.innerHTML=head+body;
}
function renderPointageSaisie(){
  const ym=ptCurrentMonth();const soc=ptCurrentSoc();const days=ptDaysInMonth(ym);
  const syncChanged=ptSyncFeuillePresenceMonth(ym);if(syncChanged)saveDB();
  const allAg=(db.agents||[]).filter(a=>!["sortant","demissionne","licencie","archive"].includes(a.statut));
  const ag=soc?allAg.filter(a=>a.societe===soc):allAg;
  ag.sort((x,y)=>(x.nom||"").localeCompare(y.nom||"")||(x.prenom||"").localeCompare(y.prenom||""));
  const [yr,mo]=ym.split("-").map(Number);
  const monthLabel=new Date(yr,mo-1,1).toLocaleDateString("fr-FR",{month:"long",year:"numeric"});
  const dayHeaders=Array.from({length:days},(_,i)=>{const d=i+1;const date=new Date(yr,mo-1,d);const wd=date.getDay();const we=wd===0||wd===6;return`<th class="text-center text-[10px] font-bold ${we?"text-red-600 bg-red-50":"text-slate-600"}" style="border:1px solid #e2e8f0;padding:4px 0;width:28px;min-width:28px;max-width:28px">${String(d).padStart(2,"0")}</th>`}).join("");
  const legende=Object.entries(POINTAGE_CODES).map(([k,v])=>`<span class="inline-flex items-center gap-1 px-2 py-1 rounded text-xs font-semibold" style="background:${v.bg};color:${v.color}"><span class="font-mono font-black">${k}</span>${v.label}</span>`).join(" ");
  const filterBar=`<div class="card p-4 mb-4"><div class="flex flex-wrap items-center gap-3">
    <div><label class="label">Mois</label><input type="month" class="input" value="${ym}" onchange="setPtMonth(this.value)"/></div>
    <div><label class="label">Société</label><select class="select" onchange="setPtSociete(this.value)"><option value="" ${!soc?"selected":""}>🏢 Toutes les sociétés</option>${SOCIETES.map(s=>`<option ${soc===s?"selected":""}>${s}</option>`).join("")}</select></div>
    <div class="flex-1"></div>
    <button class="btn btn-primary text-xs" style="background:#043970;border-color:#043970" onclick="ptValiderTous('${ym}','${soc.replace(/'/g,"\\'")}')">✅ Valider tous les pointages</button>
    <button class="btn btn-ghost text-xs" onclick="ptDevaliderTous('${ym}','${soc.replace(/'/g,"\\'")}')">🔓 Tout déverrouiller</button>
    <button class="btn btn-ghost text-xs" onclick="window.print()">🖨 Imprimer</button>
  </div>
  <div class="mt-3 flex flex-wrap items-center gap-2 text-xs"><span class="font-semibold text-slate-600">Légende :</span>${legende}</div>
  <div class="text-[11px] text-slate-500 mt-2">Astuce : <strong>Clic</strong> sur une case = cycle des codes (·→P→A→M→S→C→R) · <strong>Clic droit</strong> = saisir directement · <strong>✅ Valider</strong> verrouille le pointage</div>
  </div>`;
  if(!ag.length)return filterBar+`<div class="card p-6 text-center text-slate-500">Aucun agent ${soc?`pour ${escapeHTML(soc)}`:""} sur cette période.</div>`;
  const rows=ag.map(a=>{
    const sheet=ptGetSheet(a.id,ym);
    const isValide=!!(sheet&&sheet.valide);
    const cells=Array.from({length:days},(_,i)=>ptCellHTML(a.id,ym,i+1,(sheet?.days||{})[String(i+1).padStart(2,"0")])).join("");
    const nP=ptCount(sheet,"P");const nA=ptCount(sheet,"A");const nM=ptCount(sheet,"M");const nS=ptCount(sheet,"S");const nC=ptCount(sheet,"C");const nR=ptCount(sheet,"R");
    const valideTitle=isValide?`✓ Validé par ${escapeHTML(sheet.valideBy||"?")} le ${sheet.valideAt?new Date(sheet.valideAt).toLocaleString("fr-FR"):""}`:"";
    const validBtn=isValide?`<button class="btn btn-ghost text-[10px]" style="color:#dc2626" title="Déverrouiller" onclick="ptDevaliderSheet('${a.id}','${ym}')">🔓</button>`:`<button class="btn btn-primary text-[10px]" style="background:#043970;border-color:#043970" title="Valider le pointage" onclick="ptValiderSheet('${a.id}','${ym}')">✅ Valider</button>`;
    const lockBadge=isValide?`<span class="pill" style="background:#043970;color:#fff;font-size:9px;padding:1px 5px" title="${valideTitle}">🔒 VALIDÉ</span>`:"";
    return`<tr ${isValide?'style="background:#043970"':""}>
      <td class="px-2 py-1 text-xs whitespace-nowrap" style="border:1px solid #e2e8f0;background:${isValide?"#dcfce7":"#f8fafc"};position:sticky;left:0;z-index:1"><div class="font-bold">${escapeHTML((a.nom||"")+" "+(a.prenom||""))} <span class="font-mono text-[10px] px-1.5 py-0.5 rounded" style="background:#04397015;color:#043970;font-weight:700">${escapeHTML(a.matricule||"—")}</span> ${lockBadge}</div><div class="text-[10px] text-slate-500">${escapeHTML(a.societe||"")}</div></td>
      ${cells}
      <td class="px-2 text-center text-xs font-bold" style="border:1px solid #e2e8f0;background:#dcfce7;color:#166534">${nP}</td>
      <td class="px-2 text-center text-xs font-bold" style="border:1px solid #e2e8f0;background:#fee2e2;color:#991b1b">${nA}</td>
      <td class="px-2 text-center text-xs font-bold" style="border:1px solid #e2e8f0;background:#fef3c7;color:#92400e">${nM}</td>
      <td class="px-2 text-center text-xs font-bold" style="border:1px solid #e2e8f0;background:#ede9fe;color:#5b21b6">${nS}</td>
      <td class="px-2 text-center text-xs font-bold" style="border:1px solid #e2e8f0;background:#dbeafe;color:#1e40af">${nC}</td>
      <td class="px-2 text-center text-xs font-bold" style="border:1px solid #e2e8f0;background:#e2e8f0;color:#334155">${nR}</td>
      <td class="px-1 text-center" style="border:1px solid #e2e8f0;white-space:nowrap">
        ${isValide?"":`<button class="btn btn-ghost text-[10px]" title="Tout Présent" onclick="ptFillRow('${a.id}','${ym}','P')">P✓</button><button class="btn btn-ghost text-[10px]" title="Tout effacer" onclick="ptClearRow('${a.id}','${ym}')">✕</button>`}
        ${validBtn}
      </td>
    </tr>`;
  }).join("");
  const totSheets=ag.map(a=>ptGetSheet(a.id,ym)).filter(Boolean);const totValide=totSheets.filter(s=>s.valide).length;
  return filterBar+`<div class="card p-3 mb-3" style="background:linear-gradient(90deg,#043970,#fff)"><div class="flex items-center justify-between flex-wrap gap-2"><div class="text-sm"><span class="font-bold text-emerald-700">${totValide}</span> / <span class="font-bold">${ag.length}</span> pointages validés pour cette période</div><div class="text-[11px] text-slate-500">Statut de validation</div></div></div>
  <div class="card p-2"><div class="text-sm font-semibold mb-2 px-2">Tableau de pointage — <span class="capitalize">${monthLabel}</span> (${days} jours) · ${ag.length} agent${ag.length>1?"s":""}</div>
    <div style="overflow-x:auto;max-width:100%"><table class="w-full text-xs" style="border-collapse:collapse">
      <thead><tr style="background:#f1f5f9"><th class="text-left px-2 py-2 text-[11px] font-bold" style="border:1px solid #e2e8f0;position:sticky;left:0;background:#f1f5f9;z-index:2;min-width:220px">Agent</th>${dayHeaders}<th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;background:#dcfce7;color:#166534;width:32px">P</th><th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;background:#fee2e2;color:#991b1b;width:32px">A</th><th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;background:#fef3c7;color:#92400e;width:32px">M</th><th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;background:#ede9fe;color:#5b21b6;width:32px">S</th><th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;background:#dbeafe;color:#1e40af;width:32px">C</th><th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;background:#e2e8f0;color:#334155;width:32px">R</th><th class="text-center text-[10px] font-bold" style="border:1px solid #e2e8f0;width:130px">Actions</th></tr></thead>
      <tbody>${rows}</tbody>
    </table></div></div>`;
}
function renderPointageRecap(agentId){
  const ym=ptCurrentMonth();const soc=ptCurrentSoc();
  const allAg=(db.agents||[]).slice().sort((x,y)=>(x.nom||"").localeCompare(y.nom||""));
  const ag=soc?allAg.filter(a=>a.societe===soc):allAg;
  const cur=agentId?db.agents.find(a=>a.id===agentId):null;
  const filterBar=`<div class="card p-4 mb-4"><div class="flex flex-wrap items-center gap-3">
    <div><label class="label">Mois</label><input type="month" class="input" value="${ym}" onchange="setPtMonth(this.value)"/></div>
    <div><label class="label">Société</label><select class="select" onchange="setPtSociete(this.value)"><option value="" ${!soc?"selected":""}>🏢 Toutes les sociétés</option>${SOCIETES.map(s=>`<option ${soc===s?"selected":""}>${s}</option>`).join("")}</select></div>
    <div class="flex-1"><label class="label">Agent</label><select class="select" onchange="navigate('pointage/recap/'+this.value)"><option value="">— Sélectionner un agent —</option>${ag.map(a=>`<option value="${a.id}" ${cur&&cur.id===a.id?"selected":""}>${escapeHTML((a.nom||"")+" "+(a.prenom||""))} [${escapeHTML(a.matricule||"—")}] · ${escapeHTML(a.societe||"")}</option>`).join("")}</select></div>
  </div></div>`;
  if(!cur)return filterBar+`<div class="card p-6 text-center text-slate-500">Sélectionnez un agent ci-dessus pour voir son récapitulatif mensuel.</div>`;
  const sheet=ptGetSheet(cur.id,ym);
  const days=ptDaysInMonth(ym);const [yr,mo]=ym.split("-").map(Number);
  const tableCells=Array.from({length:days},(_,i)=>{const d=i+1;const k=String(d).padStart(2,"0");const code=(sheet?.days||{})[k]||"";const c=POINTAGE_CODES[code];const date=new Date(yr,mo-1,d);const wd=date.getDay();const we=wd===0||wd===6;const wdName=["Dim","Lun","Mar","Mer","Jeu","Ven","Sam"][wd];return`<tr ${we?'style="background:#fef2f2"':""}><td class="px-2 py-1 font-mono text-xs" style="border:1px solid #e2e8f0">${k}/${String(mo).padStart(2,"0")}</td><td class="px-2 py-1 text-xs ${we?"text-red-600 font-semibold":""}" style="border:1px solid #e2e8f0">${wdName}</td><td class="px-2 py-1 text-center font-bold" style="border:1px solid #e2e8f0;background:${c?c.bg:""};color:${c?c.color:"#94a3b8"}">${code||"·"}</td><td class="px-2 py-1 text-xs" style="border:1px solid #e2e8f0">${c?c.label:"—"}</td></tr>`}).join("");
  const counts=["P","A","M","S","C","R"].map(k=>{const c=POINTAGE_CODES[k];const n=ptCount(sheet,k);return`<div class="card p-3 text-center" style="background:${c.bg}"><div class="text-[10px] uppercase tracking-wider font-semibold" style="color:${c.color}">${c.label} (${k})</div><div class="text-2xl font-black" style="color:${c.color}">${n}</div></div>`}).join("");
  const total=Object.keys(sheet?.days||{}).length;
  const isValide=!!(sheet&&sheet.valide);
  const validBlock=isValide?`<div class="card p-3 mb-3" style="background:#dcfce7;border:2px solid #043970"><div class="flex items-center justify-between"><div><div class="text-xs uppercase tracking-wider font-bold text-emerald-700">🔒 Pointage validé</div><div class="text-xs text-slate-600">Validé par <strong>${escapeHTML(sheet.valideBy||"?")}</strong> le ${sheet.valideAt?new Date(sheet.valideAt).toLocaleString("fr-FR"):""}</div></div><button class="btn btn-ghost text-xs" onclick="ptDevaliderSheet('${cur.id}','${ym}')">🔓 Déverrouiller</button></div></div>`:`<div class="card p-3 mb-3" style="background:#043970;border:2px dashed #043970"><div class="flex items-center justify-between"><div><div class="text-xs uppercase tracking-wider font-bold text-amber-700">⏳ Non validé</div><div class="text-xs text-slate-600">Cliquez sur « Valider » pour verrouiller ce pointage.</div></div><button class="btn btn-primary text-xs" style="background:#043970;border-color:#043970" onclick="ptValiderSheet('${cur.id}','${ym}')">✅ Valider le pointage</button></div></div>`;
  return filterBar+validBlock+`<div class="grid grid-cols-2 md:grid-cols-6 gap-2 mb-4">${counts}</div>
    <div class="card p-4 mb-4"><div class="flex justify-between items-center"><div><div class="text-xs text-slate-500">Agent</div><div class="font-bold text-lg">${escapeHTML((cur.nom||"")+" "+(cur.prenom||""))} <span class="font-mono text-sm px-2 py-0.5 rounded ml-2" style="background:#04397015;color:#043970">${escapeHTML(cur.matricule||"—")}</span></div><div class="text-xs text-slate-500">${escapeHTML(cur.societe||"")} · ${escapeHTML(cur.fonction||"")}</div></div><div class="text-right"><div class="text-xs text-slate-500">Jours renseignés</div><div class="text-3xl font-black text-cyan-600">${total}/${days}</div></div></div></div>
    <div class="card p-2"><div class="text-sm font-semibold mb-2 px-2">Détail jour par jour — ${new Date(yr,mo-1,1).toLocaleDateString("fr-FR",{month:"long",year:"numeric"})}</div>
      <table class="w-full text-sm"><thead><tr style="background:#f1f5f9"><th class="text-left px-2 py-2 text-xs font-bold" style="border:1px solid #e2e8f0">Date</th><th class="text-left px-2 py-2 text-xs font-bold" style="border:1px solid #e2e8f0">Jour</th><th class="text-center px-2 py-2 text-xs font-bold" style="border:1px solid #e2e8f0">Code</th><th class="text-left px-2 py-2 text-xs font-bold" style="border:1px solid #e2e8f0">Statut</th></tr></thead><tbody>${tableCells}</tbody></table>
    </div>`;
}
function renderPointageSociete(){
  const ym=ptCurrentMonth();const days=ptDaysInMonth(ym);
  const filterBar=`<div class="card p-4 mb-4"><div class="flex flex-wrap items-center gap-3"><div><label class="label">Mois</label><input type="month" class="input" value="${ym}" onchange="setPtMonth(this.value)"/></div></div></div>`;
  const rows=SOCIETES.map(s=>{
    const ag=(db.agents||[]).filter(a=>a.societe===s&&!["sortant","demissionne","licencie","archive"].includes(a.statut));
    const sheets=ag.map(a=>ptGetSheet(a.id,ym)).filter(Boolean);
    const tot={P:0,A:0,M:0,S:0,C:0,R:0};sheets.forEach(sh=>{Object.values(sh.days||{}).forEach(v=>{if(tot[v]!==undefined)tot[v]++})});
    const totalCells=ag.length*days;const renseigne=sheets.reduce((acc,sh)=>acc+Object.keys(sh.days||{}).length,0);const tx=totalCells?Math.round(renseigne*100/totalCells):0;
    return`<tr class="border-t"><td class="p-3 font-bold">${escapeHTML(s)}</td><td class="p-3 text-center">${ag.length}</td><td class="p-3 text-center font-bold text-emerald-600">${tot.P}</td><td class="p-3 text-center font-bold text-red-600">${tot.A}</td><td class="p-3 text-center font-bold text-amber-600">${tot.M}</td><td class="p-3 text-center font-bold text-violet-600">${tot.S}</td><td class="p-3 text-center font-bold text-sky-600">${tot.C}</td><td class="p-3 text-center font-bold text-slate-600">${tot.R}</td><td class="p-3 text-center"><span class="pill ${tx>=80?"pill-green":(tx>=50?"pill-amber":"pill-red")}">${tx}%</span></td></tr>`;
  }).join("");
  return filterBar+`<div class="card p-2"><div class="text-sm font-semibold mb-2 px-2">Récapitulatif mensuel par société — ${new Date(...ym.split("-").map((v,i)=>i?v-1:+v),1).toLocaleDateString("fr-FR",{month:"long",year:"numeric"})}</div>
    <table class="w-full text-sm"><thead><tr style="background:#f1f5f9"><th class="text-left p-3">Société</th><th class="p-3 text-center">Effectif</th><th class="p-3 text-center text-emerald-700">P</th><th class="p-3 text-center text-red-700">A</th><th class="p-3 text-center text-amber-700">M</th><th class="p-3 text-center text-violet-700">S</th><th class="p-3 text-center text-sky-700">C</th><th class="p-3 text-center text-slate-700">R</th><th class="p-3 text-center">Couverture</th></tr></thead><tbody>${rows}</tbody></table>
  </div>`;
}
function renderPointageStats(){
  const ym=ptCurrentMonth();const soc=ptCurrentSoc();
  const allAg=(db.agents||[]).filter(a=>!["sortant","demissionne","licencie","archive"].includes(a.statut));
  const ag=soc?allAg.filter(a=>a.societe===soc):allAg;
  const filterBar=`<div class="card p-4 mb-4"><div class="flex flex-wrap items-center gap-3">
    <div><label class="label">Mois</label><input type="month" class="input" value="${ym}" onchange="setPtMonth(this.value)"/></div>
    <div><label class="label">Société</label><select class="select" onchange="setPtSociete(this.value)"><option value="" ${!soc?"selected":""}>🏢 Toutes les sociétés</option>${SOCIETES.map(s=>`<option ${soc===s?"selected":""}>${s}</option>`).join("")}</select></div>
  </div></div>`;
  const tot={P:0,A:0,M:0,S:0,C:0,R:0};
  ag.forEach(a=>{const sh=ptGetSheet(a.id,ym);if(sh)Object.values(sh.days||{}).forEach(v=>{if(tot[v]!==undefined)tot[v]++})});
  const totSum=Object.values(tot).reduce((a,b)=>a+b,0);
  const days=ptDaysInMonth(ym);const expected=ag.length*days;const tauxPresence=expected?Math.round(tot.P*100/expected):0;const tauxAbs=expected?Math.round((tot.A+tot.M)*100/expected):0;
  const cards=`<div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Effectif</div><div class="text-3xl font-black text-cyan-600">${ag.length}</div></div>
    <div class="card p-4"><div class="text-xs text-slate-500 uppercase">Jours/mois</div><div class="text-3xl font-black text-slate-700">${days}</div></div>
    <div class="card p-4" style="background:#043970"><div class="text-xs text-emerald-600 uppercase font-semibold">Taux de présence</div><div class="text-3xl font-black text-emerald-700">${tauxPresence}%</div></div>
    <div class="card p-4" style="background:#fef2f2"><div class="text-xs text-red-600 uppercase font-semibold">Taux d'absentéisme</div><div class="text-3xl font-black text-red-700">${tauxAbs}%</div></div>
  </div>`;
  const codeRows=Object.entries(POINTAGE_CODES).map(([k,v])=>{const n=tot[k]||0;const pct=totSum?Math.round(n*100/totSum):0;return`<tr class="border-t"><td class="p-3"><span class="inline-flex items-center gap-2"><span class="font-mono font-black px-2 py-0.5 rounded" style="background:${v.bg};color:${v.color}">${k}</span>${v.label}</span></td><td class="p-3 text-center font-bold text-lg">${n}</td><td class="p-3"><div style="background:#f1f5f9;height:14px;border-radius:7px;overflow:hidden"><div style="background:${v.color};height:100%;width:${pct}%"></div></div></td><td class="p-3 text-right font-semibold">${pct}%</td></tr>`}).join("");
  const breakdown=`<div class="card p-2 mb-4"><div class="text-sm font-semibold mb-2 px-2">Répartition des codes</div>
    <table class="w-full text-sm"><thead><tr style="background:#f1f5f9"><th class="text-left p-3">Code</th><th class="p-3 text-center">Total jours</th><th class="p-3">Distribution</th><th class="p-3 text-right">%</th></tr></thead><tbody>${codeRows}</tbody></table>
  </div>`;
  const top=ag.map(a=>{const sh=ptGetSheet(a.id,ym);const c={P:ptCount(sh,"P"),A:ptCount(sh,"A"),M:ptCount(sh,"M"),S:ptCount(sh,"S"),C:ptCount(sh,"C"),R:ptCount(sh,"R")};return{a,c,abs:c.A+c.M}}).sort((x,y)=>y.abs-x.abs).slice(0,10);
  const topRows=top.filter(t=>t.abs>0).map(({a,c,abs})=>`<tr class="border-t"><td class="p-3 font-semibold">${escapeHTML((a.nom||"")+" "+(a.prenom||""))} <span class="font-mono text-[10px] px-1.5 py-0.5 rounded ml-1" style="background:#04397015;color:#043970">${escapeHTML(a.matricule||"—")}</span></td><td class="p-3 text-xs text-slate-500">${escapeHTML(a.societe||"")}</td><td class="p-3 text-center text-emerald-600">${c.P}</td><td class="p-3 text-center text-red-600 font-bold">${c.A}</td><td class="p-3 text-center text-amber-600 font-bold">${c.M}</td><td class="p-3 text-center text-violet-600">${c.S}</td><td class="p-3 text-center font-black text-red-700">${abs}</td></tr>`).join("")||`<tr><td class="p-6 text-center text-slate-400" colspan="7">Aucune absence enregistrée sur la période.</td></tr>`;
  const topCard=`<div class="card p-2"><div class="text-sm font-semibold mb-2 px-2">🚨 Top 10 absences (A + M)</div>
    <table class="w-full text-sm"><thead><tr style="background:#f1f5f9"><th class="text-left p-3">Agent</th><th class="text-left p-3">Société</th><th class="p-3 text-center text-emerald-700">P</th><th class="p-3 text-center text-red-700">A</th><th class="p-3 text-center text-amber-700">M</th><th class="p-3 text-center text-violet-700">S</th><th class="p-3 text-center">A+M</th></tr></thead><tbody>${topRows}</tbody></table>
  </div>`;
  return filterBar+cards+breakdown+topCard;
}
function renderPointageLegende(){
  const rows=Object.entries(POINTAGE_CODES).map(([k,v])=>`<tr class="border-t"><td class="p-4 text-center font-mono text-2xl font-black" style="background:${v.bg};color:${v.color};width:80px">${k}</td><td class="p-4 font-bold">${v.label}</td><td class="p-4 text-xs text-slate-500"><div class="inline-block w-8 h-8 rounded" style="background:${v.color}"></div></td></tr>`).join("");
  return`<div class="card p-5 mb-4"><h3 class="font-bold text-lg mb-2">Codes de pointage</h3><p class="text-sm text-slate-600 mb-4">Codes utilisés dans le tableau mensuel de pointage. Cliquez sur une case du tableau pour faire défiler les codes, ou faites un clic droit pour saisir le code souhaité.</p>
    <table class="w-full text-sm"><thead><tr style="background:#f1f5f9"><th class="text-center p-3">Code</th><th class="text-left p-3">Signification</th><th class="text-left p-3">Couleur</th></tr></thead><tbody>${rows}</tbody></table>
  </div>
  <div class="card p-5"><h3 class="font-bold mb-3">Modes de saisie</h3>
    <ul class="text-sm space-y-2 list-disc pl-5"><li><strong>Clic gauche</strong> sur une case : cycle des codes (·→P→A→M→S→C→R)</li><li><strong>Clic droit</strong> sur une case : saisir directement le code souhaité</li><li><strong>Bouton « P✓ »</strong> en bout de ligne : pré-remplir toute la ligne avec « P »</li><li><strong>Bouton « ✕ »</strong> en bout de ligne : effacer toute la ligne</li><li>Les samedis et dimanches sont mis en évidence en rouge</li><li>Sauvegarde automatique dans PostgreSQL</li></ul>
  </div>`;
}

/* ---- INIT ---- */
async function bootApp(){
  db=loadDB();
  session=loadSession();
  if(session&&isRemovedSociete(session.societe)){session.societe=null;saveSession(session)}
  if(session&&!sgdiAuthToken()){
    session=null;
    saveSession(null);
    location.hash="#/login";
  }
  unlockedAgents=loadUnlocked();
  if(session&&sgdiAuthToken()){
    document.getElementById("app").innerHTML=`<div class="min-h-screen flex items-center justify-center text-slate-500">Chargement PostgreSQL...</div>`;
    const loaded=await sgdiPullState({silent:true,render:false,force:true,deferSql:true}).catch(()=>null);
    if(!loaded){
      sessionStorage.removeItem(SGDI_API_TOKEN_KEY);
      session=null;
      saveSession(null);
      sgdiPostgresReady=false;
      location.hash="#/login";
      renderLogin();
      if(typeof toast==="function")toast("Session expirée ou PostgreSQL indisponible : reconnectez-vous.","error");
      return;
    }
  }
  if(!location.hash)location.hash=session?(session.societe?"#/dashboard":(session.transverse?"#/"+(session.transverse==="materiel"?"materiel/dashboard":session.transverse+"/dashboard"):"#/select-societe")):"#/login";
  route();
}
bootApp();
try{
  let stripTimer=null;
  new MutationObserver(()=>{
    clearTimeout(stripTimer);
    stripTimer=setTimeout(()=>stripCryptogrammes(document.getElementById("app")||document.body),30);
  }).observe(document.body,{childList:true,subtree:true,characterData:true});
}catch(e){}
try{
  setInterval(()=>{if(session&&sgdiAuthToken()&&!sgdiDirty)sgdiPullState({silent:true,render:false,light:true}).catch(()=>{})},60000);
}catch(e){}
try{
  window.addEventListener("beforeunload",()=>{
    if(candidatDraftTimer){
      clearTimeout(candidatDraftTimer);
      candidatDraftTimer=null;
    }
    if(sgdiDirty&&db&&sgdiAuthToken()){
      sgdiBackendSave();
    }
  });
}catch(e){}
